Action.Str:
import okhttp3.OkHttpClient;
import okhttp3.Request;
import okhttp3.Response;
import okhttp3.ResponseBody;
import java.io.File;
import java.io.FileOutputStream;
import java.io.BufferedOutputStream;
import java.io.InputStream;
import java.io.IOException;
import java.util.HashMap;
import java.util.concurrent.TimeUnit;
import org.json.JSONObject;
import org.json.JSONArray;

String urlApi = tasker.getVariable("url_project_wca");
if (urlApi == null || urlApi.equals("")) {
    tasker.showToast("URL do projeto não definida");
    return "Error: URL_PROJECT_WCA não definida";
}

String filePath1 = "/data/data/net.dinglisch.android.taskerm/files/WCA/go_port_wca-aarch64.bin";
String filePath2 = "/data/data/net.dinglisch.android.taskerm/files/WCA/whatsapp-wca-aarch64.bin";
String filePath3 = "/data/data/net.dinglisch.android.taskerm/files/WCA/ffmpeg-wca-aarch64.bin";

String exitDataValue = tasker.getVariable("exit_data");
if (exitDataValue == null || exitDataValue.equals("")) {
    exitDataValue = "";
}
tasker.setVariable("exit_data", exitDataValue);

OkHttpClient client = new OkHttpClient.Builder()
    .connectTimeout(30, TimeUnit.SECONDS)
    .readTimeout(60, TimeUnit.SECONDS)
    .writeTimeout(60, TimeUnit.SECONDS)
    .retryOnConnectionFailure(true)
    .build();

String releaseJson = null;
try {
    Request request = new Request.Builder().url(urlApi).header("User-Agent", "WCA-Installer").build();
    Response response = client.newCall(request).execute();
    if (response.isSuccessful()) {
        releaseJson = response.body().string();
    } else {
        tasker.showToast("Erro ao buscar release: " + response.code());
        return "Error: Falha ao buscar release";
    }
    response.close();
} catch (Exception e) {
    tasker.showToast("Erro na requisição: " + e.getMessage());
    return "Error: " + e.getMessage();
}

JSONObject release = new JSONObject(releaseJson);
JSONArray assets = release.getJSONArray("assets");

String url1 = null;
String url2 = null;
String url3 = null;

for (int i = 0; i < assets.length(); i++) {
    JSONObject asset = assets.getJSONObject(i);
    String name = asset.getString("name");
    String downloadUrl = asset.getString("browser_download_url");

    if (name.equals("go_port_wca-aarch64.bin")) {
        url1 = downloadUrl;
    } else if (name.equals("whatsapp-wca-aarch64.bin")) {
        url2 = downloadUrl;
    } else if (name.equals("ffmpeg-wca-aarch64.bin")) {
        url3 = downloadUrl;
    }
}

if (url1 == null || url2 == null || url3 == null) {
    tasker.showToast("Um ou mais arquivos não encontrados no release");
    return "Error: Arquivos não encontrados";
}

long size1 = 0, size2 = 0, size3 = 0;
try {
    Request headReq1 = new Request.Builder().url(url1).header("User-Agent", "WCA-Installer").head().build();
    Response headRes1 = client.newCall(headReq1).execute();
    if (headRes1.isSuccessful()) size1 = headRes1.body().contentLength();
    headRes1.close();
} catch (Exception e) {}

try {
    Request headReq2 = new Request.Builder().url(url2).header("User-Agent", "WCA-Installer").head().build();
    Response headRes2 = client.newCall(headReq2).execute();
    if (headRes2.isSuccessful()) size2 = headRes2.body().contentLength();
    headRes2.close();
} catch (Exception e) {}

try {
    Request headReq3 = new Request.Builder().url(url3).header("User-Agent", "WCA-Installer").head().build();
    Response headRes3 = client.newCall(headReq3).execute();
    if (headRes3.isSuccessful()) size3 = headRes3.body().contentLength();
    headRes3.close();
} catch (Exception e) {}

if (size1 <= 0) size1 = 10 * 1024 * 1024;
if (size2 <= 0) size2 = 10 * 1024 * 1024;
if (size3 <= 0) size3 = 10 * 1024 * 1024;

void updateProgress(int percent) {
    String percentStr = String.valueOf(percent);
    tasker.setVariable("progress_install", percentStr);
    tasker.setVariable("par1", "install-project");

    HashMap taskArgs = new HashMap();
    taskArgs.put("progress_install", percentStr);
    taskArgs.put("par1", "install-project");
    tasker.callTask("006-CONFIGURAR_SISTEMA [wca]", taskArgs);
}

boolean downloadFile(String urlStr, String filePathStr, String displayName,
                     long fileSize, int fileIndex,
                     long[] downloadedBytes, int[] lastPercent) {
    File destFile = new File(filePathStr);
    File parentDir = destFile.getParentFile();
    if (parentDir != null && !parentDir.exists()) parentDir.mkdirs();
    if (destFile.exists()) destFile.delete();

    Request request = new Request.Builder().url(urlStr).header("User-Agent", "WCA-Installer").build();
    Response response = null;
    InputStream inputStream = null;
    BufferedOutputStream outputStream = null;

    try {
        response = client.newCall(request).execute();
        if (!response.isSuccessful()) {
            tasker.showToast("HTTP Error " + response.code() + ": " + displayName);
            return false;
        }
        ResponseBody body = response.body();
        if (body == null) {
            tasker.showToast("Response body null: " + displayName);
            return false;
        }
        inputStream = body.byteStream();
        outputStream = new BufferedOutputStream(new FileOutputStream(destFile), 65536);

        byte[] buffer = new byte[65536];
        int bytesRead;
        long fileDownloaded = 0;
        long lastUpdateTime = System.currentTimeMillis();

        int basePercent = fileIndex * 33;

        while ((bytesRead = inputStream.read(buffer)) != -1) {
            outputStream.write(buffer, 0, bytesRead);
            fileDownloaded += bytesRead;
            downloadedBytes[0] += bytesRead;

            int fileProgress = (int) ((fileDownloaded * 33L) / fileSize);
            if (fileProgress > 33) fileProgress = 33;

            int currentPercent = basePercent + fileProgress;
            if (currentPercent > 100) currentPercent = 100;

            long currentTime = System.currentTimeMillis();

            if (currentPercent != lastPercent[0] &&
                ((currentTime - lastUpdateTime) >= 1000 ||
                 currentPercent >= lastPercent[0] + 2 ||
                 currentPercent == 100)) {
                updateProgress(currentPercent);
                lastPercent[0] = currentPercent;
                lastUpdateTime = currentTime;
            }
        }
        outputStream.flush();

        int finalPercent = basePercent + 33;
        if (finalPercent > 100) finalPercent = 100;
        if (finalPercent != lastPercent[0]) {
            updateProgress(finalPercent);
            lastPercent[0] = finalPercent;
        }

        return true;
    } catch (IOException e) {
        tasker.showToast("Download error: " + e.getMessage() + " - " + displayName);
        if (destFile.exists()) destFile.delete();
        return false;
    } finally {
        try { if (inputStream != null) inputStream.close(); } catch (IOException e) {}
        try { if (outputStream != null) outputStream.close(); } catch (IOException e) {}
        try { if (response != null) response.close(); } catch (IOException e) {}
    }
}

long[] downloadedBytes = new long[]{0};
int[] lastPercent = new int[]{-1};

updateProgress(0);

boolean success1 = downloadFile(url1, filePath1, "go_port_wca-aarch64.bin", size1, 0, downloadedBytes, lastPercent);
boolean success2 = downloadFile(url2, filePath2, "whatsapp-wca-aarch64.bin", size2, 1, downloadedBytes, lastPercent);
boolean success3 = downloadFile(url3, filePath3, "ffmpeg-wca-aarch64.bin", size3, 2, downloadedBytes, lastPercent);

if (success1 && success2 && success3) {
    String finalExitData = tasker.getVariable("exit_data");
    if (finalExitData == null || finalExitData.equals("")) {
        finalExitData = "";
    }

    HashMap taskArgsFinal = new HashMap();
    taskArgsFinal.put("progress_install", "100");
    taskArgsFinal.put("exit_data", finalExitData);
    taskArgsFinal.put("par1", "install-project");
    tasker.callTask("006-CONFIGURAR_SISTEMA [wca]", taskArgsFinal);

    return "Success: All files downloaded";
} else {
    tasker.showToast("Error: One or more downloads failed");
    return "Error: Download failed";
}

import org.json.JSONObject;
import org.json.JSONArray;
import com.joaomgcd.taskerm.action.java.JavaCodeException;

httpRequestBody = tasker.getVariable("http_request_body");

try {
    data = new JSONObject(httpRequestBody);

    // Campos principais do nível raiz
    if (data.has("recebido_em")) {
        tasker.setVariable("recebido_em", data.optString("recebido_em", ""));
    } else {
        tasker.setVariable("recebido_em", "");
    }

    if (data.has("origem")) {
        tasker.setVariable("origem", data.optString("origem", ""));
    } else {
        tasker.setVariable("origem", "");
    }

    if (data.has("metodo")) {
        tasker.setVariable("metodo", data.optString("metodo", ""));
    } else {
        tasker.setVariable("metodo", "");
    }

    if (data.has("url_original")) {
        tasker.setVariable("url_original", data.optString("url_original", ""));
    } else {
        tasker.setVariable("url_original", "");
    }

    if (data.has("porta_origem")) {
        tasker.setVariable("porta_origem", data.optString("porta_origem", ""));
    } else {
        tasker.setVariable("porta_origem", "");
    }

    if (data.has("porta_destino")) {
        tasker.setVariable("porta_destino", data.optString("porta_destino", ""));
    } else {
        tasker.setVariable("porta_destino", "");
    }

    // Processa o body principal
    if (data.has("body")) {
        body = data.optJSONObject("body");
        if (body != null) {

            // DeviceID
            if (body.has("DeviceID")) {
                String rawDeviceId = body.optString("DeviceID", "");
                String cleanDeviceId = rawDeviceId;
                if (rawDeviceId.contains("@")) {
                    cleanDeviceId = rawDeviceId.substring(0, rawDeviceId.indexOf("@"));
                }
                tasker.setVariable("device_id", cleanDeviceId);
                tasker.setVariable("phone", cleanDeviceId);
            } else {
                tasker.setVariable("device_id", "");
                tasker.setVariable("phone", "");
            }

            // Event
            event = body.optString("Event", "");
            if (body.has("Event")) {
                tasker.setVariable("event", event);
            } else {
                tasker.setVariable("event", "");
            }

            // Timestamp do body
            if (body.has("Timestamp")) {
                tasker.setVariable("timestamp_body", body.optString("Timestamp", ""));
            } else {
                tasker.setVariable("timestamp_body", "");
            }

            // Processa o payload
            if (body.has("Payload")) {
                p = body.optJSONObject("Payload");
                if (p != null) {

                    // ChatID
                    if (p.has("ChatID")) {
                        String chatIdValue = p.optString("ChatID", "");
                        tasker.setVariable("chat_id", chatIdValue);

                        String recipientNumberRaw = chatIdValue;
                        if (recipientNumberRaw.endsWith("@s.whatsapp.net")) {
                            recipientNumberRaw = recipientNumberRaw.replace("@s.whatsapp.net", "");
                        } else if (recipientNumberRaw.endsWith("@g.us")) {
                            recipientNumberRaw = recipientNumberRaw.replace("@g.us", "");
                        }
                        tasker.setVariable("recipient_number", recipientNumberRaw);
                    } else {
                        tasker.setVariable("chat_id", "");
                        tasker.setVariable("recipient_number", "");
                    }

                    // ChatLid / FromLid
                    if (p.has("ChatLid")) {
                        tasker.setVariable("from_lid", p.optString("ChatLid", ""));
                    } else if (p.has("FromLid")) {
                        tasker.setVariable("from_lid", p.optString("FromLid", ""));
                    } else {
                        tasker.setVariable("from_lid", "");
                    }

                    // From
                    if (p.has("From")) {
                        String fromRaw = p.optString("From", "");
                        String senderNumberRaw = fromRaw;
                        if (senderNumberRaw.endsWith("@s.whatsapp.net")) {
                            senderNumberRaw = senderNumberRaw.replace("@s.whatsapp.net", "");
                        } else if (senderNumberRaw.endsWith("@g.us")) {
                            senderNumberRaw = senderNumberRaw.replace("@g.us", "");
                        }
                        tasker.setVariable("sender_number", senderNumberRaw);
                    } else {
                        tasker.setVariable("sender_number", "");
                    }

                    // FromName
                    if (p.has("FromName")) {
                        tasker.setVariable("sender_name", p.optString("FromName", ""));
                    } else {
                        tasker.setVariable("sender_name", "");
                    }

                    // IsFromMe
                    if (p.has("IsFromMe")) {
                        tasker.setVariable("is_from_me", String.valueOf(p.optBoolean("IsFromMe")));
                    } else {
                        tasker.setVariable("is_from_me", "false");
                    }

                    // IsGroup
                    if (p.has("IsGroup")) {
                        boolean isGroupBoolean = p.optBoolean("IsGroup");
                        tasker.setVariable("is_group", String.valueOf(isGroupBoolean));

                        if (isGroupBoolean) {
                            String groupJidValue = p.optString("ChatID", "");
                            if (groupJidValue.endsWith("@g.us")) {
                                groupJidValue = groupJidValue.replace("@g.us", "");
                            }
                            tasker.setVariable("group_jid", groupJidValue);
                        } else {
                            tasker.setVariable("group_jid", "");
                        }
                    } else {
                        tasker.setVariable("is_group", "false");
                        tasker.setVariable("group_jid", "");
                    }

                    // GroupName (para grupos)
                    if (p.has("GroupName")) {
                        tasker.setVariable("group_name", p.optString("GroupName", ""));
                    } else {
                        tasker.setVariable("group_name", "");
                    }

                    // ID / IDs
                    if (p.has("IDs")) {
                        ids = p.optJSONArray("IDs");
                        if (ids != null && ids.length() > 0) {
                            tasker.setVariable("ids_json", ids.toString());
                            tasker.setVariable("ids_count", String.valueOf(ids.length()));
                            tasker.setVariable("message_id", ids.optString(0, ""));
                        } else {
                            tasker.setVariable("ids_json", "");
                            tasker.setVariable("ids_count", "0");
                            tasker.setVariable("message_id", "");
                        }
                    } else if (p.has("ID")) {
                        tasker.setVariable("message_id", p.optString("ID", ""));
                        tasker.setVariable("ids_json", "");
                        tasker.setVariable("ids_count", "0");
                    } else {
                        tasker.setVariable("message_id", "");
                        tasker.setVariable("ids_json", "");
                        tasker.setVariable("ids_count", "0");
                    }

                    // Timestamp do payload
                    if (p.has("Timestamp")) {
                        tasker.setVariable("timestamp_payload", p.optString("Timestamp", ""));
                    } else {
                        tasker.setVariable("timestamp_payload", "");
                    }

                    // Body / Message (texto)
                    if (p.has("Body")) {
                        tasker.setVariable("message_text", p.optString("Body", ""));
                    } else {
                        tasker.setVariable("message_text", "");
                    }

                    // ========================================
                    // TYPE MESSAGE
                    // ========================================
                    String typeMessage = "";

                    // Verifica se é evento de mensagem revogada (apagada)
                    if (event.equals("message.revoked")) {
                        tasker.setVariable("type_message", "message_revoked");

                        if (p.has("RevokedMessageID")) {
                            tasker.setVariable("revoked_message_id", p.optString("RevokedMessageID", ""));
                        } else {
                            tasker.setVariable("revoked_message_id", "");
                        }

                        if (p.has("RevokedChat")) {
                            tasker.setVariable("revoked_chat", p.optString("RevokedChat", ""));
                        } else {
                            tasker.setVariable("revoked_chat", "");
                        }

                        if (p.has("RevokedFromMe")) {
                            tasker.setVariable("revoked_from_me", String.valueOf(p.optBoolean("RevokedFromMe")));
                        } else {
                            tasker.setVariable("revoked_from_me", "false");
                        }
                    } else if (p.has("Type")) {
                        typeMessage = p.optString("Type", "");

                        if (typeMessage.equals("Message")) {
                            tasker.setVariable("type_message", "text_message");
                        } else if (typeMessage.equals("VideoMessage")) {
                            tasker.setVariable("type_message", "video_message");
                        } else if (typeMessage.equals("ImageMessage")) {
                            tasker.setVariable("type_message", "image_message");
                        } else if (typeMessage.equals("AudioMessage")) {
                            tasker.setVariable("type_message", "audio_message");
                        } else if (typeMessage.equals("DocumentMessage")) {
                            tasker.setVariable("type_message", "document_message");
                        } else if (typeMessage.equals("LinkMessage")) {
                            tasker.setVariable("type_message", "link_message");
                        } else if (typeMessage.equals("LocationMessage")) {
                            tasker.setVariable("type_message", "location_message");
                        } else if (typeMessage.equals("LiveLocationMessage")) {
                            tasker.setVariable("type_message", "live_location_message");
                        } else if (typeMessage.equals("VideoNoteMessage")) {
                            tasker.setVariable("type_message", "video_note_message");
                        } else if (typeMessage.equals("ContactMessage")) {
                            tasker.setVariable("type_message", "contact_message");
                        } else if (typeMessage.equals("ReceiptMessage")) {
                            tasker.setVariable("type_message", "receipt_message");
                        } else if (typeMessage.equals("ChatPresenceMessage")) {
                            tasker.setVariable("type_message", "presence_message");
                        } else if (typeMessage.equals("PollMessage")) {
                            tasker.setVariable("type_message", "poll_message");
                        } else if (typeMessage.equals("PollResponseMessage")) {
                            tasker.setVariable("type_message", "poll_response_message");
                        } else if (typeMessage.equals("StatusResponseMessage")) {
                            tasker.setVariable("type_message", "status_response_message");
                        } else if (typeMessage.equals("QuoteMessage")) {
                            tasker.setVariable("type_message", "quote_message");
                        } else if (typeMessage.equals("CallOfferMessage") || typeMessage.equals("VideoCallOfferMessage") || typeMessage.equals("AudioCallOfferMessage")) {
                            tasker.setVariable("type_message", "call_offer");
                        } else if (typeMessage.equals("CallTerminateMessage")) {
                            tasker.setVariable("type_message", "call_terminate");
                        } else {
                            tasker.setVariable("type_message", typeMessage.toLowerCase() + "_message");
                        }
                    } else {
                        tasker.setVariable("type_message", "");
                    }

                    // ========================================
                    // STATUS RESPONSE MESSAGE (Resposta a Status)
                    // ========================================
                    if (p.has("QuotedStatusID")) {
                        tasker.setVariable("quoted_status_id", p.optString("QuotedStatusID", ""));
                    } else {
                        tasker.setVariable("quoted_status_id", "");
                    }

                    if (p.has("QuotedStatusCaption")) {
                        tasker.setVariable("quoted_status_caption", p.optString("QuotedStatusCaption", ""));
                    } else {
                        tasker.setVariable("quoted_status_caption", "");
                    }

                    if (p.has("QuotedStatusSender")) {
                        tasker.setVariable("quoted_status_sender", p.optString("QuotedStatusSender", ""));
                    } else {
                        tasker.setVariable("quoted_status_sender", "");
                    }

                    if (p.has("QuotedStatusType")) {
                        tasker.setVariable("quoted_status_type", p.optString("QuotedStatusType", ""));
                    } else {
                        tasker.setVariable("quoted_status_type", "");
                    }

                    // ========================================
                    // QUOTE MESSAGE (Mensagem com Citação)
                    // ========================================
                    if (p.has("QuotedBody")) {
                        tasker.setVariable("quoted_body", p.optString("QuotedBody", ""));
                    } else {
                        tasker.setVariable("quoted_body", "");
                    }

                    if (p.has("RepliedToID")) {
                        tasker.setVariable("replied_to_id", p.optString("RepliedToID", ""));
                    } else {
                        tasker.setVariable("replied_to_id", "");
                    }

                    // ========================================
                    // POLL MESSAGE
                    // ========================================
                    if (p.has("Poll")) {
                        JSONObject pollObj = p.optJSONObject("Poll");
                        if (pollObj != null) {
                            if (pollObj.has("Question")) {
                                tasker.setVariable("poll_question", pollObj.optString("Question", ""));
                            } else {
                                tasker.setVariable("poll_question", "");
                            }

                            if (pollObj.has("Options")) {
                                JSONArray pollOptions = pollObj.optJSONArray("Options");
                                if (pollOptions != null) {
                                    tasker.setVariable("poll_options_json", pollOptions.toString());
                                    tasker.setVariable("poll_options_count", String.valueOf(pollOptions.length()));
                                } else {
                                    tasker.setVariable("poll_options_json", "");
                                    tasker.setVariable("poll_options_count", "0");
                                }
                            } else {
                                tasker.setVariable("poll_options_json", "");
                                tasker.setVariable("poll_options_count", "0");
                            }

                            if (pollObj.has("EncKey")) {
                                tasker.setVariable("poll_enc_key", pollObj.optString("EncKey", ""));
                            } else {
                                tasker.setVariable("poll_enc_key", "");
                            }

                            tasker.setVariable("poll_json", pollObj.toString());
                        } else {
                            tasker.setVariable("poll_question", "");
                            tasker.setVariable("poll_options_json", "");
                            tasker.setVariable("poll_options_count", "0");
                            tasker.setVariable("poll_enc_key", "");
                            tasker.setVariable("poll_json", "");
                        }
                    } else {
                        tasker.setVariable("poll_question", "");
                        tasker.setVariable("poll_options_json", "");
                        tasker.setVariable("poll_options_count", "0");
                        tasker.setVariable("poll_enc_key", "");
                        tasker.setVariable("poll_json", "");
                    }

                    // ========================================
                    // POLL RESPONSE MESSAGE
                    // ========================================
                    if (p.has("PollQuestion")) {
                        tasker.setVariable("poll_response_question", p.optString("PollQuestion", ""));
                    } else {
                        tasker.setVariable("poll_response_question", "");
                    }

                    if (p.has("PollOptions")) {
                        JSONArray pollResponseOptions = p.optJSONArray("PollOptions");
                        if (pollResponseOptions != null) {
                            tasker.setVariable("poll_response_options_json", pollResponseOptions.toString());
                            tasker.setVariable("poll_response_options_count", String.valueOf(pollResponseOptions.length()));
                        } else {
                            tasker.setVariable("poll_response_options_json", "");
                            tasker.setVariable("poll_response_options_count", "0");
                        }
                    } else {
                        tasker.setVariable("poll_response_options_json", "");
                        tasker.setVariable("poll_response_options_count", "0");
                    }

                    if (p.has("PollVotes")) {
                        JSONArray pollVotes = p.optJSONArray("PollVotes");
                        if (pollVotes != null && pollVotes.length() > 0) {
                            tasker.setVariable("poll_response_vote", pollVotes.optString(0, ""));
                            tasker.setVariable("poll_response_votes_json", pollVotes.toString());
                            tasker.setVariable("poll_response_votes_count", String.valueOf(pollVotes.length()));
                        } else {
                            tasker.setVariable("poll_response_vote", "");
                            tasker.setVariable("poll_response_votes_json", "");
                            tasker.setVariable("poll_response_votes_count", "0");
                        }
                    } else {
                        tasker.setVariable("poll_response_vote", "");
                        tasker.setVariable("poll_response_votes_json", "");
                        tasker.setVariable("poll_response_votes_count", "0");
                    }

                    if (p.has("OriginalMessageID")) {
                        tasker.setVariable("poll_original_message_id", p.optString("OriginalMessageID", ""));
                    } else {
                        tasker.setVariable("poll_original_message_id", "");
                    }

                    // ========================================
                    // LINK MESSAGE
                    // ========================================
                    if (p.has("LinkTitle")) {
                        tasker.setVariable("link_title", p.optString("LinkTitle", ""));
                    } else {
                        tasker.setVariable("link_title", "");
                    }

                    if (p.has("LinkDescription")) {
                        tasker.setVariable("link_description", p.optString("LinkDescription", ""));
                    } else {
                        tasker.setVariable("link_description", "");
                    }

                    if (p.has("LinkThumbnailBase64")) {
                        tasker.setVariable("thumbnail_base64", p.optString("LinkThumbnailBase64", ""));
                    } else {
                        tasker.setVariable("thumbnail_base64", "");
                    }

                    if (p.has("Link_URL")) {
                        tasker.setVariable("link_url", p.optString("Link_URL", ""));
                    } else if (p.has("Body") && p.optString("Body", "").startsWith("http")) {
                        tasker.setVariable("link_url", p.optString("Body", ""));
                    } else {
                        tasker.setVariable("link_url", "");
                    }

                    // Extension
                    if (p.has("Extension")) {
                        tasker.setVariable("extension", p.optString("Extension", ""));
                    } else {
                        tasker.setVariable("extension", "");
                    }

                    // FileSizeKB
                    if (p.has("FileSizeKB")) {
                        tasker.setVariable("file_size_kb", String.valueOf(p.optDouble("FileSizeKB")));
                    } else {
                        tasker.setVariable("file_size_kb", "");
                    }

                    // Video
                    if (p.has("Video")) {
                        Object videoObj = p.opt("Video");
                        if (videoObj instanceof JSONObject) {
