    addressValues.put("data1", addressStr);
    addressValues.put("data2", addressTypeInt);
    context.getContentResolver().insert(Uri.parse("content://com.android.contacts/data"), addressValues);
}

if (formattedBirthday != null && formattedBirthday.length() > 0) {
    birthdayValues = new ContentValues();
