    );

    if (dataCursor != null && dataCursor.moveToFirst()) {
        do {
            mimeType = dataCursor.getString(
                dataCursor.getColumnIndex(android.provider.ContactsContract.Data.MIMETYPE)
            );

            if (mimeType.equals("vnd.android.cursor.item/phone_v2")) {
                phoneNumber = dataCursor.getString(
                    dataCursor.getColumnIndex(android.provider.ContactsContract.Data.DATA1)
                );
                phoneType = dataCursor.getInt(
