                );
                phoneMap = new java.util.HashMap();
                phoneMap.put("number", phoneNumber != null ? phoneNumber : "");
                phoneMap.put("type", String.valueOf(phoneType));
                phonesList.add(phoneMap);
            } else if (mimeType.equals("vnd.android.cursor.item/email_v2")) {
                emailAddress = dataCursor.getString(
                    dataCursor.getColumnIndex(android.provider.ContactsContract.Data.DATA1)
                );
                emailType = dataCursor.getInt(
                    dataCursor.getColumnIndex(android.provider.ContactsContract.Data.DATA2)
                );
                emailMap = new java.util.HashMap();
                emailMap.put("address", emailAddress != null ? emailAddress : "");
                emailMap.put("type", String.valueOf(emailType));
                emailsList.add(emailMap);
            } else if (mimeType.equals("vnd.android.cursor.item/name")) {
                /* Name already retrieved */
            } else if (mimeType.equals("vnd.android.cursor.item/organization")) {
                company = dataCursor.getString(
                    dataCursor.getColumnIndex(android.provider.ContactsContract.Data.DATA1)
                );
            } else if (mimeType.equals("vnd.android.cursor.item/postal-address_v2")) {
                address = dataCursor.getString(
                    dataCursor.getColumnIndex(android.provider.ContactsContract.Data.DATA1)
                );
                addressType = dataCursor.getInt(
                    dataCursor.getColumnIndex(android.provider.ContactsContract.Data.DATA2)
                );
                addressMap = new java.util.HashMap();
                addressMap.put("address", address != null ? address : "");
                addressMap.put("type", String.valueOf(addressType));
                addressesList.add(addressMap);
            } else if (mimeType.equals("vnd.android.cursor.item/contact_event")) {
                birthday = dataCursor.getString(
                    dataCursor.getColumnIndex(android.provider.ContactsContract.Data.DATA1)
                );
                eventType = dataCursor.getInt(
                    dataCursor.getColumnIndex(android.provider.ContactsContract.Data.DATA2)
                );
                if (eventType == 3) {
                    birthday = dataCursor.getString(
                        dataCursor.getColumnIndex(android.provider.ContactsContract.Data.DATA1)
                    );
                }
            } else if (mimeType.equals("vnd.android.cursor.item/note")) {
                notes = dataCursor.getString(
                    dataCursor.getColumnIndex(android.provider.ContactsContract.Data.DATA1)
                );
            }
        } while (dataCursor.moveToNext());
    }
} catch (Exception e) {
    error = "ERROR: Failed to retrieve contact details: " + e.getMessage();
    tasker.setVariable("error", error);
    return error;
} finally {
    if (dataCursor != null) {
        dataCursor.close();
    }
}

