cleanBrazilianNumber(number) {
    cleaned = number.replaceAll("[^0-9]", "");

    tasker.log("Cleaning number: " + cleaned);

    if (cleaned.startsWith("0") && cleaned.length() >= 11) {
        if (cleaned.substring(0, 3).matches("0[0-9]{2}")) {
            cleaned = cleaned.substring(3);
            tasker.log("Removed interurban prefix (0+DDD): " + cleaned);
        } else if (cleaned.substring(0, 4).matches("0[0-9]{3}")) {
            cleaned = cleaned.substring(4);
            tasker.log("Removed interurban prefix (0+DDD): " + cleaned);
        } else {
            cleaned = cleaned.substring(1);
            tasker.log("Removed leading 0: " + cleaned);
        }
    }

    if (cleaned.startsWith("55") && cleaned.length() >= 10) {
        return cleaned;
    }

    if ((cleaned.length() == 10 || cleaned.length() == 11) && !cleaned.startsWith("55")) {
        cleaned = "55" + cleaned;
        tasker.log("Added 55: " + cleaned);
        return cleaned;
    }

    if ((cleaned.length() == 12 || cleaned.length() == 13) && !cleaned.startsWith("55")) {
        ddd = cleaned.substring(0, 2);
        rest = cleaned.substring(2);

        if (rest.length() == 11 && rest.substring(0, 1).equals("9")) {
            rest = rest.substring(1);
            cleaned = "55" + ddd + rest;
        } else if (rest.length() == 10) {
            cleaned = "55" + ddd + rest;
        } else {
            cleaned = "55" + cleaned;
        }
        tasker.log("Extracted DDD: " + ddd + " -> " + cleaned);
        return cleaned;
    }

    return cleaned;
}

generatePhoneVariations(phoneNumber) {
    cleaned = cleanBrazilianNumber(phoneNumber);

    tasker.log("Generating variations for: " + cleaned);

    variations = new java.util.ArrayList();

    if (cleaned.startsWith("55") && cleaned.length() >= 12) {
        without55 = cleaned.substring(2);
        ddd = without55.substring(0, 2);
        numberPart = without55.substring(2);

        tasker.log("DDD: " + ddd + ", Number: " + numberPart);

        if (numberPart.length() == 8) {
            variations.add("55" + ddd + numberPart);
            with9 = "9" + numberPart;
            variations.add("55" + ddd + with9);
        } else if (numberPart.length() == 9) {
            without9 = numberPart.substring(1);
            variations.add("55" + ddd + without9);
            variations.add("55" + ddd + numberPart);
        } else {
            variations.add(cleaned);
        }
    } else if (cleaned.length() >= 10 && cleaned.length() <= 11 && !cleaned.startsWith("55")) {
        ddd = cleaned.substring(0, 2);
        rest = cleaned.substring(2);

        if (rest.length() == 8) {
            variations.add("55" + ddd + rest);
            variations.add("55" + ddd + "9" + rest);
        } else if (rest.length() == 9) {
            variations.add("55" + ddd + rest.substring(1));
            variations.add("55" + ddd + rest);
        } else {
            variations.add("55" + cleaned);
        }
    } else {
        variations.add(cleaned);
    }

    uniqueVariations = new java.util.ArrayList();
    for (i = 0; i < variations.size(); i++) {
        num = (String) variations.get(i);
        if (!uniqueVariations.contains(num)) {
            uniqueVariations.add(num);
        }
    }

    tasker.log("Generated " + uniqueVariations.size() + " variation(s), in try-order:");
    for (i = 0; i < uniqueVariations.size(); i++) {
        tasker.log("  [" + i + "] " + (String) uniqueVariations.get(i));
    }

    return uniqueVariations;
}

hasContactPhoto(contactId) {
    rawIds = new java.util.ArrayList();

    rawContactCursor = context.getContentResolver().query(
        ContactsContract.RawContacts.CONTENT_URI,
        new String[]{ContactsContract.RawContacts._ID},
        ContactsContract.RawContacts.CONTACT_ID + " = ?",
        new String[]{String.valueOf(contactId)},
        null
    );

    if (rawContactCursor != null) {
        while (rawContactCursor.moveToNext()) {
            rawIds.add(rawContactCursor.getLong(0));
        }
        rawContactCursor.close();
    }

    hasPhoto = false;
    for (i = 0; i < rawIds.size() && !hasPhoto; i++) {
        rawId = (Long) rawIds.get(i);

        photoCursor = context.getContentResolver().query(
            ContactsContract.Data.CONTENT_URI,
            new String[]{ContactsContract.Data._ID, ContactsContract.Data.DATA15},
            ContactsContract.Data.RAW_CONTACT_ID + "=? AND " + ContactsContract.Data.MIMETYPE + "=?",
            new String[]{String.valueOf(rawId), CommonDataKinds.Photo.CONTENT_ITEM_TYPE},
            null
        );

        if (photoCursor != null) {
            if (photoCursor.moveToFirst()) {
                try {
                    photoData = photoCursor.getBlob(photoCursor.getColumnIndex(ContactsContract.Data.DATA15));
                    if (photoData != null && photoData.length > 0) {
                        hasPhoto = true;
                        tasker.log("Found photo data with size: " + photoData.length + " bytes");
                    } else {
                        tasker.log("Photo record found but data is empty (size: 0)");
                    }
                } catch (Exception e) {
                    tasker.log("Error reading photo data: " + e.getMessage());
                }
            }
            photoCursor.close();
        }
    }

    return hasPhoto;
}

tasker.log("Loading contacts...");

contactsProjection = new String[]{
    ContactsContract.Contacts._ID,
    ContactsContract.Contacts.DISPLAY_NAME,
    ContactsContract.Contacts.HAS_PHONE_NUMBER,
    ContactsContract.Contacts.PHOTO_URI,
    ContactsContract.Contacts.STARRED
};

contactCursor = null;
allContacts = new java.util.ArrayList();
updatedContactsList = new java.util.ArrayList();
skippedContactsList = new java.util.ArrayList();
totalNumbersFound = 0;
successfulUpdates = 0;
failedUpdates = 0;
skippedContacts = 0;
totalWhatsAppContacts = 0;
processed = 0;
contactCounter = 0;
totalContactsToProcess = 0;

try {
    contactCursor = context.getContentResolver().query(
        ContactsContract.Contacts.CONTENT_URI,
        contactsProjection,
        null,
        null,
        ContactsContract.Contacts.DISPLAY_NAME + " ASC"
    );

    if (contactCursor != null && contactCursor.moveToFirst()) {
        totalContactsToProcess = contactCursor.getCount();
        if (MAX_CONTACTS > 0 && MAX_CONTACTS < totalContactsToProcess) {
            totalContactsToProcess = MAX_CONTACTS;
        }

        do {
            contactCounter++;

            if (MAX_CONTACTS > 0 && contactCounter > MAX_CONTACTS) {
                tasker.log("Reached limit of " + MAX_CONTACTS + " contacts");
                break;
            }

            contactId = contactCursor.getLong(
                contactCursor.getColumnIndex(ContactsContract.Contacts._ID)
            );
            contactName = contactCursor.getString(
                contactCursor.getColumnIndex(ContactsContract.Contacts.DISPLAY_NAME)
            );
            hasPhone = contactCursor.getInt(
                contactCursor.getColumnIndex(ContactsContract.Contacts.HAS_PHONE_NUMBER)
            ) > 0;
            starred = contactCursor.getInt(
                contactCursor.getColumnIndex(ContactsContract.Contacts.STARRED)
            ) > 0;
            photoUri = contactCursor.getString(
                contactCursor.getColumnIndex(ContactsContract.Contacts.PHOTO_URI)
            );

            if (hasPhone) {
                contactHasPhoto = hasContactPhoto(contactId);

                tasker.log("Contact: " + contactName + " | hasPhoto: " + contactHasPhoto + " | photoUri: " + (photoUri != null ? photoUri : "null"));

                if (updateMode.equals("true") && contactHasPhoto) {
                    tasker.log("Skipping " + contactName + " - already has photo");
                    skippedContacts++;

                    skippedContactInfo = new java.util.HashMap();
                    skippedContactInfo.put("id", String.valueOf(contactId));
                    skippedContactInfo.put("name", contactName);
                    skippedContactInfo.put("reason", "already_has_photo");
                    skippedContactsList.add(skippedContactInfo);

                    tasker.logAndToast(contactName + " (" + contactCounter + "/" + totalContactsToProcess + ") | Atualizados: " + successfulUpdates + " | Ignorados: " + skippedContacts);

                    continue;
                }

                phoneProjection = new String[]{
                    ContactsContract.CommonDataKinds.Phone.NUMBER,
                    ContactsContract.CommonDataKinds.Phone.TYPE,
                    ContactsContract.CommonDataKinds.Phone.LABEL,
                    ContactsContract.CommonDataKinds.Phone.NORMALIZED_NUMBER
                };

                phoneCursor = context.getContentResolver().query(
                    ContactsContract.CommonDataKinds.Phone.CONTENT_URI,
                    phoneProjection,
                    ContactsContract.CommonDataKinds.Phone.CONTACT_ID + " = ?",
                    new String[]{String.valueOf(contactId)},
                    null
                );

                phones = new java.util.ArrayList();
                if (phoneCursor != null && phoneCursor.moveToFirst()) {
                    do {
                        phoneNumber = phoneCursor.getString(
                            phoneCursor.getColumnIndex(ContactsContract.CommonDataKinds.Phone.NUMBER)
                        );
                        phoneType = phoneCursor.getInt(
                            phoneCursor.getColumnIndex(ContactsContract.CommonDataKinds.Phone.TYPE)
                        );
                        phoneLabel = phoneCursor.getString(
                            phoneCursor.getColumnIndex(ContactsContract.CommonDataKinds.Phone.LABEL)
                        );
                        normalizedNumber = phoneCursor.getString(
                            phoneCursor.getColumnIndex(ContactsContract.CommonDataKinds.Phone.NORMALIZED_NUMBER)
                        );

                        cleanPhone = phoneNumber.replaceAll("[^0-9]", "");
                        totalNumbersFound++;

                        variations = generatePhoneVariations(cleanPhone);

                        isMobile = (phoneType == 2);

                        isWhatsApp = false;
                        isWhatsAppBusiness = false;

                        if (cleanPhone.length() >= 10 && (cleanPhone.startsWith("55") || cleanPhone.length() >= 10)) {
                            isWhatsApp = true;
                        }

                        if (phoneType == 2) {
                            isWhatsApp = true;
                        }

                        if (whatsappInstalled) {
                            try {
                                uriWhatsApp = Uri.parse("content://com.whatsapp.provider/contacts");
                                cursorWA = context.getContentResolver().query(
                                    uriWhatsApp,
                                    new String[]{"number"},
                                    "number = ?",
                                    new String[]{cleanPhone},
                                    null
                                );
                                if (cursorWA != null && cursorWA.moveToFirst()) {
                                    isWhatsApp = true;
                                }
                                if (cursorWA != null) {
                                    cursorWA.close();
                                }
                            } catch (Exception e) {
                            }
                        }

                        if (whatsappBusinessInstalled) {
                            try {
                                uriWAB = Uri.parse("content://com.whatsapp.w4b.provider/contacts");
                                cursorWAB = context.getContentResolver().query(
                                    uriWAB,
                                    new String[]{"number"},
                                    "number = ?",
                                    new String[]{cleanPhone},
                                    null
                                );
                                if (cursorWAB != null && cursorWAB.moveToFirst()) {
                                    isWhatsAppBusiness = true;
                                }
                                if (cursorWAB != null) {
                                    cursorWAB.close();
                                }
                            } catch (Exception e) {
                            }
                        }

                        if (!isWhatsApp && !isWhatsAppBusiness) {
                            accountCursor = context.getContentResolver().query(
                                ContactsContract.RawContacts.CONTENT_URI,
                                new String[]{ContactsContract.RawContacts.ACCOUNT_NAME},
                                ContactsContract.RawContacts.CONTACT_ID + " = ?",
                                new String[]{String.valueOf(contactId)},
                                null
                            );

                            if (accountCursor != null && accountCursor.moveToFirst()) {
                                do {
                                    accountName = accountCursor.getString(0);
                                    if (accountName != null) {
                                        if (accountName.toLowerCase().contains("whatsapp") && !accountName.toLowerCase().contains("business")) {
                                            isWhatsApp = true;
                                        }
                                        if (accountName.toLowerCase().contains("business")) {
                                            isWhatsAppBusiness = true;
                                        }
                                    }
                                } while (accountCursor.moveToNext());
                                accountCursor.close();
                            }
                        }

                        whatsappStatus = "";
                        if (isWhatsApp && isWhatsAppBusiness) {
                            whatsappStatus = "Both";
                            totalWhatsAppContacts++;
                        } else if (isWhatsApp) {
                            whatsappStatus = "WhatsApp";
                            totalWhatsAppContacts++;
                        } else if (isWhatsAppBusiness) {
                            whatsappStatus = "WhatsApp Business";
                            totalWhatsAppContacts++;
                        } else {
                            whatsappStatus = "None";
                        }

                        avatarUrl = null;
                        if (isWhatsApp || isWhatsAppBusiness) {
                            for (k = 0; k < variations.size() && avatarUrl == null; k++) {
                                tryNumber = (String) variations.get(k);
                                phoneWithSuffix = tryNumber + "@s.whatsapp.net";
                                tasker.log("Trying: " + phoneWithSuffix);

                                try {
                                    avatarRequest = new Request.Builder()
                                        .url("http://127.0.0.1:3000/user/avatar?phone=" + phoneWithSuffix + "&is_preview=false&is_community=false")
                                        .header("Accept", "application/json")
                                        .header("Authorization", "Basic dXNlcjE6cGFzczE=")
                                        .header("X-Device-Id", deviceId)
                                        .build();

                                    avatarResponse = client.newCall(avatarRequest).execute();
                                    avatarBody = avatarResponse.body().string();
                                    avatarJson = new JSONObject(avatarBody);

                                    if (avatarJson.getString("code").equals("SUCCESS")) {
                                        resultsObj = avatarJson.getJSONObject("results");
                                        avatarUrl = resultsObj.getString("url");
                                        tasker.log("Avatar found for " + contactName + " with: " + tryNumber);
                                    }
                                } catch (Exception e) {
                                    tasker.log("Error with " + tryNumber + ": " + e.getMessage());
                                }
                            }

                            if (avatarUrl == null) {
                                tasker.log("No avatar found for " + contactName + " after " + variations.size() + " attempts");
                            }
                        }

                        avatarUpdated = false;
                        if (avatarUrl != null && avatarUrl.length() > 0) {
                            try {
                                imageRequest = new Request.Builder()
                                    .url(avatarUrl)
                                    .build();

                                imageResponse = client.newCall(imageRequest).execute();
                                imageBytes = imageResponse.body().bytes();

                                if (imageBytes != null && imageBytes.length > 0) {
                                    rawContactId = null;
                                    rawContactCursor2 = context.getContentResolver().query(
                                        ContactsContract.RawContacts.CONTENT_URI,
                                        new String[]{ContactsContract.RawContacts._ID},
                                        ContactsContract.RawContacts.CONTACT_ID + " = ?",
                                        new String[]{String.valueOf(contactId)},
                                        null
                                    );

                                    if (rawContactCursor2 != null && rawContactCursor2.moveToFirst()) {
                                        rawContactId = rawContactCursor2.getLong(0);
                                    }
                                    if (rawContactCursor2 != null) {
                                        rawContactCursor2.close();
                                    }

                                    if (rawContactId != null) {
                                        rawContactUri = Uri.parse("content://com.android.contacts/raw_contacts");
                                        rawContactUri = Uri.withAppendedPath(rawContactUri, String.valueOf(rawContactId));
                                        photoUri2 = Uri.withAppendedPath(rawContactUri, "display_photo");

                                        afd = context.getContentResolver().openAssetFileDescriptor(photoUri2, "rw");
                                        os = afd.createOutputStream();
                                        os.write(imageBytes);
                                        os.close();
                                        afd.close();

                                        successfulUpdates++;
                                        avatarUpdated = true;
                                        tasker.log("Avatar updated: " + contactName);
                                    }
                                }
                            } catch (Exception e) {
                                failedUpdates++;
                                tasker.log("Failed to save avatar for " + contactName + ": " + e.getMessage());
                            }
                        }

                        processed++;

                        phoneMap = new java.util.HashMap();
                        phoneMap.put("number", phoneNumber != null ? phoneNumber : "");
                        phoneMap.put("clean_number", cleanPhone);
                        phoneMap.put("type", String.valueOf(phoneType));
                        phoneMap.put("label", phoneLabel != null ? phoneLabel : "");
                        phoneMap.put("normalized", normalizedNumber != null ? normalizedNumber : "");
                        phoneMap.put("is_mobile", isMobile ? "true" : "false");
                        phoneMap.put("whatsapp_status", whatsappStatus);
                        phoneMap.put("has_whatsapp", isWhatsApp ? "true" : "false");
                        phoneMap.put("has_whatsapp_business", isWhatsAppBusiness ? "true" : "false");
                        phoneMap.put("avatar_url", avatarUrl != null ? avatarUrl : "");
                        phoneMap.put("avatar_updated", avatarUpdated ? "true" : "false");
                        phones.add(phoneMap);
                    } while (phoneCursor.moveToNext());
                    phoneCursor.close();
                }

                contactEntry = new java.util.HashMap();
                contactEntry.put("id", String.valueOf(contactId));
                contactEntry.put("name", contactName != null ? contactName : "");
                contactEntry.put("has_phone", String.valueOf(hasPhone));
                contactEntry.put("starred", String.valueOf(starred));
                contactEntry.put("has_photo", (photoUri != null && photoUri.length() > 0) ? "true" : "false");
                contactEntry.put("phones", phones);

                allContacts.add(contactEntry);

                if (avatarUpdated) {
                    updatedContactInfo = new java.util.HashMap();
                    updatedContactInfo.put("id", String.valueOf(contactId));
                    updatedContactInfo.put("name", contactName);
                    updatedContactsList.add(updatedContactInfo);
                }
            }

            tasker.logAndToast(contactName + " (" + contactCounter + "/" + totalContactsToProcess + ") | Atualizados: " + successfulUpdates + " | Ignorados: " + skippedContacts);

        } while (contactCursor.moveToNext());
        contactCursor.close();
    }
} catch (Exception e) {
    error = "ERROR: Failed to retrieve contacts: " + e.getMessage();
    tasker.setVariable("error", error);
    return error;
}

tasker.log("Completed! Updated " + successfulUpdates + " avatars, " + failedUpdates + " failed, " + skippedContacts + " skipped");

totalContacts = allContacts.size();

jsonResult = new java.util.HashMap();

if (failedUpdates > 0) {
    jsonResult.put("status", "partial_success");
} else {
    jsonResult.put("status", "success");
}

jsonResult.put("update_mode", updateMode);
jsonResult.put("device_id_used", deviceId);
jsonResult.put("max_contacts_limit", String.valueOf(MAX_CONTACTS));
jsonResult.put("total_contacts", String.valueOf(totalContacts));
jsonResult.put("total_numbers", String.valueOf(totalNumbersFound));
jsonResult.put("total_whatsapp_contacts", String.valueOf(totalWhatsAppContacts));
jsonResult.put("avatars_updated", String.valueOf(successfulUpdates));
jsonResult.put("avatars_failed", String.valueOf(failedUpdates));
jsonResult.put("avatars_skipped", String.valueOf(skippedContacts));

summaryResult = new java.util.HashMap();
summaryResult.put("updated_count", String.valueOf(successfulUpdates));
summaryResult.put("skipped_count", String.valueOf(skippedContacts));
summaryResult.put("failed_count", String.valueOf(failedUpdates));

updatedListJson = new java.util.ArrayList();
for (i = 0; i < updatedContactsList.size(); i++) {
    contactInfo = (java.util.HashMap) updatedContactsList.get(i);
    updatedListJson.add(contactInfo);
}
summaryResult.put("updated_contacts", updatedListJson);

skippedListJson = new java.util.ArrayList();
for (i = 0; i < skippedContactsList.size(); i++) {
    contactInfo = (java.util.HashMap) skippedContactsList.get(i);
    skippedListJson.add(contactInfo);
}
summaryResult.put("skipped_contacts", skippedListJson);

jsonResult.put("summary", summaryResult);

jsonResult.put("whatsapp_installed", String.valueOf(whatsappInstalled));
jsonResult.put("whatsapp_business_installed", String.valueOf(whatsappBusinessInstalled));

contactsArray = new java.util.ArrayList();
numbersList = new java.util.ArrayList();

for (i = 0; i < allContacts.size(); i++) {
    contactEntry = (java.util.HashMap) allContacts.get(i);

    contactObj = new java.util.HashMap();
    contactObj.put("id", (String) contactEntry.get("id"));
    contactObj.put("name", (String) contactEntry.get("name"));
    contactObj.put("starred", (String) contactEntry.get("starred"));
    contactObj.put("has_photo", (String) contactEntry.get("has_photo"));

    phonesArray = new java.util.ArrayList();
    phonesList = (java.util.ArrayList) contactEntry.get("phones");
    for (j = 0; j < phonesList.size(); j++) {
        phoneMap = (java.util.HashMap) phonesList.get(j);
        phoneObj = new java.util.HashMap();
        phoneObj.put("number", (String) phoneMap.get("number"));
        phoneObj.put("clean_number", (String) phoneMap.get("clean_number"));
        phoneObj.put("is_mobile", (String) phoneMap.get("is_mobile"));
        phoneObj.put("whatsapp_status", (String) phoneMap.get("whatsapp_status"));
        phoneObj.put("has_whatsapp", (String) phoneMap.get("has_whatsapp"));
        phoneObj.put("has_whatsapp_business", (String) phoneMap.get("has_whatsapp_business"));
        phoneObj.put("avatar_url", (String) phoneMap.get("avatar_url"));
        phoneObj.put("avatar_updated", (String) phoneMap.get("avatar_updated"));
        phonesArray.add(phoneObj);

        numberEntry = new java.util.HashMap();
        numberEntry.put("name", (String) contactEntry.get("name"));
        numberEntry.put("number", (String) phoneMap.get("number"));
        numberEntry.put("clean_number", (String) phoneMap.get("clean_number"));
        numberEntry.put("whatsapp_status", (String) phoneMap.get("whatsapp_status"));
        numberEntry.put("avatar_updated", (String) phoneMap.get("avatar_updated"));
        numbersList.add(numberEntry);
    }
    contactObj.put("phones", phonesArray);
    contactsArray.add(contactObj);
}

jsonResult.put("contacts", contactsArray);
jsonResult.put("all_numbers", numbersList);
jsonResult.put("created_at", new java.util.Date().toString());

tasker.setVariable("error", "");
tasker.setVariable("update_summary", tasker.toJson(summaryResult), true);

return tasker.toJson(jsonResult);

import android.content.ContentValues;
import android.content.ContentResolver;
import android.net.Uri;
import android.database.Cursor;
import android.provider.ContactsContract;
import android.provider.ContactsContract.CommonDataKinds;
import com.joaomgcd.taskerm.action.java.JavaCodeException;

error = null;

tasker.log("Starting FULL contact photo removal...");

contactsProjection = new String[]{
    ContactsContract.Contacts._ID,
    ContactsContract.Contacts.DISPLAY_NAME,
    ContactsContract.Contacts.HAS_PHONE_NUMBER,
    ContactsContract.Contacts.PHOTO_URI,
    ContactsContract.Contacts.STARRED
};

contactCursor = null;
allContacts = new java.util.ArrayList();
totalContactsProcessed = 0;
successfulRemovals = 0;
failedRemovals = 0;
processed = 0;
contactCounter = 0;

try {
    contactCursor = context.getContentResolver().query(
        ContactsContract.Contacts.CONTENT_URI,
        contactsProjection,
        null,
        null,
        ContactsContract.Contacts.DISPLAY_NAME + " ASC"
    );

    if (contactCursor != null && contactCursor.moveToFirst()) {
        do {
            contactCounter++;

            contactId = contactCursor.getLong(
                contactCursor.getColumnIndex(ContactsContract.Contacts._ID)
            );
            contactName = contactCursor.getString(
                contactCursor.getColumnIndex(ContactsContract.Contacts.DISPLAY_NAME)
            );
            photoUri = contactCursor.getString(
                contactCursor.getColumnIndex(ContactsContract.Contacts.PHOTO_URI)
            );

            rawContactIds = new java.util.ArrayList();
            rawContactAccountTypes = new java.util.HashMap();

            rawContactCursor = context.getContentResolver().query(
                ContactsContract.RawContacts.CONTENT_URI,
                new String[]{
                    ContactsContract.RawContacts._ID,
                    ContactsContract.RawContacts.ACCOUNT_TYPE
                },
                ContactsContract.RawContacts.CONTACT_ID + " = ?",
                new String[]{String.valueOf(contactId)},
                null
            );

            if (rawContactCursor != null && rawContactCursor.moveToFirst()) {
                do {
                    rid = rawContactCursor.getLong(0);
                    accType = rawContactCursor.getString(1);
                    rawContactIds.add(rid);
                    rawContactAccountTypes.put(rid, accType == null ? "local" : accType);
                } while (rawContactCursor.moveToNext());
            }
            if (rawContactCursor != null) {
                rawContactCursor.close();
            }

            if (rawContactIds.size() == 0) {
                tasker.log("No raw_contact_id found for: " + contactName);
                continue;
            }

            hasPhoto = false;
            rawIdsWithPhotoData = new java.util.ArrayList();

            for (r = 0; r < rawContactIds.size(); r++) {
                rawId = (Long) rawContactIds.get(r);

                dataCursor = context.getContentResolver().query(
                    ContactsContract.Data.CONTENT_URI,
                    new String[]{ContactsContract.Data._ID},
                    ContactsContract.Data.RAW_CONTACT_ID + "=? AND " + ContactsContract.Data.MIMETYPE + "=?",
                    new String[]{String.valueOf(rawId), CommonDataKinds.Photo.CONTENT_ITEM_TYPE},
                    null
                );

                if (dataCursor != null) {
                    if (dataCursor.moveToFirst()) {
                        hasPhoto = true;
                        rawIdsWithPhotoData.add(rawId);
                    }
                    dataCursor.close();
                }
            }

            if (!hasPhoto && photoUri != null && photoUri.length() > 0) {
                hasPhoto = true;
            }

            if (!hasPhoto) {
                continue;
            }

            totalContactsProcessed++;
            tasker.log("Removing photo from: " + contactName + " (ID: " + contactId + ", raw_ids with Data.Photo: " + rawIdsWithPhotoData.size() + ")");

            photoRemoved = false;
            deletedRowsTotal = 0;

            for (r = 0; r < rawContactIds.size(); r++) {
                rawId = (Long) rawContactIds.get(r);
                accType = (String) rawContactAccountTypes.get(rawId);

                try {
                    deletedRows = context.getContentResolver().delete(
                        ContactsContract.Data.CONTENT_URI,
                        ContactsContract.Data.RAW_CONTACT_ID + "=? AND " + ContactsContract.Data.MIMETYPE + "=?",
                        new String[]{String.valueOf(rawId), CommonDataKinds.Photo.CONTENT_ITEM_TYPE}
                    );

                    if (deletedRows > 0) {
                        deletedRowsTotal += deletedRows;
                        photoRemoved = true;
                        tasker.log("Deleted " + deletedRows + " Photo row(s) from Data for raw_contact " + rawId + " (account: " + accType + ")");
                    }
                } catch (Exception e) {
                    tasker.log("Data delete failed for raw_contact " + rawId + ": " + e.getMessage());
                }
            }

            for (r = 0; r < rawContactIds.size(); r++) {
                rawId = (Long) rawContactIds.get(r);

                try {
                    rawContactUri = Uri.parse("content://com.android.contacts/raw_contacts");
                    rawContactUri = Uri.withAppendedPath(rawContactUri, String.valueOf(rawId));
                    displayPhotoUri = Uri.withAppendedPath(rawContactUri, "display_photo");

                    afd = context.getContentResolver().openAssetFileDescriptor(displayPhotoUri, "rw");
                    if (afd != null) {
                        os = afd.createOutputStream();
                        os.write(new byte[0]);
                        os.flush();
                        os.close();
                        afd.close();
                        tasker.log("display_photo cache cleared for raw_contact: " + rawId);
                    }
                } catch (Exception e) {
                    tasker.log("display_photo clear skipped for raw_contact " + rawId + ": " + e.getMessage());
                }
            }

            if (!photoRemoved) {
                try {
                    contactPhotoUri = Uri.parse("content://com.android.contacts/contacts");
                    contactPhotoUri = Uri.withAppendedPath(contactPhotoUri, String.valueOf(contactId));
                    contactPhotoUri = Uri.withAppendedPath(contactPhotoUri, "photo");

                    afd2 = context.getContentResolver().openAssetFileDescriptor(contactPhotoUri, "rw");
                    if (afd2 != null) {
                        os2 = afd2.createOutputStream();
                        os2.write(new byte[0]);
                        os2.flush();
                        os2.close();
                        afd2.close();
                        photoRemoved = true;
                        tasker.log("Photo removed via legacy contacts/photo fallback");
                    }
                } catch (Exception e) {
                    tasker.log("Fallback method failed: " + e.getMessage());
                }
            }

            stillHasPhoto = false;
            for (r = 0; r < rawContactIds.size(); r++) {
                rawId = (Long) rawContactIds.get(r);
                verifyCursor = context.getContentResolver().query(
                    ContactsContract.Data.CONTENT_URI,
                    new String[]{ContactsContract.Data._ID},
                    ContactsContract.Data.RAW_CONTACT_ID + "=? AND " + ContactsContract.Data.MIMETYPE + "=?",
                    new String[]{String.valueOf(rawId), CommonDataKinds.Photo.CONTENT_ITEM_TYPE},
                    null
                );
                if (verifyCursor != null) {
                    if (verifyCursor.moveToFirst()) {
                        stillHasPhoto = true;
                    }
                    verifyCursor.close();
                }
            }

            if (!stillHasPhoto) {
                photoRemoved = true;
                successfulRemovals++;
            } else {
                failedRemovals++;
                tasker.log("Photo STILL present after all methods for: " + contactName + " (likely a synced account rewriting it, e.g. Google)");
            }

            contactInfo = new java.util.HashMap();
            contactInfo.put("id", String.valueOf(contactId));
            contactInfo.put("name", contactName);
            contactInfo.put("data_rows_deleted", String.valueOf(deletedRowsTotal));
            contactInfo.put("photo_removed", photoRemoved ? "true" : "false");
            allContacts.add(contactInfo);

            processed++;

            if (processed % 10 == 0 || processed == contactCounter) {
                tasker.log("Progress: " + processed + " contacts scanned | Removed: " + successfulRemovals + " | Failed: " + failedRemovals);
            }

        } while (contactCursor.moveToNext());
        contactCursor.close();
    }
} catch (Exception e) {
    error = "ERROR: Failed to retrieve contacts: " + e.getMessage();
    tasker.setVariable("error", error);
    return error;
}

tasker.log("Completed! Removed " + successfulRemovals + " photos, " + failedRemovals + " failed");

jsonResult = new java.util.HashMap();
jsonResult.put("status", "success");
jsonResult.put("message", "Contact photos removed successfully");
jsonResult.put("total_contacts_scanned", String.valueOf(contactCounter));
jsonResult.put("contacts_with_photos", String.valueOf(totalContactsProcessed));
jsonResult.put("photos_removed", String.valueOf(successfulRemovals));
jsonResult.put("photos_failed", String.valueOf(failedRemovals));

contactsList = new java.util.ArrayList();
for (i = 0; i < allContacts.size(); i++) {
    contactInfo = (java.util.HashMap) allContacts.get(i);
    contactsList.add(contactInfo);
}
jsonResult.put("contacts_processed", contactsList);

jsonResult.put("created_at", new java.util.Date().toString());

tasker.setVariable("error", "");
return tasker.toJson(jsonResult);

import java.util.regex.Matcher;
import java.util.regex.Pattern;
import java.util.ArrayList;
import java.util.List;

String input = tasker.getVariable("phones_participants");

List result = new ArrayList();

if (input != null && input.length() > 0) {
    Pattern pattern = Pattern.compile("\\d{12}");
    Matcher matcher = pattern.matcher(input);

    while (matcher.find()) {
        result.add(matcher.group());
    }
