            fileType = rootJson.substring(typeStart, typeEnd);
            if (fileType.equals("dir")) {
                subDirs.add(dirName);
            }
        }
    }
    startIndex = nameEnd + 1;
}

for (int i = 0; i < subDirs.size(); i++) {
    subDir = (String) subDirs.get(i);
    subDirUrl = "https://api.github.com/repos/multihubandredye-prog/W-C-A_GO/contents/wca-resources/media/" + subDir + "?ref=main";

    subJson = null;
    try {
        url = new URL(subDirUrl);
        connection = (HttpURLConnection) url.openConnection();
        connection.setRequestMethod("GET");
        connection.setConnectTimeout(15000);
        connection.setReadTimeout(15000);
        connection.setRequestProperty("Accept", "application/vnd.github.v3+json");
        connection.connect();

        responseCode = connection.getResponseCode();

        if (responseCode == HttpURLConnection.HTTP_OK) {
            inputStream = connection.getInputStream();
            reader = new BufferedReader(new InputStreamReader(inputStream));
            stringBuilder = new StringBuilder();
            line = null;

            while ((line = reader.readLine()) != null) {
                stringBuilder.append(line);
            }

            reader.close();
            inputStream.close();
            subJson = stringBuilder.toString();
        } else {
            errorLog.add("Subdir " + subDir + " HTTP " + responseCode);
        }
        connection.disconnect();
    } catch (Exception e) {
        errorLog.add("Subdir " + subDir + ": " + e.getClass().getSimpleName() + " - " + e.getMessage());
        tasker.log("Error fetching " + subDir + ": " + e.getMessage());
    }

    if (subJson != null) {
        searchPattern = "\"name\":\"";
        startIndex = 0;

        while (true) {
            nameStart = subJson.indexOf(searchPattern, startIndex);
            if (nameStart == -1) break;
            nameStart = nameStart + searchPattern.length();
            nameEnd = subJson.indexOf("\"", nameStart);
            if (nameEnd == -1) break;
            fileName = subJson.substring(nameStart, nameEnd);

            typePattern = "\"type\":\"";
            typeStart = subJson.indexOf(typePattern, nameEnd);
            if (typeStart != -1) {
                typeStart = typeStart + typePattern.length();
                typeEnd = subJson.indexOf("\"", typeStart);
                if (typeEnd != -1) {
                    fileType = subJson.substring(typeStart, typeEnd);
                    if (fileType.equals("file")) {
                        allGitHubFiles.add(fileName);
                    }
                }
            }
            startIndex = nameEnd + 1;
        }
    }
}

if (allGitHubFiles.size() == 0) {
    tasker.setVariable("download_status", "no_files");
    tasker.setVariable("download_error_log", errorLog.toString());
    return "No media files found";
}

gitHubFileList = "";
for (int i = 0; i < allGitHubFiles.size(); i++) {
    fileName = (String) allGitHubFiles.get(i);
    if (i > 0) gitHubFileList = gitHubFileList + ", ";
    gitHubFileList = gitHubFileList + fileName;
}
tasker.setVariable("github_files_list", gitHubFileList);

localFiles = new ArrayList();
localDirCheck = new File(localBasePath);
if (localDirCheck.exists()) {
    filesArray = localDirCheck.listFiles();
    if (filesArray != null) {
        for (int i = 0; i < filesArray.length; i++) {
            fileEntry = filesArray[i];
            if (fileEntry.isFile()) {
                localFiles.add(fileEntry.getName());
            }
        }
    }
}

localFileList = "";
for (int i = 0; i < localFiles.size(); i++) {
    localFile = (String) localFiles.get(i);
    if (i > 0) localFileList = localFileList + ", ";
    localFileList = localFileList + localFile;
}
tasker.setVariable("local_files_list", localFileList);

missingFiles = new ArrayList();
for (int i = 0; i < allGitHubFiles.size(); i++) {
    fileName = (String) allGitHubFiles.get(i);
    fileExists = false;
    for (int j = 0; j < localFiles.size(); j++) {
        localFile = (String) localFiles.get(j);
        if (localFile.equals(fileName)) {
            fileExists = true;
            break;
        }
    }
    if (!fileExists) {
        missingFiles.add(fileName);
    }
}

if (missingFiles.size() == 0) {
    tasker.setVariable("download_status", "all_present");
    tasker.setVariable("download_count", "0");
    tasker.setVariable("missing_files_list", "none");
    tasker.setVariable("download_error_log", errorLog.toString());
    return "All files already present";
}

missingFileList = "";
for (int i = 0; i < missingFiles.size(); i++) {
    fileName = (String) missingFiles.get(i);
    if (i > 0) missingFileList = missingFileList + ", ";
    missingFileList = missingFileList + fileName;
}
tasker.setVariable("missing_files_list", missingFileList);

shownSignal = CompletableSubject.create();
statusTextRef = new TextView[1];
activityRef = new Activity[1];
dialogRef = new AlertDialog[1];

dialogConsumer = new Consumer() {
    accept(Object activityObj) {
        activity = (Activity) activityObj;
        activityRef[0] = activity;

        statusText = new TextView(activity);
        statusText.setText("Iniciando download...");
        statusText.setPadding(48, 32, 48, 32);
        statusText.setTextSize(15);
        statusTextRef[0] = statusText;

        container = new LinearLayout(activity);
        container.setOrientation(LinearLayout.VERTICAL);
        container.addView(statusText);

        builder = new AlertDialog.Builder(activity);
        builder.setTitle("Baixando arquivos do seu WCA, aguarde...");
        builder.setView(container);
        builder.setCancelable(false);
        dialog = builder.create();
        dialog.show();
        dialogRef[0] = dialog;

        shownSignal.onComplete();
    }
};

tasker.doWithActivity(dialogConsumer);
shownSignal.blockingAwait();

activity = activityRef[0];
statusText = statusTextRef[0];
dialog = dialogRef[0];

updateStatus = new Consumer() {
    accept(Object text) {
        final String msg = (String) text;
        activity.runOnUiThread(new Runnable() {
            run() {
                statusText.setText(msg);
            }
        });
    }
};

closeDialog = new Runnable() {
    run() {
        dialog.dismiss();
        activity.finish();
    }
};

downloadedCount = 0;
failedFiles = new ArrayList();

for (int i = 0; i < missingFiles.size(); i++) {
    fileName = (String) missingFiles.get(i);

    updateStatus.accept("Baixando " + fileName + " (" + (i + 1) + "/" + missingFiles.size() + ")");

    fileUrl = null;
    found = false;

    for (int j = 0; j < subDirs.size(); j++) {
        subDir = (String) subDirs.get(j);
        testUrl = githubBaseUrl + subDir + "/" + fileName;

        try {
            testConn = (HttpURLConnection) new URL(testUrl).openConnection();
            testConn.setRequestMethod("HEAD");
            testConn.setConnectTimeout(5000);
            testConn.connect();
            testCode = testConn.getResponseCode();
            testConn.disconnect();

            if (testCode == HttpURLConnection.HTTP_OK) {
                fileUrl = testUrl;
                found = true;
                break;
            }
        } catch (Exception e) {
        }
    }

    if (!found) {
        for (int j = 0; j < subDirs.size(); j++) {
            subDir = (String) subDirs.get(j);
            testUrl = githubBaseUrl + subDir + "/" + fileName;
            fileUrl = testUrl;
            found = true;
            break;
        }
    }

    if (fileUrl == null) {
        failedFiles.add(fileName);
        errorLog.add(fileName + ": subdiretório não encontrado");
        continue;
    }

    localFile = new File(localBasePath, fileName);

    try {
        url = new URL(fileUrl);
        connection = (HttpURLConnection) url.openConnection();
        connection.setRequestMethod("GET");
        connection.setConnectTimeout(15000);
        connection.setReadTimeout(15000);
        connection.connect();

        responseCode = connection.getResponseCode();

        if (responseCode == HttpURLConnection.HTTP_OK) {
            inputStream = connection.getInputStream();
            outputStream = new FileOutputStream(localFile);

            buffer = new byte[8192];
            bytesRead = 0;

            while ((bytesRead = inputStream.read(buffer)) != -1) {
                outputStream.write(buffer, 0, bytesRead);
            }

            outputStream.close();
            inputStream.close();
            downloadedCount++;
        } else {
            failedFiles.add(fileName);
            errorLog.add(fileName + ": HTTP " + responseCode);
        }

        connection.disconnect();
    } catch (Exception e) {
        failedFiles.add(fileName);
        errorLog.add(fileName + ": " + e.getClass().getSimpleName() + " - " + e.getMessage());
        tasker.log("Error: " + fileName + " - " + e.getMessage());
    }
}

tasker.setVariable("download_status", failedFiles.size() == 0 ? "success" : "partial_failure");
tasker.setVariable("download_count", String.valueOf(downloadedCount));
tasker.setVariable("total_missing", String.valueOf(missingFiles.size()));
tasker.setVariable("download_failed_count", String.valueOf(failedFiles.size()));
tasker.setVariable("download_error_log", errorLog.toString());

if (failedFiles.size() == 0 && downloadedCount > 0) {
    tasker.setVariable("download_message", "Downloaded " + downloadedCount + " file(s)");
    updateStatus.accept(downloadedCount + " arquivo(s) baixado(s) com sucesso");
    Thread.sleep(1500);
    activity.runOnUiThread(closeDialog);
    return "Successfully downloaded " + downloadedCount + " file(s)";
} else if (failedFiles.size() == 0 && downloadedCount == 0) {
    tasker.setVariable("download_message", "All files present");
    updateStatus.accept("Todos os arquivos já estavam presentes");
    Thread.sleep(1500);
    activity.runOnUiThread(closeDialog);
    return "All files already present";
} else {
    tasker.setVariable("download_message", "Downloaded " + downloadedCount + " of " + missingFiles.size() + " files");
    tasker.setVariable("download_failed_files", failedFiles.toString());
    updateStatus.accept(downloadedCount + " de " + missingFiles.size() + " baixados, " + failedFiles.size() + " falha(s)");
    Thread.sleep(1500);
    activity.runOnUiThread(closeDialog);
    return "Downloaded " + downloadedCount + " of " + missingFiles.size() + " files. Failed: " + failedFiles.size();
}

import okhttp3.OkHttpClient;
