errorLog = new ArrayList();

String urlApi = tasker.getVariable("url_project_wca");
if (urlApi == null || urlApi.equals("")) {
    errorLog.add("URL_PROJECT_WCA não definida");
    tasker.setVariable("download_error_log", errorLog.toString());
    return "Error: URL_PROJECT_WCA não definida";
}

String filePath = "/storage/emulated/0/Tasker/projects_task/projects/whats-connect-api/system/tasks-send/W_C_A_API_RECEIVER.prj.xml";
OkHttpClient client = new OkHttpClient();
String releaseJson = null;

try {
    Request request = new Request.Builder().url(urlApi).build();
    Response response = client.newCall(request).execute();
    if (response.isSuccessful()) {
        releaseJson = response.body().string();
    } else {
        errorLog.add("Falha ao buscar release: HTTP " + response.code());
        tasker.setVariable("download_error_log", errorLog.toString());
        return "Error: Falha ao buscar release";
    }
    response.close();
} catch (Exception e) {
    errorLog.add("Requisição release: " + e.getClass().getSimpleName() + " - " + e.getMessage());
    tasker.setVariable("download_error_log", errorLog.toString());
    return "Error: " + e.getMessage();
}

JSONObject release = new JSONObject(releaseJson);
JSONArray assets = release.getJSONArray("assets");
String url = null;

for (int i = 0; i < assets.length(); i++) {
    JSONObject asset = assets.getJSONObject(i);
    String name = asset.getString("name");
    String downloadUrl = asset.getString("browser_download_url");

    if (name.equals("W_C_A_API_RECEIVER.prj.xml")) {
        url = downloadUrl;
        break;
    }
}

if (url == null) {
    errorLog.add("Arquivo W_C_A_API_RECEIVER.prj.xml não encontrado no release");
    tasker.setVariable("download_error_log", errorLog.toString());
    return "Error: Arquivo não encontrado";
}

/* Só a partir daqui, com o arquivo localizado, o diálogo é exibido. */
