    function showToast({title = '', message = '', type = 'info', duration = CONFIG.TOAST_DURATION} = {}){
        const container = document.getElementById('toastContainer');
        if(!container) return;
        const icons = {success: 'fa-circle-check', error: 'fa-circle-xmark', info: 'fa-circle-info', warning: 'fa-triangle-exclamation'};
        const tmpl = document.getElementById('toastTemplate');
        const frag = tmpl ? tmpl.content.cloneNode(true) : document.createDocumentFragment();
        const el = frag.querySelector('.toast');
        if(!el) return;
        el.classList.add(`toast-${type}`);
        const iconEl = el.querySelector('i');
        if(iconEl) iconEl.classList.add(icons[type] || icons.info);
        const titleEl = el.querySelector('.toast-title');
        if(titleEl){
            titleEl.textContent = title;
            if(!title) titleEl.classList.add('d-none');
        }
        const msgEl = el.querySelector('.toast-message');
        if(msgEl) msgEl.textContent = message;
        container.appendChild(el);
        setTimeout(() => {
            el.classList.add('removing');
            el.addEventListener('animationend', () => el.remove(), {once: true});
        }, duration);
    }

    function showEl(el){ if(el) el.classList.remove('d-none'); }
    function hideEl(el){ if(el) el.classList.add('d-none'); }

    function openModal(id){
        const m = document.getElementById(id);
        if(!m) return;
        m.classList.add('open');
        m.setAttribute('aria-hidden', 'false');
        document.body.classList.add('modal-open');
    }

    function closeModal(id){
        const m = document.getElementById(id);
        if(!m) return;
        m.classList.remove('open');
        m.setAttribute('aria-hidden', 'true');
        if(!document.querySelector('.modal-overlay.open')) document.body.classList.remove('modal-open');

        if(id === 'zoomModal' && currentZoomId){
            stopAllTimers(currentZoomId);
            currentZoomId = null;
        }
        if(id === 'pairCodeModal'){
            stopAllTimers();
            currentPairDeviceId = null;
            currentCodePhone = null;
        }
        if(id === 'codePhoneModal'){
            currentPairDeviceId = null;
            currentCodePhone = null;
        }
    }

    function dismissModal(id){
        if(id === 'zoomModal'){ closeZoom(); return; }
        if(id === 'pairCodeModal'){ closePairCode(); return; }
        closeModal(id);
    }

    document.addEventListener('click', e => {
        const c = e.target.closest('[data-close]');
        if(c){ dismissModal(c.getAttribute('data-close')); return; }
        if(e.target.classList.contains('modal-overlay')) dismissModal(e.target.id);
    });

    document.addEventListener('keydown', e => {
        if(e.key === 'Escape') document.querySelectorAll('.modal-overlay.open').forEach(m => dismissModal(m.id));
    });

    function processLicense() {
        const isVip     = CONFIG.VIP_LOG_DATA.includes("MODO VIP");
        const isExpired = CONFIG.VIP_LOG_DATA.includes("LICENÇA EXPIRADA");

        dom.licenseLabel.classList.remove('status-vip', 'status-expired', 'status-test');
        dom.licenseIcon.classList.remove('status-vip', 'status-expired', 'status-test');

        if(dom.menuBtn) dom.menuBtn.classList.remove('d-none');

        if(isExpired){
            dom.createDeviceBtn.disabled = true;
            dom.licenseLabel.textContent = "LICENÇA EXPIRADA";
            dom.licenseLabel.classList.add('status-expired');
            dom.licenseIcon.classList.add('status-expired');
            dom.licenseIconI.className = 'fa-solid fa-circle-xmark';
        } else if(isVip){
            dom.licenseLabel.textContent = "MODO VIP ATIVO";
            dom.licenseLabel.classList.add('status-vip');
            dom.licenseIcon.classList.add('status-vip');
            dom.licenseIconI.className = 'fa-solid fa-crown';
        } else {
            dom.licenseLabel.textContent = "MODO TESTE ATIVO";
            dom.licenseLabel.classList.add('status-test');
            dom.licenseIcon.classList.add('status-test');
            dom.licenseIconI.className = 'fa-solid fa-flask';
        }

        const parts = CONFIG.VIP_LOG_DATA.split('|');
        if(parts.length >= 3){
            dom.licenseExpiry.textContent = parts[2].trim() + (parts[3] ? ` | ${parts[3].trim()}` : "");
        }

        validatePhoneNumber();
    }

    function setWelcome(){
        if(!dom.welcomeMessage) return;
        dom.welcomeMessage.innerHTML = '';
        if(!CONFIG.SHOW_WELCOME_MESSAGE){
            dom.welcomeMessage.classList.add('d-none');
            return;
        }
        dom.welcomeMessage.classList.remove('d-none');
        const isVip = CONFIG.VIP_LOG_DATA.includes('MODO VIP');
        const isExpired = CONFIG.VIP_LOG_DATA.includes('LICENÇA EXPIRADA');
        const vipBox = document.getElementById('getVipContainer');
        if(isVip && !isExpired){
            if(vipBox) vipBox.classList.add('d-none');
            const tmpl = document.getElementById('welcomeVipTemplate');
            if(tmpl){
                const frag = tmpl.content.cloneNode(true);
                const nameEl = frag.querySelector('.sparkle-name');
                if(nameEl) nameEl.textContent = (CONFIG.USER_NAME || "").toUpperCase();
                dom.welcomeMessage.appendChild(frag);
            }
        } else {
            if(vipBox) vipBox.classList.remove('d-none');
            const tmpl = document.getElementById('welcomeDefaultTemplate');
            if(tmpl){
                const frag = tmpl.content.cloneNode(true);
                const nameEl = frag.querySelector('.welcome-name');
                if(nameEl) nameEl.textContent = (CONFIG.USER_NAME || "").toUpperCase();
                dom.welcomeMessage.appendChild(frag);
            }
        }
    }

    function openTab(tabName){
        document.querySelectorAll(".tab-content").forEach(c => c.classList.remove("active"));
        document.querySelectorAll(".tab-btn").forEach(b => b.classList.remove("active"));
        const p = document.getElementById(tabName);
        if(p) p.classList.add("active");
        const btn = document.querySelector(`.tab-btn[data-tab="${tabName}"]`);
        if(btn) btn.classList.add('active');
        if(tabName === 'connections-tab'){
            checkServerStatus().then(isOnline => { if(isOnline) refreshAndVerifyNames(); });
        }
    }

    document.querySelectorAll('.tab-btn').forEach(btn => {
        btn.addEventListener('click', () => openTab(btn.dataset.tab));
    });

    function validatePhoneNumber(){
        const isExpired = CONFIG.VIP_LOG_DATA.includes("LICENÇA EXPIRADA");
        dom.telInput.value = dom.telInput.value.replace(/\D/g, '');
        const val = dom.telInput.value;
        const isValid = (val.length === 12 || val.length === 13);

        dom.valMsg.classList.remove('success', 'error');

        const sessionGroup = document.getElementById('sessionInputGroup');

        if(isExpired && val.length > 0){
            dom.valMsg.textContent = "ACESSO BLOQUEADO (LICENÇA EXPIRADA)";
            dom.valMsg.classList.add('error');
            dom.installBtn.disabled = true;
            if(sessionGroup) sessionGroup.classList.add('d-none');
        } else if(isValid){
            dom.valMsg.textContent = "✓ Válido";
            dom.valMsg.classList.add('success');
            dom.installBtn.disabled = false;
            if(sessionGroup) sessionGroup.classList.remove('d-none');
        } else {
            dom.valMsg.textContent = val.length === 0 ? "" : "✗ Inválido";
            if(val.length > 0) dom.valMsg.classList.add('error');
            dom.installBtn.disabled = true;
            if(sessionGroup) sessionGroup.classList.add('d-none');
        }
    }

    function validateBuyPhoneNumber(){
        dom.buyTelInput.value = dom.buyTelInput.value.replace(/\D/g, '');
        const isValid = (dom.buyTelInput.value.length === 12 || dom.buyTelInput.value.length === 13);
        dom.buyValMsg.classList.remove('success', 'error');
        if(isValid){
            dom.buyValMsg.textContent = "";
            dom.buySendBtn.disabled = false;
        } else {
            dom.buyValMsg.textContent = dom.buyTelInput.value.length === 0 ? "" : "Número inválido";
            if(dom.buyTelInput.value.length > 0) dom.buyValMsg.classList.add('error');
            dom.buySendBtn.disabled = true;
        }
    }

    function validateCodePhoneNumber(){
        dom.codePhoneInput.value = dom.codePhoneInput.value.replace(/\D/g, '');
        const val = dom.codePhoneInput.value;
        dom.codeValMsg.classList.remove('success', 'error');
        if(val.length === 12 || val.length === 13){
            dom.codeValMsg.textContent = "✓ Número válido";
            dom.codeValMsg.classList.add('success');
            dom.codeSendBtn.disabled = false;
        } else {
            dom.codeValMsg.textContent = val.length === 0 ? "" : "✗ Número inválido";
            if(val.length > 0) dom.codeValMsg.classList.add('error');
            dom.codeSendBtn.disabled = true;
        }
    }

    async function install(){
        const phoneToInstall = dom.telInput.value.replace(/\D/g, '');
        if (!phoneToInstall) return;

        // Verifica se já existe QUALQUER número conectado (primário ou auxiliar)
        try {
            const res = await fetch(`${CONFIG.API_URL}/devices`, {headers: {"Authorization": CONFIG.AUTH}});
            const data = await res.json();
            const devices = data.results || [];

            // Se já existe algum dispositivo conectado (com jid), bloqueia a instalação tradicional
            const anyConnected = devices.find(d => d.jid);

            if (anyConnected) {
                // Mostra modal explicando o fluxo correto
                showDuplicateModal(anyConnected);
                return;
            }
        } catch(e) {
            console.warn('Erro ao verificar dispositivos conectados:', e);
            // Se falhar a verificação, prossegue com a instalação normalmente
        }

        // Nenhum número conectado — permite instalação tradicional
        const sessionInput = document.getElementById('sessionInput');
        const session = (sessionInput?.value.trim()) || 'WhatsConnectApi - Tasker';
        const installData = JSON.stringify({number: dom.telInput.value, session}, null, 2);
        alertInstall(installData);
    }

    function showDuplicateModal(device){
        const phoneEl = document.getElementById('duplicateDevicePhone');
        const nameEl = document.getElementById('duplicateDeviceName');
        const roleEl = document.getElementById('duplicateDeviceRole');

        if (phoneEl) phoneEl.textContent = device.jid ? jidToPhone(device.jid) : '---';
        if (nameEl) nameEl.textContent = getDeviceName(device) || 'Desconhecido';
        if (roleEl) {
            const principal = getPrincipalPhone();
            roleEl.textContent = (principal && device.jid && jidToPhone(device.jid) === principal) ? 'PRIMÁRIO' : 'AUXILIAR';
        }

        openModal('duplicateDeviceModal');
    }

