    function sendPurchase(){
        if(!selectedPlan.name){
            dom.planErrorMsg.textContent = "Por favor, selecione um plano.";
            return;
        }
        dom.planErrorMsg.textContent = "";
        const name = dom.buyNameInput.value.trim();
        const tel  = dom.buyTelInput.value.trim();
        if(!name){ dom.planErrorMsg.textContent = "Por favor, informe seu nome."; return; }
        document.getElementById('confirmName').textContent  = name;
        document.getElementById('confirmTel').textContent   = tel;
        document.getElementById('confirmPlan').textContent  = selectedPlan.name;
        document.getElementById('confirmPrice').textContent = selectedPlan.price;
        closeModal('buyModal');
        openModal('buyConfirmModal');
    }

    function confirmBuyPurchase(){
        closeModal('buyConfirmModal');
        const details = `Nome: ${document.getElementById('confirmName')?.textContent || ''}\nPlano: ${document.getElementById('confirmPlan')?.textContent || ''}\nTelefone: ${document.getElementById('confirmTel')?.textContent || ''}\nValor: ${document.getElementById('confirmPrice')?.textContent || ''}`;
        alertSendPurchase(details);
    }

