    function confirmVipCheck(){
        closeModal('vipCheckModal');
        const isVip     = CONFIG.VIP_LOG_DATA.includes("MODO VIP");
        const isExpired = CONFIG.VIP_LOG_DATA.includes("LICENÇA EXPIRADA");
        if(isVip && !isExpired){
            openHelp();
            const toast = document.getElementById('vipToast');
            if(toast){
                toast.classList.add('show');
                setTimeout(() => toast.classList.remove('show'), 5000);
