    function openCodePhone(id){
        currentPairDeviceId = id;
        dom.codePhoneInput.value = "";
        dom.codeSendBtn.disabled = true;
        dom.codeValMsg.textContent = '';
        dom.codeValMsg.classList.remove('success', 'error');
        openModal('codePhoneModal');
    }

    function closeCodePhone(){ closeModal('codePhoneModal'); }

    async function startCodeGeneration(){
        const phoneVal = (dom.codePhoneInput.value || '').trim();
        const deviceId = currentPairDeviceId;
        if(!phoneVal || !deviceId) return;
        currentCodePhone = phoneVal;
        closeCodePhone();

        currentCodePhone = phoneVal;
        currentPairDeviceId = deviceId;

        pairingDevices.add(deviceId);

        fetchDevices();

        showEl(dom.pairLoadingMsg);
        hideEl(dom.pairCodeValue);
        hideEl(dom.pairTimerText);
        hideEl(document.getElementById('btnCopyPairCode'));
        openModal('pairCodeModal');
        await fetchPairCode(deviceId);
    }

    async function fetchPairCode(id){
        try{
            const res  = await fetch(`${CONFIG.API_URL}/app/login-with-code?phone=${currentCodePhone}`, {
                headers: { "Authorization": CONFIG.AUTH, "X-Device-Id": id }
            });
            const data = await res.json();
            if(data.results?.pair_code){
                dom.pairCodeValue.textContent    = data.results.pair_code;
                hideEl(dom.pairLoadingMsg);
                showEl(dom.pairCodeValue);
                showEl(dom.pairTimerText);

                dom.pairCodeTimer.textContent    = "30";
                showEl(document.getElementById('btnCopyPairCode'));
                startPairTimer(id, 30);

                setTimeout(() => startStatusCheck(id), 1200);
            } else {
                hideEl(dom.pairLoadingMsg);
                dom.pairCodeValue.textContent = 'Erro ao gerar código';
                showEl(dom.pairCodeValue);
            }
        } catch(e){
            console.error("Erro ao buscar código de pareamento:", e);
            hideEl(dom.pairLoadingMsg);
            dom.pairCodeValue.textContent = 'Falha na geração';
            showEl(dom.pairCodeValue);
        }
    }

    function startPairTimer(id, seconds){
        clearInterval(qrTimers["pair"]);
        let count = seconds;
        qrTimers["pair"] = setInterval(() => {
            count--;
            dom.pairCodeTimer.textContent = count;
            if(count <= 0){
                clearInterval(qrTimers["pair"]);
                showEl(dom.pairLoadingMsg);
                hideEl(dom.pairCodeValue);
                hideEl(dom.pairTimerText);
                hideEl(document.getElementById('btnCopyPairCode'));
                fetchPairCode(id);
            }
        }, 1000);
    }

    async function resetDeviceConnection(id){
        if(!id) return;
        stopAllTimers(id);
        stopNameWatch(id);
        pairingDevices.delete(id);
        connectingDevices.delete(id);
        deviceListSignature = null;
        try{
            const dev = await fetchDeviceFromList(id);
            if(dev && dev.jid){
                await fetch(`${CONFIG.API_URL}/app/logout`, {headers: {"Authorization": CONFIG.AUTH, "X-Device-Id": id}});
            }
        }catch(e){ console.warn('reset logout falhou:', e); }
        deviceListSignature = null;
        fetchDevices();
    }

    function closePairCode(){

        const deviceId = currentPairDeviceId;
        const succeeded = pairingSucceeded;
        pairingSucceeded = false;
        if (currentPairDeviceId) pairingDevices.delete(currentPairDeviceId);
        if (!succeeded && deviceId) resetDeviceConnection(deviceId);
        closeModal('pairCodeModal');
        showEl(dom.pairLoadingMsg);
        hideEl(dom.pairCodeValue);
        hideEl(dom.pairTimerText);
        hideEl(document.getElementById('btnCopyPairCode'));
        clearInterval(qrTimers["pair"]);
    }

    async function getQr(id){
        currentZoomId = id;

        pairingDevices.add(id);

        showEl(dom.qrLoadingMsg);
        hideEl(dom.qrZoomViewport);
        hideEl(dom.zoomTimerText);
        hideEl(dom.qrZoomHint);
        resetQrZoom();
        openModal('zoomModal');
        try{
            const res = await fetch(`${CONFIG.API_URL}/app/login`, {
                headers: { "Authorization": CONFIG.AUTH, "X-Device-Id": id }
            });
            const d = await res.json();
            if(d.results?.qr_link){
                dom.zoomImg.src                 = d.results.qr_link;
                hideEl(dom.qrLoadingMsg);
                showEl(dom.qrZoomViewport);
                showEl(dom.zoomTimerText);
                showEl(dom.qrZoomHint);
                dom.zoomTimer.textContent       = d.results.qr_duration;
                resetQrZoom();
                startQrTimer(id, d.results.qr_duration);

                setTimeout(() => startStatusCheck(id), 1100);
            }
        } catch(e){ console.error("Erro ao obter QR Code:", e); }
    }

    function startQrTimer(id, seconds){
        clearInterval(qrTimers[id]);
        let count = seconds;
        qrTimers[id] = setInterval(() => {
            count--;
            if(currentZoomId === id) dom.zoomTimer.textContent = count;
            if(count <= 0){ stopAllTimers(id); getQr(id); }
        }, 1000);
    }

    function closeZoom(){

        const deviceId = currentZoomId;
        const succeeded = pairingSucceeded;
        pairingSucceeded = false;
        if (currentZoomId) pairingDevices.delete(currentZoomId);
        if (!succeeded && deviceId) resetDeviceConnection(deviceId);
        closeModal('zoomModal');
        showEl(dom.qrLoadingMsg);
        hideEl(dom.qrZoomViewport);
        hideEl(dom.zoomTimerText);
        hideEl(dom.qrZoomHint);
        resetQrZoom();
        if(currentZoomId) stopAllTimers(currentZoomId);
        currentZoomId = null;
    }

    let qrScale = 1;
    const QR_MIN_SCALE = 1;
    const QR_MAX_SCALE = 3;

    function applyQrTransform(){
        if(dom.qrZoomViewport){
            dom.qrZoomViewport.style.transform = `scale(${qrScale})`;
            dom.qrZoomViewport.classList.toggle('zoomed', qrScale > QR_MIN_SCALE + 0.01);
        }
    }

    function resetQrZoom(){
        qrScale = 1;
        applyQrTransform();
    }

    function setQrScale(value){
        qrScale = Math.min(QR_MAX_SCALE, Math.max(QR_MIN_SCALE, value));
        applyQrTransform();
    }

    function setupQrPinchZoom(){
        const vp = dom.qrZoomViewport;
        if(!vp) return;
        let pointers = new Map();
        let startDist = 0;
        let startScale = 1;

        vp.addEventListener('wheel', e => {
            e.preventDefault();
            const factor = e.deltaY < 0 ? 1.12 : 0.89;
            setQrScale(qrScale * factor);
        }, {passive: false});

        vp.addEventListener('dblclick', e => {
            e.preventDefault();
            setQrScale(qrScale > QR_MIN_SCALE + 0.01 ? QR_MIN_SCALE : 2);
        });

        vp.addEventListener('pointerdown', e => {
            vp.setPointerCapture(e.pointerId);
            pointers.set(e.pointerId, {x: e.clientX, y: e.clientY});
            if(pointers.size === 2){
                const pts = [...pointers.values()];
                startDist = Math.hypot(pts[0].x - pts[1].x, pts[0].y - pts[1].y);
                startScale = qrScale;
            }
        });

        vp.addEventListener('pointermove', e => {
            if(!pointers.has(e.pointerId)) return;
            pointers.set(e.pointerId, {x: e.clientX, y: e.clientY});
            if(pointers.size === 2){
                const pts = [...pointers.values()];
                const dist = Math.hypot(pts[0].x - pts[1].x, pts[0].y - pts[1].y);
                if(startDist > 0) setQrScale(startScale * (dist / startDist));
            }
        });

        const endPointer = e => {
            pointers.delete(e.pointerId);
            if(pointers.size < 2) startDist = 0;
        };
        vp.addEventListener('pointerup', endPointer);
        vp.addEventListener('pointercancel', endPointer);
        vp.addEventListener('pointerleave', endPointer);
    }

    let wcaConnectedInterval = null;
    let wcaConnectedTimeout = null;

    function startWcaConnectedToastLoop() {
        if (wcaConnectedInterval) return;

        function runCycle() {
            const toast = document.getElementById('wcaConnectedToast');
            if (!toast) return;
            toast.classList.add('show');

            wcaConnectedTimeout = setTimeout(() => {
                toast.classList.remove('show');
            }, 5000);
        }

        runCycle();
        wcaConnectedInterval = setInterval(runCycle, 12000);
    }

    function stopWcaConnectedToastLoop() {
        if (wcaConnectedInterval) {
            clearInterval(wcaConnectedInterval);
            wcaConnectedInterval = null;
        }
        if (wcaConnectedTimeout) {
            clearTimeout(wcaConnectedTimeout);
            wcaConnectedTimeout = null;
        }
        const toast = document.getElementById('wcaConnectedToast');
        if (toast) toast.classList.remove('show');
    }

    function markServerOnline(){
        dom.createDeviceBtn.disabled = false;
        hideServerAlert();
        startWcaConnectedToastLoop();
    }

    function markServerOffline(){
        dom.createDeviceBtn.disabled = true;
        if (dom.removeAllBtn) dom.removeAllBtn.classList.add('d-none');
        showServerAlert('Api desconectada , realize a primeira instalação ou aguarde a reconexão ...');
        stopWcaConnectedToastLoop();
    }

    async function checkServerStatus(){
        try{

            let res = await fetch(`${CONFIG.API_URL}/`, {
                headers: {"Authorization": CONFIG.AUTH},
                method: 'GET'
            });

            if (res.ok) { markServerOnline(); return true; }

            res = await fetch(`${CONFIG.API_URL}/devices`, {
                headers: {"Authorization": CONFIG.AUTH}
            });

            if (res.ok) { markServerOnline(); return true; }

            if (res.status) { markServerOnline(); return true; }

            markServerOffline();
            return false;
        } catch(e){
            markServerOffline();
            return false;
        }
    }

    function showServerAlert(msg) {
        if (dom.serverAlert) {
            if (msg && dom.serverAlertText) dom.serverAlertText.textContent = msg;
            dom.serverAlert.classList.remove('d-none');
        }
    }

    function hideServerAlert() {
        if (dom.serverAlert) dom.serverAlert.classList.add('d-none');
    }

    function handleServerError(msg) {
        console.warn('[handleServerError]', msg);
        showServerAlert('Não foi possível conectar à API. Verifique se ela está ativa.');
    }

    function computeDeviceView(dev){
        const isLoggedIn = !!dev.jid;
        let deviceName = getDeviceName(dev);
        const hasName    = !!deviceName;
        const isWaiting  = pairingDevices.has(dev.id) && !isLoggedIn;
        const isSyncing  = isLoggedIn && !hasName && !devicesWithFallback.has(dev.id);
        const isFallback = isLoggedIn && !hasName && devicesWithFallback.has(dev.id);
        const effectiveOnline = (isLoggedIn && hasName) || isFallback;

        let stateKey, cardClass = 'device-card', nameToDisplay, badgeText, badgeClass;
        if (effectiveOnline) {
            stateKey = 'online'; 
            nameToDisplay = deviceName || jidToPhone(dev.jid); 
            badgeText = isFallback ? 'CONECTADO' : 'ONLINE'; 
            badgeClass = 'badge-online';
        } else if (isSyncing) {
            stateKey = 'syncing'; cardClass += ' connecting'; nameToDisplay = 'Sincronizando...'; badgeText = 'SINCRONIZANDO'; badgeClass = 'badge-pairing';
        } else if (isWaiting) {
            stateKey = 'waiting'; cardClass += ' connecting'; nameToDisplay = 'Aguardando conexão'; badgeText = 'AGUARDANDO'; badgeClass = 'badge-pairing';
        } else {
            stateKey = 'offline'; cardClass += ' offline'; nameToDisplay = 'Dispositivo'; badgeText = 'OFFLINE'; badgeClass = 'badge-offline';
        }

        const idToDisplay = (isLoggedIn && dev.jid) ? dev.jid.split('@')[0] : dev.id;
        const showButtons = !isLoggedIn && !isWaiting;

        let roleLabel = '';
        if (isLoggedIn && dev.jid) {
            const principal = getPrincipalPhone();
            roleLabel = (principal && jidToPhone(dev.jid) === principal) ? 'PRIMÁRIO' : 'AUXILIAR';
        }

        return {id: dev.id, isLoggedIn, effectiveOnline, cardClass, nameToDisplay, badgeText, badgeClass, idToDisplay, showButtons, stateKey, roleLabel};
    }

    function renderDeviceList(devices){
        const principalPhone = getPrincipalPhone();
        const views = devices
            .slice()
            .sort((a, b) => {
                const aPrincipal = principalPhone && a.jid && jidToPhone(a.jid) === principalPhone;
                const bPrincipal = principalPhone && b.jid && jidToPhone(b.jid) === principalPhone;
                if (aPrincipal && !bPrincipal) return -1;
                if (bPrincipal && !aPrincipal) return 1;
                const ta = a.created_at ? new Date(a.created_at).getTime() : 0;
                const tb = b.created_at ? new Date(b.created_at).getTime() : 0;
                if (ta !== tb) return ta - tb;
                return a.id.localeCompare(b.id);
            })
            .map(computeDeviceView);

        const signature = views.map(v => `${v.id}|${v.stateKey}|${v.nameToDisplay}|${v.idToDisplay}|${v.roleLabel}`).join('~~');
        if (signature === deviceListSignature) return;
        deviceListSignature = signature;

        if(views.length === 0){
            dom.noDeviceMessage.textContent = 'Nenhum dispositivo cadastrado.';
            dom.noDeviceMessage.classList.remove('d-none');
            if (dom.removeAllBtn) dom.removeAllBtn.classList.add('d-none');
        } else {
            dom.noDeviceMessage.classList.add('d-none');
            if (dom.removeAllBtn) dom.removeAllBtn.classList.remove('d-none');
        }

        dom.deviceList.innerHTML = '';

        views.forEach((v, index) => {
            const frag = cloneTemplate('deviceCardTemplate');
            const card = frag.querySelector('.device-card');
            card.className = v.cardClass;
            card.dataset.delay = Math.min(index + 1, 20);

            const nameEl = card.querySelector('.device-name');
            if(nameEl) nameEl.textContent = v.nameToDisplay;

            const badgeEl = card.querySelector('.badge');
            if(badgeEl){
                badgeEl.classList.add(v.badgeClass);
                badgeEl.textContent = v.badgeText;
            }

            const idEl = card.querySelector('.device-id');
            if(idEl) idEl.textContent = v.idToDisplay;

            const roleEl = card.querySelector('.role-badge');
            if(roleEl){
                if(v.roleLabel){
                    roleEl.textContent = v.roleLabel;
                    roleEl.classList.add(v.roleLabel === 'PRIMÁRIO' ? 'role-primary' : 'role-secondary');
                    roleEl.classList.remove('d-none');
                } else {
                    roleEl.classList.add('d-none');
                }
            }

            const delBtn = card.querySelector('.btn-delete');
            if(delBtn) delBtn.onclick = () => askDeleteDevice(v.id);

            const buttonsWrap = card.querySelector('.device-buttons');
            if(buttonsWrap){
                if(v.showButtons){
                    buttonsWrap.classList.remove('d-none');
                    const codeBtn = buttonsWrap.querySelector('[data-code]');
                    const qrBtn = buttonsWrap.querySelector('[data-qr]');
                    if(codeBtn) codeBtn.onclick = () => openCodePhone(v.id);
                    if(qrBtn) qrBtn.onclick = () => getQr(v.id);
                } else {
                    buttonsWrap.classList.add('d-none');
                }
            }

            dom.deviceList.appendChild(card);
        });
    }

    async function fetchDevices(){
        try{
            const res     = await fetch(`${CONFIG.API_URL}/devices`, {headers: {"Authorization": CONFIG.AUTH}});
            const data    = await res.json();
            const devices = data.results || [];

            hideServerAlert();
            renderDeviceList(devices);

            const loggedInIds = new Set();
            devices.forEach(d => {
                if (d.jid) {
                    loggedInIds.add(d.id);
                    pairingDevices.delete(d.id);
                    if (getDeviceName(d)) {
                        syncDeviceToFile(d);
                        stopNameWatch(d.id);
                    } else {
                        // Verifica imediatamente se já tem nome antes de iniciar polling
                        fetchDeviceFromList(d.id).then(latestDev => {
                            if (latestDev && getDeviceName(latestDev)) {
                                syncDeviceToFile(latestDev);
                                deviceListSignature = null;
                                fetchDevices();
                            } else {
                                startNameWatch(d.id);
                            }
                        }).catch(() => startNameWatch(d.id));
                    }
                }
            });

            Object.keys(nameTimers).forEach(id => { if (!loggedInIds.has(id)) stopNameWatch(id); });

            return devices.filter(d => d.jid).every(d => getDeviceName(d));
        } catch(e){
            handleServerError(e);
            return true;
        }
    }

    async function refreshAndVerifyNames(){
        deviceListSignature = null;
        await fetchDevices();

        // Verificação adicional: para cada dispositivo logado sem nome, inicia polling
        try{
            const res = await fetch(`${CONFIG.API_URL}/devices`, {headers: {"Authorization": CONFIG.AUTH}});
            const data = await res.json();
            const devices = data.results || [];

            devices.forEach(d => {
                if (d.jid && !getDeviceName(d) && !devicesWithFallback.has(d.id)) {
                    // Dispositivo online mas sem nome - inicia polling (1s por até 20s)
                    stopNameWatch(d.id);
                    startNameWatch(d.id);
                }
            });
        } catch(e) {
            console.warn('refreshAndVerifyNames error:', e);
        }
    }

    async function fetchDeviceFromList(id){
        const res  = await fetch(`${CONFIG.API_URL}/devices`, {
            headers: {
                "Authorization": CONFIG.AUTH,
                "X-Device-Id": id
            }
        });
        const data = await res.json();
        const devices = data.results || [];
        return devices.find(d => d.id === id) || null;
    }

    function startStatusCheck(id){
        clearInterval(checkTimers[id]);
        checkTimers[id] = setInterval(async () => {
            try{
                const dev = await fetchDeviceFromList(id);
                const isLoggedIn = !!dev?.jid;

                if (isLoggedIn) {
                    clearInterval(checkTimers[id]);
                    pairingDevices.delete(id);
                    const pairModalOpen = document.getElementById('pairCodeModal')?.classList.contains('open');
                    const qrModalOpen = document.getElementById('zoomModal')?.classList.contains('open');
                    if (pairModalOpen && currentPairDeviceId === id){ pairingSucceeded = true; closePairCode(); }
                    if (qrModalOpen && currentZoomId === id){ pairingSucceeded = true; closeZoom(); }
                    fetchDevices();
                    return;
                }

                fetchDevices();
            } catch(e){ }
        }, 1600);
    }

    function startNameWatch(id){
        if (nameTimers[id]) return;
        connectingDevices.add(id);
        nameWatchCounters[id] = 0;

        // Polling a cada 1 segundo por até 20 segundos
        nameTimers[id] = setInterval(async () => {
            try{
                nameWatchCounters[id] = (nameWatchCounters[id] || 0) + 1;
                const dev = await fetchDeviceFromList(id);

                // Se não tem jid, dispositivo desconectou
                if (!dev || !dev.jid) { 
                    stopNameWatch(id); 
                    fetchDevices(); 
                    return; 
                }

                // Dispositivo está conectado (tem jid)
                if (getDeviceName(dev)) {
                    // ✅ Obteve o nome - sincroniza normalmente
                    syncDeviceToFile(dev);
                    devicesWithFallback.delete(id);
                    stopNameWatch(id);
                    deviceListSignature = null;
                    fetchDevices();
                } else if (nameWatchCounters[id] >= NAME_WATCH_MAX_SECONDS) {
                    // ⚠️ Passou 20 segundos sem obter nome
                    // Mas está conectado (tem jid) - armazena com número como fallback
                    const phoneFallback = jidToPhone(dev.jid);
                    dev.display_name = phoneFallback;
                    devicesWithFallback.add(id);
                    syncDeviceToFile(dev);
                    stopNameWatch(id);
                    deviceListSignature = null;
                    fetchDevices();
                    showToast({
                        title: 'Nome indisponível',
                        message: `Dispositivo ${phoneFallback} conectado, mas não foi possível obter o nome após ${NAME_WATCH_MAX_SECONDS}s`,
                        type: 'warning',
                        duration: 5000
                    });
                }
                // Se ainda está tentando (menos de 20s), continua o polling
            } catch(e){ }
        }, NAME_WATCH_INTERVAL);
    }

    function stopNameWatch(id){
        if (nameTimers[id]) { 
            clearInterval(nameTimers[id]); 
            delete nameTimers[id];
            delete nameWatchCounters[id];
        }
        connectingDevices.delete(id);
    }

    // Verificação global: roda a cada 10s para tentar obter nomes que ainda estão como "Sincronizando"
    function startGlobalNameCheck(){
        if (globalNameCheckInterval) return;
        globalNameCheckInterval = setInterval(async () => {
            try {
                const res = await fetch(`${CONFIG.API_URL}/devices`, {headers: {"Authorization": CONFIG.AUTH}});
                const data = await res.json();
                const devices = data.results || [];
                let changed = false;

                for (const dev of devices) {
                    if (!dev.jid) continue;

                    // Se já tem nome, sincroniza e sai
                    if (getDeviceName(dev)) {
                        syncDeviceToFile(dev);
                        devicesWithFallback.delete(dev.id);
                        continue;
                    }

                    // Se está aguardando polling, não mexe
                    if (nameTimers[dev.id]) continue;

                    // Se é um fallback ativo, tenta obter o nome real novamente
                    // Faz uma requisição individual para esse dispositivo
                    try {
                        const latestDev = await fetchDeviceFromList(dev.id);
                        if (latestDev && latestDev.jid && getDeviceName(latestDev)) {
                            // Nome apareceu! Sai do fallback
                            devicesWithFallback.delete(dev.id);
                            syncDeviceToFile(latestDev);
                            changed = true;
                        }
                    } catch(e) { /* continua */ }
                }

                if (changed) {
                    deviceListSignature = null;
                    fetchDevices();
                }
            } catch(e) { /* silencioso */ }
        }, 10000);
    }

    function stopAllTimers(id){
        if(id){
            clearInterval(qrTimers[id]);
            clearInterval(checkTimers[id]);
        }
        clearInterval(qrTimers["pair"]);
    }

    function askDeleteDevice(id){
        deleteDeviceTargetId = id;
        openModal('confirmModal');
    }

    async function doDeleteDevice(){
        if(!deleteDeviceTargetId) return;
        const id = deleteDeviceTargetId;
        stopAllTimers(id);
        stopNameWatch(id);
        pairingDevices.delete(id);
        devicesWithFallback.delete(id);
        deviceListSignature = null;
        let jid = '';
        try{
            const dev = await fetchDeviceFromList(id);
            jid = dev && dev.jid ? dev.jid : '';
        }catch(e){ /* segue mesmo sem jid */ }
        try{
            await fetch(`${CONFIG.API_URL}/app/logout`, {headers: {"Authorization": CONFIG.AUTH, "X-Device-Id": id}});
        }catch(e){ console.warn('logout falhou:', e); }
        try{
            await fetch(`${CONFIG.API_URL}/devices/${id}`, {method: 'DELETE', headers: {"Authorization": CONFIG.AUTH, "X-Device-Id": id}});
        }catch(e){ console.warn('delete falhou:', e); }
        if(jid) removeDeviceFromFile(jid);
        closeModal('confirmModal');
        deleteDeviceTargetId = null;
        fetchDevices();
    }

    function askDeleteAllDevices(){
        openModal('confirmAllModal');
    }

    async function doDeleteAllDevices(){
        const btn = document.getElementById('btnConfirmDeleteAll');
        if (btn) btn.disabled = true;
        try{
            const res = await fetch(`${CONFIG.API_URL}/devices`, {headers: {"Authorization": CONFIG.AUTH}});
            const data = await res.json();
            const devices = data.results || [];
            for (const dev of devices){
                const id = dev.id;
                stopAllTimers(id);
                stopNameWatch(id);
                pairingDevices.delete(id);
                try{ await fetch(`${CONFIG.API_URL}/app/logout`, {headers: {"Authorization": CONFIG.AUTH, "X-Device-Id": id}}); }catch(e){ console.warn('logout falhou:', e); }
                try{ await fetch(`${CONFIG.API_URL}/devices/${id}`, {method: 'DELETE', headers: {"Authorization": CONFIG.AUTH, "X-Device-Id": id}}); }catch(e){ console.warn('delete falhou:', e); }
            }
            deviceListSignature = null;
            clearDevicesFile();
            showToast({title: 'Dispositivos removidos', message: 'Todos os dispositivos foram removidos.', type: 'success'});
        }catch(e){
            console.error('doDeleteAllDevices:', e);
            showToast({title: 'Erro', message: 'Falha ao remover os dispositivos.', type: 'error'});
        }finally{
            if (btn) btn.disabled = false;
            closeModal('confirmAllModal');
            fetchDevices();
        }
    }

