function alertMessenger() {


    ///alert('WhatsApp Messenger selecionado');
    tk.setLocal("bottom","wa-message");
    tk.destroyScene('004-WHATSAPP_SELETOR [wca]');
}

function alertBusiness() {


    ///alert('WhatsApp Business selecionado');
     tk.setLocal("bottom","wa-business");
     tk.destroyScene('004-WHATSAPP_SELETOR [wca]');

}

document.getElementById('btnMessenger').addEventListener('click', alertMessenger);
document.getElementById('btnBusiness').addEventListener('click', alertBusiness);

document.addEventListener('DOMContentLoaded', function() {
    document.body.style.opacity = '0';
    setTimeout(() => {
        document.body.style.transition = 'opacity 0.1s ease';
        document.body.style.opacity = '1';
    }, 100);
});

