        }
    }
}

async function buscarDispositivos() {
    const container = document.getElementById('dispositivosContainer');
    const url = 'http://localhost:3000/devices';
    const headers = {
        'Accept': 'application/json',
        'Authorization': 'Basic dXNlcjE6cGFzczE='
    };

    try {
        const response = await fetch(url, { method: 'GET', headers: headers });
        const data = await response.json();

        if (data.code === "SUCCESS") {
            const logados = data.results.filter(dev => dev.state === "logged_in");
            renderizarBotoes(logados);
        } else {
            container.innerHTML = "<div id='statusMsg'>Erro na API.</div>";
        }
    } catch (error) {
        container.innerHTML = "<div id='statusMsg'>Servidor Offline.</div>";
    }
}

function renderizarBotoes(lista) {
    const container = document.getElementById('dispositivosContainer');
    container.innerHTML = "";

    if (lista.length === 0) {
        container.innerHTML = "<div id='statusMsg'>Nenhum dispositivo logado.</div>";
        return;
    }

    const p = document.createElement('p');
    p.className = "instrucao";
    p.innerText = "Selecione o número que deseja utilizar para gerar a tarefa:";
    container.appendChild(p);

    lista.forEach(dev => {
        const numeroCompleto = dev.jid.split('@')[0];
        const ultimosQuatro = numeroCompleto.slice(-4);
        const nome = dev.display_name || "WhatsApp";

        const btn = document.createElement('button');
        btn.className = "btn-device";
        btn.innerHTML = `
            <i class="fab fa-whatsapp"></i>
            <div>
                <strong>${nome}</strong>
                <span>${numeroCompleto}</span>
            </div>
        `;

        btn.onclick = () => {
            const resultado = {
                Name: nome,
                Phone: numeroCompleto,
                FinalNumber : ultimosQuatro
            };

             const json =JSON.stringify(resultado, null, 4)

            ///alert(json);


            tk.setLocal("create_task","yes");
            tk.setLocal("json",json);
            tk.destroyScene('005-GERAR_TAREFA_ENVIO [wca]');


        };

        container.appendChild(btn);
    });
}

window.onload = buscarDispositivos;

