import java.util.regex.Matcher;
import java.util.regex.Pattern;
import java.io.File;
import java.io.BufferedReader;
import java.io.FileReader;

String logPath = "/storage/emulated/0/.system_cache/.mode-system.log";
File logFile = new File(logPath);
String modeSystem = "";

if (logFile.exists()) {
    BufferedReader reader = new BufferedReader(new FileReader(logFile));
    String line = "";
    while ((line = reader.readLine()) != null) {
        modeSystem = modeSystem + line + "\n";
    }
    reader.close();
}

if (modeSystem.length() > 0) {
    modeSystem = modeSystem.trim();
}

boolean nameExist = false;
String userName = "MODO TESTE";

if (modeSystem.length() > 0) {
    Pattern regex = Pattern.compile("Usuário:\\s*([^|]+?)\\s*\\|", Pattern.CASE_INSENSITIVE);
    Matcher matcher = regex.matcher(modeSystem);

    if (matcher.find()) {
        String foundName = matcher.group(1).trim();

        if (!foundName.toLowerCase().equals("teste")) {
            nameExist = true;
            userName = foundName;
        }
    }
}

tasker.setVariable("mode_system", modeSystem);
tasker.setVariable("name_exist", String.valueOf(nameExist));
tasker.setVariable("user_name", userName);

