:root {
    --bg-body: #000000;
    --bg-card: #06222A;
    --bg-elevated: #0a2c35;
    --primary: #0F9DCB;
    --accent: #B5FB2A;
    --border: #0F507A;
    --border-soft: rgba(15, 80, 122, 0.5);
    --text-main: #C6E3DC;
    --text-dim: #8494A4;
    --gold: #FFD700;
    --success: #B5FB2A;
    --warning: #FFD700;
    --danger: #ff4d4d;
    --header-h: 11rem;
    --tabs-h: 5.6rem;
    --quicknav-h: 4.8rem;
    --footer-h: 5.5rem;
}

html {
    font-size: 62.5%;
}

* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
    font-family: 'Inter', sans-serif;
    -webkit-tap-highlight-color: transparent;
}

body {
    background-color: var(--bg-body);
    color: var(--text-main);
    line-height: 1.6;
    min-height: 100vh;
    font-size: 1.6rem;
    padding-top: calc(var(--header-h) + var(--tabs-h) + var(--quicknav-h));
    padding-bottom: var(--footer-h);
    overflow-x: hidden;
}

.header {
    background: linear-gradient(135deg, var(--primary) 0%, #0a5a7a 100%);
    padding: 1rem 1rem;
    text-align: center;
    box-shadow: 0 1rem 3rem rgba(0,0,0,0.5);
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: var(--header-h);
    z-index: 1000;
    display: flex;
    align-items: center;
}

.header-wrapper {
    max-width: 120rem;
    width: 100%;
    margin: 0 auto;
    background: var(--bg-card);
    border-radius: 1.8rem;
    padding: 1.5rem;
    border: 0.1rem solid var(--border);
}

.header-content {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 1.5rem;
    flex-wrap: nowrap;
}

.header-content > div {
    flex-grow: 1;
    min-width: 0;
}

.header-video {
    width: 4.5rem;
    height: 4.5rem;
    border-radius: 50%;
    object-fit: cover;
    border: 0.2rem solid var(--accent);
    flex-shrink: 0;
}

.header h1 {
    font-size: 2rem;
    margin-bottom: 0.2rem;
    color: var(--accent);
    letter-spacing: 0.05rem;
}

.header p {
    font-size: 1.3rem;
    opacity: 0.9;
    color: var(--text-main);
}

.tabs {
    position: fixed;
    top: var(--header-h);
    left: 0;
    width: 100%;
    height: var(--tabs-h);
    background: var(--bg-card);
    border-bottom: 0.1rem solid var(--border);
    z-index: 999;
    display: flex;
    align-items: center;
    box-shadow: 0 0.5rem 1.5rem rgba(0,0,0,0.4);
}

.tabs-track {
    display: flex;
    align-items: center;
    width: 100%;
    max-width: 120rem;
    margin: 0 auto;
    position: relative;
    padding: 0 0.5rem;
    overflow-x: auto;
    scrollbar-width: none;
}

.tabs-track::-webkit-scrollbar {
    display: none;
}

.tab-btn {
    flex: 1 1 auto;
    min-width: 8rem;
    background: transparent;
    border: none;
    color: var(--text-dim);
    font-family: 'Inter', sans-serif;
    font-size: 1.35rem;
    font-weight: 500;
    padding: 0.9rem 0.5rem;
    cursor: pointer;
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 0.3rem;
    transition: color 0.25s ease;
    position: relative;
    z-index: 2;
    white-space: nowrap;
}

.tab-btn i {
    font-size: 1.6rem;
    transition: transform 0.25s ease;
}

.tab-btn.active {
    color: var(--accent);
}

.tab-btn.active i {
    transform: scale(1.1);
}

.tab-indicator {
    position: absolute;
    bottom: 0;
    left: 0;
    height: 0.3rem;
    background: linear-gradient(90deg, var(--primary), var(--accent));
    border-radius: 0.2rem 0.2rem 0 0;
    transition: transform 0.3s cubic-bezier(0.4, 0, 0.2, 1), width 0.3s cubic-bezier(0.4, 0, 0.2, 1);
    z-index: 1;
}

.quick-nav {
    position: fixed;
    top: calc(var(--header-h) + var(--tabs-h));
    left: 0;
    width: 100%;
    height: var(--quicknav-h);
    background: var(--bg-elevated);
    border-bottom: 0.1rem solid var(--border-soft);
    z-index: 998;
    display: flex;
    align-items: center;
    gap: 0.6rem;
    padding: 0 1rem;
    overflow-x: auto;
    scrollbar-width: none;
    box-shadow: 0 0.5rem 1.5rem rgba(0,0,0,0.3);
}

.quick-nav::-webkit-scrollbar {
    display: none;
}

.quick-nav-chip {
    flex: 0 0 auto;
    display: inline-flex;
    align-items: center;
    gap: 0.5rem;
    padding: 0.55rem 1.1rem;
    background: var(--bg-card);
    border: 0.1rem solid var(--border);
    border-radius: 99.9rem;
    color: var(--text-main);
    text-decoration: none;
    font-size: 1.3rem;
    font-weight: 500;
    white-space: nowrap;
    transition: all 0.25s ease;
}

.quick-nav-chip i {
    color: var(--primary);
    font-size: 1.2rem;
}

.quick-nav-chip:hover,
.quick-nav-chip:active {
    background: rgba(15, 157, 203, 0.15);
    border-color: var(--primary);
    color: var(--accent);
}

.quick-nav-chip:hover i,
.quick-nav-chip:active i {
    color: var(--accent);
}

.tab-panels {
    min-height: 50vh;
}

.tab-panel {
    display: none;
    animation: fadeInPanel 0.3s ease;
    padding: 1.5rem 1rem;
    max-width: 110rem;
    margin: 0 auto;
}

.tab-panel.active {
    display: block;
}

@keyframes fadeInPanel {
    from { opacity: 0; transform: translateY(0.5rem); }
    to { opacity: 1; transform: translateY(0); }
}

.section {
    background: var(--bg-card);
    border-radius: 1.5rem;
    padding: 2rem;
    margin-bottom: 1.5rem;
    box-shadow: 0 1rem 3rem rgba(0,0,0,0.6);
    border: 0.1rem solid var(--border);
    transition: border-color 0.2s ease;
    scroll-margin-top: calc(var(--header-h) + var(--tabs-h) + var(--quicknav-h) + 1rem);
}

.section:hover {
    border-color: var(--primary);
}

.section-header {
    display: flex;
    align-items: center;
    gap: 1rem;
    margin-bottom: 1.2rem;
    padding-bottom: 0.8rem;
    border-bottom: 0.15rem solid var(--border);
}

.section-header i {
    font-size: 1.8rem;
    color: var(--primary);
}

.section-header h2 {
    font-size: 1.7rem;
    color: var(--accent);
    font-weight: 600;
}

.section-content {
    color: var(--text-main);
    font-size: 1.45rem;
    overflow-wrap: break-word;
}

.section-content p {
    margin-bottom: 1rem;
    line-height: 1.8;
}

.section-content ul {
    list-style: none;
    margin-left: 1rem;
}

.section-content ul li {
    margin-bottom: 0.8rem;
    padding-left: 1.5rem;
    position: relative;
}

.section-content ul li::before {
    content: "▸";
    position: absolute;
    left: 0;
    color: var(--accent);
    font-weight: bold;
}

.section-content strong,
.section-content b {
    color: var(--accent);
    font-weight: 600;
}

.sub-heading {
    color: var(--accent);
    margin-top: 1.5rem;
    margin-bottom: 1rem;
    font-weight: 600;
    font-size: 1.55rem;
    display: flex;
    align-items: center;
    gap: 0.6rem;
}

.price-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(20rem, 1fr));
    gap: 1.5rem;
    margin-top: 1.5rem;
}

.price-card {
    background: rgba(0, 0, 0, 0.4);
    padding: 1.5rem;
    border-radius: 1.5rem;
    text-align: center;
    border: 0.2rem solid var(--border);
    transition: all 0.3s ease;
    position: relative;
    overflow: hidden;
}

.price-card::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    height: 0.4rem;
    background: linear-gradient(90deg, var(--primary), var(--accent));
    transform: scaleX(0);
    transition: transform 0.3s ease;
}

.price-card:hover {
    transform: scale(1.05);
    border-color: var(--primary);
    box-shadow: 0 1.2rem 3.5rem rgba(15, 157, 203, 0.4);
}

.price-card:hover::before {
    transform: scaleX(1);
}

.price-card h3 {
    color: var(--primary);
    margin-bottom: 1rem;
    font-size: 1.7rem;
    font-weight: 600;
}

.price-card .price {
    font-size: 2.6rem;
    font-weight: bold;
    color: var(--accent);
    margin-bottom: 0.5rem;
}

.price-card p {
    color: var(--text-dim);
}

.modal {
    display: none;
    position: fixed;
    z-index: 9999;
    left: 0;
    top: 0;
    width: 100%;
    height: 100%;
    background-color: rgba(0, 0, 0, 0.9);
    animation: fadeIn 0.3s ease;
}

.modal.show {
    display: flex;
    align-items: center;
    justify-content: center;
}

.modal-content {
    background: var(--bg-card);
    border-radius: 1.8rem;
    border: 0.1rem solid var(--border);
    padding: 2rem;
    max-width: 90rem;
    width: 90vw;
    max-height: 85vh;
    overflow-y: auto;
    position: relative;
    box-shadow: 0 2rem 6rem rgba(0,0,0,0.8);
}

.modal-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 2rem;
    padding-bottom: 1rem;
    border-bottom: 0.2rem solid var(--border);
}

.modal-header h2 {
    color: var(--accent);
    font-size: 2rem;
    display: flex;
    align-items: center;
    gap: 0.5rem;
}

.modal-close {
    background: transparent;
    border: none;
    color: var(--text-main);
    font-size: 3rem;
    cursor: pointer;
    width: 4rem;
    height: 4rem;
    display: flex;
    align-items: center;
    justify-content: center;
    border-radius: 50%;
    transition: all 0.3s ease;
}

.modal-close:hover {
    background: var(--danger);
    color: white;
    transform: rotate(90deg);
}

.video-thumbnails {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(20rem, 1fr));
    gap: 1.2rem;
}

.video-thumb {
    background: rgba(0, 0, 0, 0.4);
    border-radius: 1.2rem;
    overflow: hidden;
    border: 0.2rem solid var(--border);
    cursor: pointer;
    transition: all 0.3s ease;
}

.video-thumb:hover {
    transform: translateY(-0.5rem);
    border-color: var(--primary);
    box-shadow: 0 0.8rem 2.5rem rgba(15, 157, 203, 0.4);
}

.video-thumb-image {
    position: relative;
    width: 100%;
    padding-top: 56.25%;
    background: linear-gradient(135deg, rgba(15, 157, 203, 0.3), rgba(181, 251, 42, 0.2));
    overflow: hidden;
}

.video-thumb-image img {
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    object-fit: contain;
}

.video-thumb-play {
    position: absolute;
    top: 50%;
    left: 50%;
    transform: translate(-50%, -50%);
    width: 4.5rem;
    height: 4.5rem;
    background: rgba(0, 0, 0, 0.8);
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    color: var(--accent);
    font-size: 1.8rem;
}

.video-thumb-title {
    padding: 0.8rem;
    color: var(--text-main);
    font-size: 1.4rem;
    font-weight: 600;
    text-align: center;
}

.btn-open-videos {
    display: inline-flex;
    align-items: center;
    gap: 0.5rem;
    background: linear-gradient(135deg, var(--primary), var(--accent));
    color: #000;
    padding: 0.8rem 1.5rem;
    border: none;
    border-radius: 1rem;
    font-size: 1.5rem;
    font-weight: 600;
    cursor: pointer;
    transition: all 0.3s ease;
    margin-top: 1rem;
}

.btn-open-videos:hover {
    transform: translateY(-0.2rem);
    box-shadow: 0 0.8rem 2.5rem rgba(15, 157, 203, 0.5);
}

.example-box {
    background: rgba(0, 0, 0, 0.6);
    padding: 1.5rem;
    border-radius: 1.2rem;
    margin: 1rem 0;
    border-left: 0.4rem solid var(--primary);
    font-family: 'Courier New', monospace;
}

.example-box.correct {
    border-left-color: var(--success);
    background: rgba(181, 251, 42, 0.05);
}

.example-box.incorrect {
    border-left-color: var(--danger);
    background: rgba(255, 77, 77, 0.05);
}

.example-box h4 {
    color: var(--primary);
    margin-bottom: 0.8rem;
    font-family: 'Inter', sans-serif;
    font-weight: 600;
    display: flex;
    align-items: center;
    gap: 0.5rem;
}

.example-box.correct h4 {
    color: var(--success);
}

.example-box.incorrect h4 {
    color: var(--danger);
}

.example-box code {
    color: var(--text-main);
    font-size: 1.5rem;
    display: block;
    margin: 0.3rem 0;
}

.alert {
    padding: 1.2rem;
    border-radius: 1.2rem;
    margin: 1.5rem 0;
    border-left: 0.4rem solid;
    display: flex;
    align-items: start;
    gap: 1rem;
}

.alert i {
    font-size: 1.8rem;
    margin-top: 0.2rem;
}

.alert.warning {
    background: rgba(255, 215, 0, 0.08);
    border-left-color: var(--warning);
    color: var(--gold);
}

.alert.info {
    background: rgba(15, 157, 203, 0.08);
    border-left-color: var(--primary);
    color: var(--primary);
}

.alert strong {
    color: var(--accent);
}

.scroll-top {
    position: fixed;
    bottom: calc(var(--footer-h) + 1.5rem);
    right: 2rem;
    width: 4.5rem;
    height: 4.5rem;
    background: linear-gradient(135deg, var(--primary), var(--accent));
    color: #000;
    border: none;
    border-radius: 50%;
    cursor: pointer;
    display: none;
    align-items: center;
    justify-content: center;
    font-size: 1.8rem;
    box-shadow: 0 0.8rem 2.5rem rgba(15, 157, 203, 0.5);
    transition: all 0.3s ease;
    z-index: 950;
}

.scroll-top:hover {
    transform: translateY(-0.5rem);
    box-shadow: 0 1.2rem 3.5rem rgba(15, 157, 203, 0.7);
}

.scroll-top.show {
    display: flex;
}

.main-footer {
    position: fixed;
    bottom: 0;
    left: 0;
    width: 100%;
    height: var(--footer-h);
    background: var(--bg-card);
    display: flex;
    align-items: center;
    justify-content: center;
    border-top: 0.1rem solid var(--border);
    z-index: 900;
    box-shadow: 0 -0.5rem 2rem rgba(0, 0, 0, 0.4);
    font-size: 1.4rem;
    color: var(--text-dim);
}

.dev-name {
    color: var(--accent);
    font-weight: 600;
}

@keyframes fadeIn {
    from { opacity: 0; transform: translateY(2rem); }
    to { opacity: 1; transform: translateY(0); }
}

.tasker-subtitle {
    font-size: 1.9rem;
    color: var(--primary);
    margin-top: 2.5rem;
    margin-bottom: 1.5rem;
    padding-bottom: 0.5rem;
    border-bottom: 0.2rem solid var(--border);
    display: flex;
    align-items: center;
    gap: 0.8rem;
}

.receiver-list {
    background: var(--bg-card);
    border-radius: 1.5rem;
    padding: 2rem;
    border: 0.1rem solid var(--border);
    box-shadow: 0 1rem 3rem rgba(0, 0, 0, 0.6);
    margin-bottom: 1.5rem;
}

.receiver-section-title {
    font-size: 1.45rem;
    color: var(--accent);
    margin-top: 2rem;
    margin-bottom: 0.8rem;
    font-weight: 600;
    letter-spacing: 0.03rem;
    scroll-margin-top: calc(var(--header-h) + var(--tabs-h) + var(--quicknav-h) + 2rem);
}

.receiver-block {
    background: var(--bg-card);
    border-radius: 1.2rem;
    padding: 1.5rem;
    margin-bottom: 1.2rem;
    border: 0.1rem solid var(--border);
    box-shadow: 0 0.5rem 1.5rem rgba(0, 0, 0, 0.4);
    scroll-margin-top: calc(var(--header-h) + var(--tabs-h) + var(--quicknav-h) + 2rem);
}

.receiver-block:hover {
    border-color: var(--primary);
}

.receiver-block-title {
    font-size: 1.4rem;
    color: var(--accent);
    margin-bottom: 1rem;
    font-weight: 600;
    letter-spacing: 0.03rem;
    padding-bottom: 0.5rem;
    border-bottom: 0.1rem solid var(--border-soft);
}

.receiver-intro {
    color: var(--text-dim);
    margin-bottom: 1.5rem;
    font-size: 1.4rem;
}

.tasker-item {
    background: var(--bg-elevated);
    border-radius: 1.2rem;
    padding: 1.5rem;
    margin-bottom: 1rem;
    border: 0.1rem solid var(--border);
    transition: all 0.3s ease;
}

.tasker-item:hover {
    border-color: var(--primary);
}

.tasker-item h4 {
    color: var(--accent);
    margin-bottom: 0.5rem;
    font-size: 1.6rem;
    font-family: 'JetBrains Mono', monospace;
}

.tasker-item p {
    margin-bottom: 0;
    color: var(--text-dim);
    font-size: 1.45rem;
}

.tasker-list {
    margin-top: 0;
}

.variables-list {
    margin-top: 1rem;
}

.variables-list dt {
    font-family: 'Courier New', monospace;
    font-weight: bold;
    color: var(--accent);
    margin-top: 0.8rem;
    background-color: rgba(0,0,0,0.3);
    padding: 0.3rem 0.6rem;
    border-radius: 0.6rem;
    display: inline-block;
    font-size: 1.35rem;
}

.variables-list dd {
    margin-left: 0.6rem;
    padding: 0.4rem 0 0.4rem 1rem;
    border-left: 0.2rem solid var(--border);
    color: var(--text-dim);
    font-size: 1.35rem;
}

.variables-list pre {
    background-color: #000;
    padding: 0.6rem;
    border-radius: 0.6rem;
    border: 0.1rem solid var(--border);
    color: #fff;
    white-space: pre-wrap;
    word-break: break-all;
    margin-top: 0.4rem;
    font-size: 1.3rem;
}

.variables-details {
    margin-top: 1rem;
    background: rgba(0, 0, 0, 0.3);
    border-radius: 1rem;
    border: 0.1rem solid var(--border);
}

.variables-details summary {
    padding: 0.7rem 1.1rem;
    cursor: pointer;
    list-style: none;
    display: flex;
    align-items: center;
    justify-content: space-between;
    font-weight: 600;
    color: var(--primary);
    user-select: none;
    transition: background 0.3s ease;
    font-size: 1.4rem;
}

.variables-details summary:hover {
    background: rgba(15, 157, 203, 0.1);
}

.variables-details summary::-webkit-details-marker {
    display: none;
}

.variables-details summary::after {
    content: '▼';
    color: var(--accent);
    transition: transform 0.3s ease;
}

.variables-details[open] > summary::after {
    transform: rotate(180deg);
}

.variables-details .variables-list {
    padding: 0 1.1rem 1.1rem 1.1rem;
    border-top: 0.1rem solid var(--border);
    margin-top: 0.7rem;
}

.credits-modal-content.modal-content {
    max-width: 56rem;
    width: 90vw;
    padding: 0;
    background: transparent;
    border: none;
    box-shadow: none;
}

.novidades-content {
    background: var(--bg-card);
    border-radius: 1rem;
    padding: 1.2rem;
    border: 0.1rem solid var(--border-soft);
    max-height: 40rem;
    overflow-y: scroll;
    -webkit-overflow-scrolling: touch;
    overscroll-behavior: contain;
    touch-action: pan-y;
    margin-bottom: 1rem;
    position: relative;
    scrollbar-width: thin;
    scrollbar-color: var(--primary) transparent;
}

.novidades-content::-webkit-scrollbar {
    width: 0.8rem;
}

.novidades-content::-webkit-scrollbar-track {
    background: rgba(15, 157, 203, 0.05);
    border-radius: 0.4rem;
}

.novidades-content::-webkit-scrollbar-thumb {
    background: linear-gradient(180deg, var(--primary), var(--accent));
    border-radius: 0.4rem;
    border: 0.15rem solid var(--bg-card);
}

.novidades-content::-webkit-scrollbar-thumb:hover {
    background: linear-gradient(180deg, var(--accent), var(--primary));
}

.novidades-text {
    color: var(--text-main);
    font-family: 'JetBrains Mono', monospace;
    font-size: 1.25rem;
    line-height: 1.5;
    white-space: pre-wrap;
    word-wrap: break-word;
    margin: 0;
    padding: 0;
}

.credits-box-inline,
.credits-box {
    width: 100%;
    background: var(--bg-card);
    border: 0.1rem solid var(--primary);
    border-radius: 0.6rem;
    overflow: hidden;
    box-shadow:
        0 0 0 0.1rem rgba(15,157,203,0.08),
        0 0 4rem rgba(15,157,203,0.12),
        inset 0 0 4rem rgba(15,157,203,0.03);
    position: relative;
}

.credits-box::before {
    content: '// AGRADECIMENTOS';
    position: absolute;
    top: -1.1rem; left: 2rem;
    background: var(--bg-card);
    padding: 0 1rem;
    font-family: 'JetBrains Mono', monospace;
    font-size: 1rem;
    letter-spacing: 0.25rem;
    color: var(--primary);
    text-transform: uppercase;
}

.credits-list {
    padding: 2.8rem 3.2rem 3.2rem;
    display: flex;
    flex-direction: column;
    gap: 2.2rem;
}

.credits-person {
    display: flex;
    align-items: flex-start;
    gap: 1.6rem;
}

.credits-person .num {
    font-family: 'JetBrains Mono', monospace;
    font-size: 1.1rem;
    color: var(--border);
    width: 2rem;
    text-align: right;
    padding-top: 0.2rem;
    flex-shrink: 0;
    user-select: none;
}

.credits-person .bar {
    width: 0.2rem;
    height: 4.8rem;
    flex-shrink: 0;
    border-radius: 99.9rem;
}

.bar-primary { background: linear-gradient(to bottom, var(--primary), transparent); }
.bar-accent  { background: linear-gradient(to bottom, var(--accent), transparent); }
.bar-gold    { background: linear-gradient(to bottom, var(--gold), transparent); }

.credits-person .info { flex: 1; }

.credits-person .info .name-row {
    display: flex;
    align-items: center;
    flex-wrap: wrap;
    gap: 1rem;
    margin-bottom: 0.5rem;
}

.credits-person .info .name {
    font-family: 'JetBrains Mono', monospace;
    font-size: 1.5rem;
    font-weight: 700;
    color: var(--text-main);
}

.badge-role {
    font-family: 'JetBrains Mono', monospace;
    font-size: 0.9rem;
    letter-spacing: 0.15rem;
    text-transform: uppercase;
    padding: 0.2rem 0.8rem;
    border-radius: 0.3rem;
    font-weight: 600;
}

.badge-dev  { background: rgba(15,157,203,0.12); color: var(--primary);  border: 0.1rem solid rgba(15,157,203,0.25); }
.badge-dev2 { background: rgba(181,251,42,0.10); color: var(--accent);   border: 0.1rem solid rgba(181,251,42,0.22); }
.badge-des  { background: rgba(255,215,0,0.10);  color: var(--gold);     border: 0.1rem solid rgba(255,215,0,0.22); }

.credits-person .info .meta {
    font-family: 'JetBrains Mono', monospace;
    font-size: 1rem;
    color: var(--text-dim);
    letter-spacing: 0.1rem;
    text-transform: uppercase;
    margin-bottom: 0.7rem;
}

.credits-person .info .handle a {
    font-family: 'JetBrains Mono', monospace;
    font-size: 1.4rem;
    font-weight: 700;
    text-decoration: none;
    transition: all 0.2s ease;
    padding: 0.2rem 0;
    border-bottom: 0.1rem solid transparent;
}

.handle-primary a { color: var(--primary); }
.handle-primary a:hover { color: #3db8e0; text-shadow: 0 0 1.2rem rgba(15,157,203,0.55); border-bottom-color: rgba(15,157,203,0.4); }
.handle-accent a { color: var(--accent); }
.handle-accent a:hover { color: #cbff60; text-shadow: 0 0 1.2rem rgba(181,251,42,0.55); border-bottom-color: rgba(181,251,42,0.4); }
.handle-gold a { color: var(--gold); }
.handle-gold a:hover { color: #ffe44d; text-shadow: 0 0 1.2rem rgba(255,215,0,0.55); border-bottom-color: rgba(255,215,0,0.4); }

.credits-footer-content {
    border-top: 0.1rem solid var(--border);
    padding: 1.4rem 3.2rem;
    display: flex;
    align-items: center;
    justify-content: space-between;
}

.credits-footer-content .ver {
    font-family: 'JetBrains Mono', monospace;
    font-size: 1rem;
    color: var(--border);
    letter-spacing: 0.15rem;
}

.credits-footer-content .dot-row {
    display: flex;
    gap: 0.6rem;
}

.credits-footer-content .dot {
    width: 0.6rem; height: 0.6rem;
    border-radius: 50%;
}

@media (max-width: 850px) {
    :root {
        --header-h: 9rem;
        --tabs-h: 5rem;
        --quicknav-h: 4.5rem;
    }
    .header h1 { font-size: 1.7rem; }
    .header p { font-size: 1.2rem; }
    .header-video { width: 3.5rem; height: 3.5rem; }
    .tab-btn { font-size: 1.2rem; min-width: 6.5rem; }
    .tab-btn i { font-size: 1.4rem; }
    .quick-nav-chip { font-size: 1.2rem; padding: 0.4rem 0.9rem; }
}

@media (max-width: 480px) {
    :root {
        --header-h: 8rem;
        --tabs-h: 4.5rem;
        --quicknav-h: 4.2rem;
    }
