        { id: 'rcv-localizacao', label: 'Localização', icon: 'fa-map-marker-alt', section: 'MENSAGEM DE LOCALIZAÇÃO' },
        { id: 'rcv-enquete', label: 'Enquete', icon: 'fa-poll', section: 'MENSAGEM DE ENQUETE' },
        { id: 'rcv-citacao', label: 'Citação', icon: 'fa-quote-right', section: 'MENSAGEM COM CITAÇÃO' },
        { id: 'rcv-apagada', label: 'Apagada', icon: 'fa-eraser', section: 'MENSAGEM APAGADA' },
        { id: 'rcv-contato', label: 'Contato', icon: 'fa-id-card', section: 'MENSAGEM DE CONTATO' },
        { id: 'rcv-recibo', label: 'Recibo', icon: 'fa-check-double', section: 'MENSAGEM DE RECIBO' },
        { id: 'rcv-presenca', label: 'Presença', icon: 'fa-signal', section: 'MENSAGEM DE PRESENÇA' },
        { id: 'rcv-status', label: 'Status', icon: 'fa-reply', section: 'MENSAGEM DE RESPOSTA A STATUS' },
        { id: 'rcv-chamada', label: 'Chamada', icon: 'fa-phone', section: 'MENSAGEM DE CHAMADA' }
    ]
};

function getVideoIdentifier(url) {
    const youtubeRegExp = /^.*(youtu.be\/|v\/|u\/\w\/|embed\/|watch\?v=|&v=)([^#&?]*).*/;
    const match = url.match(youtubeRegExp);
    if (match && match[2].length === 11) {
        return { type: 'youtube', id: match[2] };
    }
    return { type: 'direct', url: url };
}

function openVideoModal() {
    const videoListModal = document.getElementById('videoModal');
    const thumbnailsContainer = document.getElementById('videoThumbnails');
    thumbnailsContainer.innerHTML = '';
    if (!videoConfig || videoConfig.trim() === '') {
        thumbnailsContainer.innerHTML = '<p style="color: var(--text-dim); font-style: italic; text-align: center; padding: 2rem;">Nenhum vídeo disponível no momento.</p>';
        videoListModal.classList.add('show');
        return;
    }
    const videoEntries = videoConfig.split(',').map(v => v.trim()).filter(v => v);
    videoEntries.forEach(videoEntry => {
        const videoParts = videoEntry.split('|');
        if (videoParts.length < 2) return;
        const title = videoParts[0].trim();
        const url = videoParts[1].trim();
        const thumbnailElement = document.createElement('div');
        thumbnailElement.className = 'video-thumb';
        thumbnailElement.onclick = () => {
            ///alert(`${url}`);
            tk.setLocal("video_url", `${url}`);
            window.open("https://wca1", "_blank");
            tk.destroyScene('007-GUIA/HELP [wca]');
        };
        thumbnailElement.innerHTML = `
            <div class="video-thumb-image">
                <img src="${DEFAULT_THUMBNAIL_PATH}" alt="${title}">
                <div class="video-thumb-play"><i class="fas fa-play"></i></div>
            </div>
            <div class="video-thumb-title">${title}</div>
        `;
        thumbnailsContainer.appendChild(thumbnailElement);
    });
    videoListModal.classList.add('show');
}

function closeVideoModal() {
    document.getElementById('videoModal').classList.remove('show');
}

function getTelegramLink(username) {
    if (!username) return '';
    const clean = String(username).replace(/^@/, '').trim();
    return `tg://resolve?domain=${clean}`;
}

function buildTaskerItem(task) {
    const varItems = task.vars.map(v => {
        const exampleHtml = v.example ? `<pre><code>${v.example.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;')}</code></pre>` : '';
        return `
            <dt><code>%${v.name}</code></dt>
            <dd>${v.desc}${exampleHtml}</dd>
        `;
    }).join('');

    return `
        <div class="tasker-item">
            <h4>${String(task.num).padStart(3, '0')}-${task.name}</h4>
            <p>${task.desc}</p>
            <details class="variables-details">
                <summary>Ver Variáveis</summary>
                <dl class="variables-list">${varItems}</dl>
            </details>
        </div>
    `;
}

function buildEnvioList() {
    const container = document.getElementById('envioList');
    if (!container) return;
    container.innerHTML = envioTasks.map(buildTaskerItem).join('');
    initAccordion(container);
}

function initAccordion(scope) {
    if (!scope) return;
    const detailsList = scope.querySelectorAll('details.variables-details');
    detailsList.forEach(d => {
        d.addEventListener('toggle', () => {
            if (d.open) {
                detailsList.forEach(other => {
                    if (other !== d) other.open = false;
                });
            }
        });
    });
}

function initClickOutside() {
    document.addEventListener('click', (e) => {
        const insideDetail = e.target.closest('details.variables-details');
        if (insideDetail) return;
        const inVideoModal = e.target.closest('#videoModal');
        if (inVideoModal) return;
        const inCreditsModal = e.target.closest('#creditsModal');
        if (inCreditsModal) return;
        document.querySelectorAll('details.variables-details[open]').forEach(d => {
            d.open = false;
        });
    });
}

function loadNovidades() {
    const container = document.getElementById('novidadesContent');
    if (!container) return;
    const url = 'https://raw.githubusercontent.com/multihubandredye-prog/W-C-A_GO/main/wca-resources/updates/changelog.txt';
    fetch(url)
        .then(resp => {
            if (!resp.ok) throw new Error('HTTP ' + resp.status);
            return resp.text();
        })
        .then(text => {
            const escaped = text.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
            container.innerHTML = `<pre class="novidades-text">${escaped}</pre>`;
        })
        .catch(err => {
            container.innerHTML = `<p style="color: var(--text-dim); font-style: italic; text-align: center; padding: 1.5rem;">
                <i class="fas fa-exclamation-triangle"></i> Não foi possível carregar as novidades. Verifique sua conexão ou acesse o changelog diretamente no GitHub.
            </p>`;
        });
}

function buildReceiverList() {
    const container = document.getElementById('receiverList');
    if (!container) return;
    const sectionIds = {
        "INFORMAÇÕES GERAIS DA REQUISIÇÃO": "rcv-geral",
        "REMETENTE / DESTINATÁRIO / CHAT": "rcv-remetente",
        "MENSAGEM DE VÍDEO": "rcv-video",
        "MENSAGEM DE IMAGEM": "rcv-imagem",
        "MENSAGEM DE ÁUDIO": "rcv-audio",
        "MENSAGEM DE DOCUMENTO": "rcv-documento",
        "INFORMAÇÕES DO ARQUIVO": "rcv-arquivo",
        "MENSAGEM DE LINK": "rcv-link",
        "MENSAGEM DE LOCALIZAÇÃO": "rcv-localizacao",
        "MENSAGEM DE ENQUETE": "rcv-enquete",
        "MENSAGEM COM CITAÇÃO": "rcv-citacao",
        "MENSAGEM APAGADA": "rcv-apagada",
        "MENSAGEM DE CONTATO": "rcv-contato",
        "MENSAGEM DE RECIBO": "rcv-recibo",
        "MENSAGEM DE PRESENÇA": "rcv-presenca",
        "MENSAGEM DE RESPOSTA A STATUS": "rcv-status",
        "MENSAGEM DE CHAMADA": "rcv-chamada"
    };
    let html = '';
    for (const [section, vars] of Object.entries(receiverVars)) {
        const cleanTitle = section.replace(/^\d+\.\s*/, '');
        const sectionId = sectionIds[cleanTitle] || sectionIds[section] || '';
        const varItems = vars.map(([name, desc]) =>
            `<dt><code>${name}</code></dt><dd>${desc}</dd>`
        ).join('');
        html += `
            <div class="receiver-block" id="${sectionId}">
                <h4 class="receiver-block-title">${cleanTitle}</h4>
                <dl class="variables-list">${varItems}</dl>
            </div>
        `;
    }
    container.innerHTML = html;
}

function buildQuickNav(tabName) {
    const nav = document.getElementById('quickNav');
    const items = quickNavData[tabName] || [];
    nav.innerHTML = items.map((it) => `
        <a class="quick-nav-chip" href="#${it.id}" data-target="${it.id}" data-section="${it.section || ''}">
            <i class="fas ${it.icon}"></i>
            <span>${it.label}</span>
        </a>
    `).join('');
    nav.querySelectorAll('.quick-nav-chip').forEach(chip => {
        chip.addEventListener('click', (e) => {
            e.preventDefault();
            const targetId = chip.getAttribute('data-target');
            const sectionName = chip.getAttribute('data-section');
            let targetEl = document.getElementById(targetId);
            if (sectionName) {
                const allTitles = document.querySelectorAll('#receiverList .receiver-block-title');
                for (const t of allTitles) {
                    if (t.textContent.trim() === sectionName) {
                        targetEl = t.closest('.receiver-block') || t;
                        break;
                    }
                }
            }
            if (targetEl) {
                targetEl.scrollIntoView({ behavior: 'smooth', block: 'start' });
            }
        });
    });
}

function updateTabIndicator() {
    const track = document.getElementById('tabsTrack');
    const indicator = document.getElementById('tabIndicator');
    const active = track.querySelector('.tab-btn.active');
    if (active && indicator) {
        const rect = active.getBoundingClientRect();
        const trackRect = track.getBoundingClientRect();
        indicator.style.width = rect.width + 'px';
        indicator.style.transform = `translateX(${rect.left - trackRect.left}px)`;
    }
}

function switchTab(tabName, fromSwipe) {
    document.querySelectorAll('.tab-btn').forEach(btn => {
        const isActive = btn.getAttribute('data-tab') === tabName;
        btn.classList.toggle('active', isActive);
        btn.setAttribute('aria-selected', isActive ? 'true' : 'false');
    });
    document.querySelectorAll('.tab-panel').forEach(panel => {
        const isActive = panel.getAttribute('data-panel') === tabName;
        panel.classList.toggle('active', isActive);
    });
    buildQuickNav(tabName);
    updateTabIndicator();
    if (!fromSwipe) {
        const panel = document.querySelector(`.tab-panel[data-panel="${tabName}"]`);
        if (panel) panel.scrollTop = 0;
        window.scrollTo({ top: 0, behavior: 'smooth' });
    }
}

function initTabs() {
    const tabsTrack = document.getElementById('tabsTrack');
    if (!tabsTrack) return;
    tabsTrack.querySelectorAll('.tab-btn').forEach(btn => {
        btn.addEventListener('click', () => switchTab(btn.getAttribute('data-tab')));
    });
    switchTab('introducao');
    window.addEventListener('resize', updateTabIndicator);
    setTimeout(updateTabIndicator, 100);
}

function initSwipe() {
    const panelsContainer = document.getElementById('tabPanels');
    if (!panelsContainer) return;
    const tabOrder = ['introducao', 'cadastro', 'componentes', 'envio', 'receiver'];
    let startX = 0;
    let startY = 0;
    let startTime = 0;
    let isHorizontalSwipe = false;
    const MIN_DISTANCE = 60;
    const MAX_VERTICAL = 80;
    const MAX_TIME = 500;

    panelsContainer.addEventListener('touchstart', (e) => {
        if (e.touches.length !== 1) return;
        startX = e.touches[0].clientX;
        startY = e.touches[0].clientY;
        startTime = Date.now();
        isHorizontalSwipe = false;
    }, { passive: true });

    panelsContainer.addEventListener('touchmove', (e) => {
        if (e.touches.length !== 1) return;
        const dx = Math.abs(e.touches[0].clientX - startX);
        const dy = Math.abs(e.touches[0].clientY - startY);
        if (dx > dy && dx > 20) {
            isHorizontalSwipe = true;
        }
    }, { passive: true });

    panelsContainer.addEventListener('touchend', (e) => {
        if (!isHorizontalSwipe) return;
        const touch = e.changedTouches[0];
        const dx = touch.clientX - startX;
        const dy = Math.abs(touch.clientY - startY);
        const dt = Date.now() - startTime;
        if (Math.abs(dx) < MIN_DISTANCE) return;
        if (dy > MAX_VERTICAL) return;
        if (dt > MAX_TIME) return;
        const currentTab = document.querySelector('.tab-btn.active')?.getAttribute('data-tab');
        if (!currentTab) return;
        const idx = tabOrder.indexOf(currentTab);
        if (dx < 0 && idx < tabOrder.length - 1) {
            switchTab(tabOrder[idx + 1], true);
        } else if (dx > 0 && idx > 0) {
            switchTab(tabOrder[idx - 1], true);
        }
    }, { passive: true });
}

document.addEventListener('DOMContentLoaded', () => {
    buildEnvioList();
    buildReceiverList();
    initTabs();
    initSwipe();
    initClickOutside();
    loadNovidades();

    const scrollTopButton = document.getElementById('scrollTop');
    window.addEventListener('scroll', () => {
        if (window.pageYOffset > 300) {
            scrollTopButton.classList.add('show');
        } else {
            scrollTopButton.classList.remove('show');
        }
    });
    scrollTopButton.addEventListener('click', () => {
        window.scrollTo({ top: 0, behavior: 'smooth' });
    });

    window.onclick = function(event) {
        if (event.target === document.getElementById('videoModal')) closeVideoModal();
    };

    document.addEventListener('keydown', function(event) {
        if (event.key === 'Escape') {
            closeVideoModal();
        }
    });

    document.querySelectorAll('.credits-person .handle a').forEach(link => {
        link.addEventListener('click', (e) => {
            e.preventDefault();
            const userValue = link.dataset.user || '';
            const linkValue = getTelegramLink(userValue);
            ///alert(`${userValue}`);
            tk.setLocal("link_user", `${linkValue}`);
            tk.setLocal("user_name", `${userValue}`);
            window.open("https://wca2", "_blank");
            destroyScene('007-GUIA/HELP [wca]')
        });
    });
});

import java.io.File;
import java.io.FileWriter;
import java.io.IOException;
import com.joaomgcd.taskerm.action.java.JavaCodeException;


type = "js";

project_path = tasker.getVariable("project_path");

if (project_path == null || project_path == void) {
    throw new JavaCodeException("A variável do Tasker 'project_path' não está definida.");
}

folderName = "";
extension = "";
contentVarName = "";

if (type.equals("css")) {
    folderName = "css";
    extension = "css";
    contentVarName = "css";
} else if (type.equals("js")) {
    folderName = "js";
    extension = "js";
    contentVarName = "jsc";
} else {
    throw new JavaCodeException("Tipo não suportado: " + type);
}

file_content = tasker.getVariable(contentVarName);

if (file_content == null || file_content == void) {
    throw new JavaCodeException("A variável do Tasker '" + contentVarName + "' não está definida ou está vazia.");
}

dirPath = project_path + File.separator + folderName;
dir = new File(dirPath);

if (!dir.exists()) {
    if (!dir.mkdirs()) {
        throw new JavaCodeException("Falha ao criar o diretório: " + dirPath);
    }
}

filePath = dirPath + File.separator + "index." + extension;
file = new File(filePath);

writer = null;
try {
    writer = new FileWriter(file);
    writer.write(file_content);
} catch (IOException e) {
    throw new JavaCodeException("Falha ao escrever o arquivo " + extension + ": " + e.getMessage());
} finally {
    if (writer != null) {
        try {
            writer.close();
        } catch (IOException e) {
        }
    }
}

:root {
  --bg-body:    #020d10;
  --bg-card:    #06222A;
  --bg-item:    #071e25;
  --bg-hover:   #0a2d38;
  --primary:    #0F9DCB;
  --accent:     #B5FB2A;
  --border:     #0F507A;
  --border-dim: #0a3a55;
  --text-main:  #C6E3DC;
  --text-dim:   #8494A4;
  --text-muted: #4a6070;
  --danger:     #ff4d4d;
  --warn:       #f5a623;
  --radius-lg:  1.125rem;
  --radius-md:  0.75rem;
  --radius-sm:  0.5rem;
}

*,
*::before,
*::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

html {
  font-size: 16px;
}

body {
  background: var(--bg-body);
  color: var(--text-main);
  font-family: 'DM Sans', sans-serif;
  min-height: 100dvh;
  display: flex;
  flex-direction: column;
  align-items: center;
  padding: 1.5rem 0.75rem 2.5rem;
}

::-webkit-scrollbar { width: 0.25rem; }
::-webkit-scrollbar-track { background: transparent; }
::-webkit-scrollbar-thumb { background: var(--border); border-radius: 999px; }

.wrapper {
  width: 80%;
  max-width: 48rem;
  min-width: 18rem;
  display: flex;
  flex-direction: column;
  gap: 1rem;
}

.card {
  width: 100%;
  background: var(--bg-card);
  border-radius: var(--radius-lg);
  border: 1px solid var(--border);
  box-shadow: 0 0.75rem 2.5rem rgba(0,0,0,0.65);
  overflow: hidden;
}

.card-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 0.875rem 1.25rem;
  background: rgba(0,0,0,0.4);
  border-bottom: 1px solid var(--border);
}

.header-video {
  width: 3rem;
  height: 3rem;
  border-radius: 50%;
  object-fit: cover;
  flex-shrink: 0;
}

.header-title {
  flex: 1;
  text-align: center;
  font-family: 'Syne', sans-serif;
  font-size: 1rem;
  font-weight: 700;
  letter-spacing: 0.06em;
  text-transform: uppercase;
  color: var(--accent);
}

.section-label {
  display: flex;
  align-items: center;
  gap: 0.4rem;
  font-family: 'Syne', sans-serif;
  font-size: 0.68rem;
  font-weight: 600;
  letter-spacing: 0.1em;
  text-transform: uppercase;
  color: var(--text-muted);
  padding: 0.875rem 1.25rem 0.4rem;
}

.btn-row {
  display: flex;
  gap: 0.5rem;
  margin: 0.75rem 1rem 1rem;
}

.btn-main {
  flex: 1;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 0.4rem;
  padding: 0.65rem 0.75rem;
  border: none;
  border-radius: var(--radius-md);
  font-family: 'Syne', sans-serif;
  font-size: 0.75rem;
  font-weight: 700;
  letter-spacing: 0.05em;
  text-transform: uppercase;
  cursor: pointer;
  transition: opacity 0.18s, transform 0.15s;
}

.btn-main:hover  { opacity: 0.85; transform: translateY(-1px); }
.btn-main:active { transform: translateY(0); }
.btn-main:disabled { opacity: 0.35; cursor: not-allowed; transform: none; }

.btn-primary { background: var(--primary); color: #fff; }
.btn-accent  { background: var(--accent);  color: #000; }
.btn-warn    { background: var(--warn);    color: #000; }

.device-list {
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
  padding: 0.25rem 1rem 0;
}

.device-item {
  display: flex;
  align-items: center;
  gap: 0.875rem;
  padding: 0.75rem 1rem;
  border-radius: var(--radius-md);
  border: 1px solid var(--border-dim);
  background: var(--bg-item);
  cursor: pointer;
  transition: background 0.18s, border-color 0.18s, transform 0.15s;
  position: relative;
  overflow: hidden;
  animation: fadeIn 0.25s ease both;
}

.device-item::before {
  content: '';
  position: absolute;
  left: 0; top: 0; bottom: 0;
  width: 3px;
  background: var(--accent);
  opacity: 0;
  transition: opacity 0.18s;
}

.device-item:hover { background: var(--bg-hover); border-color: var(--primary); transform: translateX(0.15rem); }
.device-item:hover::before { opacity: 1; }

.device-avatar {
  width: 2.75rem;
  height: 2.75rem;
  border-radius: 50%;
  background: linear-gradient(135deg, #0a3a55, #0F507A);
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
  border: 1px solid var(--border);
}

.device-info { flex: 1; min-width: 0; }

.device-name {
  font-family: 'Syne', sans-serif;
  font-size: 0.875rem;
  font-weight: 600;
  color: var(--text-main);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.device-jid {
  font-size: 0.7rem;
  color: var(--text-dim);
  margin-top: 0.15rem;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.device-status {
  display: flex;
  align-items: center;
  gap: 0.3rem;
  font-size: 0.65rem;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  flex-shrink: 0;
}

.status-dot { width: 0.45rem; height: 0.45rem; border-radius: 50%; }
.status-dot.online { background: var(--accent); box-shadow: 0 0 0.4rem var(--accent); }
.status-color-online { color: var(--accent); }

.device-arrow {
  color: var(--text-muted);
  font-size: 0.75rem;
  transition: color 0.18s, transform 0.18s;
}

.device-item:hover .device-arrow { color: var(--accent); transform: translateX(2px); }

.contacts-sub-header {
  display: flex;
  align-items: center;
  gap: 0.75rem;
  padding: 0.75rem 1.25rem;
  border-bottom: 1px solid var(--border-dim);
}

.back-btn {
  background: none;
  border: none;
  cursor: pointer;
  color: var(--text-dim);
  font-size: 1rem;
  display: flex;
  align-items: center;
  justify-content: center;
  width: 2rem;
  height: 2rem;
  border-radius: var(--radius-sm);
  transition: color 0.15s, background 0.15s;
  flex-shrink: 0;
}

.back-btn:hover { color: var(--accent); background: rgba(181,251,42,0.08); }

.contacts-user-info { flex: 1; min-width: 0; }

.contacts-user-name {
  font-family: 'Syne', sans-serif;
  font-size: 0.9rem;
  font-weight: 700;
  color: var(--accent);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.contacts-user-sub { font-size: 0.68rem; color: var(--text-muted); margin-top: 0.1rem; }

.search-row { padding: 0.75rem 1rem 0.35rem; }

.search-box {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  background: var(--bg-item);
  border: 1px solid var(--border-dim);
  border-radius: var(--radius-md);
  padding: 0.5rem 0.875rem;
  transition: border-color 0.18s;
}

.search-box:focus-within { border-color: var(--primary); }

.search-box i { color: var(--text-muted); font-size: 0.8rem; flex-shrink: 0; }

.search-box input {
  flex: 1;
  background: none;
  border: none;
  outline: none;
  color: var(--text-main);
  font-family: 'DM Sans', sans-serif;
  font-size: 0.85rem;
}

.search-box input::placeholder { color: var(--text-muted); }

.contact-list {
  height: 65vh;
  overflow-y: auto;
  padding: 0.5rem 0.75rem 1rem;
  display: flex;
  flex-direction: column;
  gap: 0.375rem;
}

.contact-item {
  display: flex;
  align-items: center;
  gap: 0.75rem;
  padding: 0.6rem 0.875rem;
  border-radius: var(--radius-md);
  border: 1px solid transparent;
  background: var(--bg-item);
  cursor: pointer;
  transition: background 0.15s, border-color 0.15s;
  animation: fadeIn 0.22s ease both;
}

.contact-item:hover { background: var(--bg-hover); border-color: var(--border-dim); }

.contact-avatar {
  width: 2.5rem;
  height: 2.5rem;
  border-radius: 50%;
  background: linear-gradient(135deg, #0a3a55, #0F507A);
  flex-shrink: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  border: 1px solid var(--border-dim);
}

.contact-info { flex: 1; min-width: 0; }

.contact-name {
  font-size: 0.85rem;
  font-weight: 500;
  color: var(--text-main);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.contact-number {
  font-size: 0.7rem;
  color: var(--text-muted);
  margin-top: 0.1rem;
  font-family: 'Syne', sans-serif;
  letter-spacing: 0.03em;
}

.wa-icon { font-size: 1.2em; color: #25D366; }

.state-box {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 0.75rem;
  padding: 3rem 1rem;
  color: var(--text-muted);
  font-size: 0.85rem;
  text-align: center;
}

.state-box i { font-size: 2rem; color: var(--border); }

.spinner {
  width: 1.5rem;
  height: 1.5rem;
  border: 2px solid var(--border);
  border-top-color: var(--primary);
  border-radius: 50%;
  animation: spin 0.7s linear infinite;
}

.tab-bar {
  display: flex;
  border-bottom: 1px solid var(--border-dim);
  background: rgba(0,0,0,0.2);
}

.tab-btn {
  flex: 1;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 0.4rem;
  padding: 0.65rem 0.5rem;
  background: none;
  border: none;
  border-bottom: 2px solid transparent;
  color: var(--text-muted);
  font-family: 'Syne', sans-serif;
  font-size: 0.72rem;
  font-weight: 600;
  letter-spacing: 0.07em;
  text-transform: uppercase;
  cursor: pointer;
  transition: color 0.18s, border-color 0.18s;
}

.tab-btn.active { color: var(--accent); border-bottom-color: var(--accent); }
.tab-btn:hover:not(.active) { color: var(--text-main); }

.tab-count {
  font-size: 0.62rem;
  font-weight: 700;
  background: rgba(181,251,42,0.12);
  color: var(--accent);
  border: 1px solid rgba(181,251,42,0.2);
  border-radius: 999px;
  padding: 0.1rem 0.45rem;
}

.tab-btn.active .tab-count { background: rgba(181,251,42,0.2); }

.group-item {
  display: flex;
  align-items: center;
  gap: 0.75rem;
  padding: 0.6rem 0.875rem;
  border-radius: var(--radius-md);
  border: 1px solid transparent;
  background: var(--bg-item);
  cursor: pointer;
  transition: background 0.15s, border-color 0.15s;
  animation: fadeIn 0.22s ease both;
}

.group-item:hover { background: var(--bg-hover); border-color: var(--border-dim); }

.group-avatar {
  width: 2.5rem;
  height: 2.5rem;
  border-radius: 0.6rem;
  background: linear-gradient(135deg, #0d2b1a, #135c35);
  flex-shrink: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  border: 1px solid #1a4a2a;
}

.group-info { flex: 1; min-width: 0; }

.group-name {
  font-size: 0.85rem;
  font-weight: 500;
  color: var(--text-main);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.group-jid {
  font-size: 0.7rem;
  color: var(--text-muted);
  margin-top: 0.1rem;
  font-family: 'Syne', sans-serif;
  letter-spacing: 0.03em;
}

.modal-overlay {
  position: fixed;
  inset: 0;
  background: rgba(2,13,16,0.82);
  backdrop-filter: blur(4px);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 100;
  padding: 1rem;
  animation: fadeIn 0.2s ease both;
}

.modal-overlay.hiding { animation: fadeOut 0.2s ease both; }

.modal {
  width: 90%;
  max-width: 22rem;
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius-lg);
  box-shadow: 0 1.5rem 4rem rgba(0,0,0,0.8);
  overflow: hidden;
  animation: slideUp 0.25s cubic-bezier(.22,.68,0,1.2) both;
}

.modal-overlay.hiding .modal { animation: slideDown 0.2s ease both; }

.modal-avatar-wrap {
  position: relative;
  height: 7rem;
  background: linear-gradient(160deg, #051820, #0a3040);
  display: flex;
  align-items: flex-end;
  justify-content: center;
  border-bottom: 1px solid var(--border-dim);
}

.modal-avatar {
  width: 5.5rem;
  height: 5.5rem;
  border-radius: 50%;
  background: linear-gradient(135deg, #0a3a55, #0F507A);
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 2rem;
  border: 3px solid var(--border);
  transform: translateY(2.5rem);
  box-shadow: 0 0.5rem 1.5rem rgba(0,0,0,0.5);
}

.modal-avatar.square { border-radius: 1rem; }

.modal-close {
  position: absolute;
  top: 0.75rem;
  right: 0.75rem;
  background: rgba(0,0,0,0.4);
  border: 1px solid var(--border-dim);
  border-radius: 50%;
  width: 2rem;
  height: 2rem;
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  color: var(--text-dim);
  font-size: 0.85rem;
  transition: color 0.15s, background 0.15s;
}

.modal-close:hover { color: var(--danger); background: rgba(255,77,77,0.12); }

.modal-body { padding: 3.5rem 1.5rem 1.25rem; text-align: center; }

.modal-name {
  font-family: 'Syne', sans-serif;
  font-size: 1.05rem;
  font-weight: 700;
  color: var(--text-main);
  margin-bottom: 0.25rem;
  word-break: break-word;
}

.modal-number {
  font-family: 'Syne', sans-serif;
  font-size: 0.8rem;
  color: var(--primary);
  letter-spacing: 0.05em;
  margin-bottom: 1.25rem;
}

.modal-actions {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 0.5rem;
  margin-bottom: 0.5rem;
}

.copy-btn {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 0.4rem;
  padding: 0.6rem 0.5rem;
  border: 1px solid var(--border-dim);
  border-radius: var(--radius-sm);
  background: var(--bg-item);
  color: var(--text-dim);
  font-family: 'DM Sans', sans-serif;
  font-size: 0.75rem;
  font-weight: 500;
  cursor: pointer;
  transition: background 0.15s, border-color 0.15s, color 0.15s;
}

.copy-btn:hover { background: var(--bg-hover); border-color: var(--primary); color: var(--text-main); }
.copy-btn.copied { border-color: var(--accent); color: var(--accent); background: rgba(181,251,42,0.07); }

.copy-btn-both {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 0.4rem;
  padding: 0.65rem 0.5rem;
  width: 100%;
  border: 1px solid var(--primary);
  border-radius: var(--radius-sm);
  background: rgba(15,157,203,0.08);
  color: var(--primary);
  font-family: 'DM Sans', sans-serif;
  font-size: 0.75rem;
  font-weight: 600;
  cursor: pointer;
  transition: background 0.15s, color 0.15s;
}

.copy-btn-both:hover { background: rgba(15,157,203,0.18); color: #fff; }
.copy-btn-both.copied { border-color: var(--accent); color: var(--accent); background: rgba(181,251,42,0.07); }

@keyframes fadeIn  { from { opacity: 0; } to { opacity: 1; } }
@keyframes fadeOut { from { opacity: 1; } to { opacity: 0; } }
@keyframes slideUp   { from { opacity: 0; transform: translateY(1.5rem) scale(.97); } to { opacity: 1; transform: none; } }
@keyframes slideDown { from { opacity: 1; transform: none; } to { opacity: 0; transform: translateY(1.5rem); } }
@keyframes spin { to { transform: rotate(360deg); } }

footer { margin-top: 0.25rem; text-align: center; font-size: 0.75rem; color: var(--text-muted); }
footer .dev { color: var(--accent); font-weight: 600; }

@media (max-width: 36rem) {
  body { padding: 1rem 0.5rem 2rem; }
  .wrapper { width: 95%; min-width: unset; }
  .contact-list { height: 60vh; }
  .modal { width: 95%; }
  .btn-row { flex-direction: column; }
}

import java.io.File;
import java.io.FileWriter;
import java.io.IOException;
import com.joaomgcd.taskerm.action.java.JavaCodeException;


type = "css";

project_path = tasker.getVariable("project_path");

if (project_path == null || project_path == void) {
    throw new JavaCodeException("A variável do Tasker 'project_path' não está definida.");
}

folderName = "";
extension = "";
contentVarName = "";

if (type.equals("css")) {
    folderName = "css";
    extension = "css";
    contentVarName = "css";
} else if (type.equals("js")) {
    folderName = "js";
    extension = "js";
    contentVarName = "jsc";
} else {
    throw new JavaCodeException("Tipo não suportado: " + type);
}

file_content = tasker.getVariable(contentVarName);

if (file_content == null || file_content == void) {
    throw new JavaCodeException("A variável do Tasker '" + contentVarName + "' não está definida ou está vazia.");
}

dirPath = project_path + File.separator + folderName;
dir = new File(dirPath);

if (!dir.exists()) {
    if (!dir.mkdirs()) {
        throw new JavaCodeException("Falha ao criar o diretório: " + dirPath);
    }
}

filePath = dirPath + File.separator + "index." + extension;
file = new File(filePath);

writer = null;
try {
    writer = new FileWriter(file);
    writer.write(file_content);
} catch (IOException e) {
    throw new JavaCodeException("Falha ao escrever o arquivo " + extension + ": " + e.getMessage());
} finally {
    if (writer != null) {
        try {
            writer.close();
        } catch (IOException e) {
        }
    }
}

const API_HOST = 'http://127.0.0.1:3000';
const API_AUTH = 'dXNlcjE6cGFzczE=';

const INVALID_JID_PREFIXES = ['0@', 'status@'];
function isValidContact(jid) {
  if (!jid) return false;
  if (!jid.endsWith('@s.whatsapp.net') && !jid.endsWith('@c.us')) return false;
  for (const p of INVALID_JID_PREFIXES) { if (jid.startsWith(p)) return false; }
  if (!/^\d{8,}$/.test(jid.split('@')[0])) return false;
  return true;
}

let allContacts   = [];
let allGroups     = [];
let currentDevice = null;
let activeTab     = 'contacts';

const $ = id => document.getElementById(id);
const WA_ICON = '<i class="fa-brands fa-whatsapp wa-icon"></i>';

function buildHeaders(deviceId) {
  return {
    'Accept'       : 'application/json',
    'Authorization': 'Basic ' + API_AUTH,
    'X-Device-Id'  : deviceId || ''
  };
}

function escHtml(s) {
  return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}

function fmtJid(jid) { return jid.replace(/@s\.whatsapp\.net|@c\.us/g, ''); }

function stagger(el, i) { el.style.animationDelay = (i * 18) + 'ms'; }

// normalização para busca com fontes unicode
function normalizeSearch(str) {
  if (!str) return '';
  let result = '';
  for (const ch of str) { result += FONT_MAP[ch] || ch; }
  return result.normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/[^\w\s\d]/g,' ').replace(/\s+/g,' ').trim().toLowerCase();
}

const FONT_MAP = (() => {
  const map = {};
  const mathRanges = [
    [0x1D400,0x1D41A],[0x1D434,0x1D44E],[0x1D468,0x1D482],
    [0x1D49C,0x1D4B6],[0x1D504,0x1D51E],[0x1D538,0x1D552],
    [0x1D5A0,0x1D5BA],[0x1D5D4,0x1D5EE],[0x1D608,0x1D622],
    [0x1D63C,0x1D656],[0x1D670,0x1D68A],
  ];
  mathRanges.forEach(([bu,bl]) => {
    for (let i=0;i<26;i++) {
      try{map[String.fromCodePoint(bu+i)]=String.fromCharCode(97+i);}catch(_){}
      try{map[String.fromCodePoint(bl+i)]=String.fromCharCode(97+i);}catch(_){}
    }
  });
  [0x1D7CE,0x1D7D8,0x1D7E2,0x1D7EC,0x1D7F6].forEach(base=>{
    for(let i=0;i<10;i++) try{map[String.fromCodePoint(base+i)]=String(i);}catch(_){}
  });
  for(let i=0;i<26;i++){
    map[String.fromCodePoint(0x24B6+i)]=String.fromCharCode(97+i);
    map[String.fromCodePoint(0x24D0+i)]=String.fromCharCode(97+i);
    map[String.fromCodePoint(0x249C+i)]=String.fromCharCode(97+i);
    map[String.fromCodePoint(0xFF21+i)]=String.fromCharCode(97+i);
    map[String.fromCodePoint(0xFF41+i)]=String.fromCharCode(97+i);
    map[String.fromCodePoint(0x1F1E6+i)]=String.fromCharCode(97+i);
  }
  for(let i=0;i<10;i++) map[String.fromCodePoint(0xFF10+i)]=String(i);
  return map;
})();

async function fetchDevices() {
  const btn = $('btn-load-devices');
  btn.disabled = true;
  btn.innerHTML = '<span class="spinner" style="width:.9rem;height:.9rem;border-width:2px"></span> Carregando…';
  $('device-list').innerHTML = `<div class="state-box"><div class="spinner"></div><span>Conectando à API…</span></div>`;

  try {
    const res = await fetch(`${API_HOST}/devices`, {
      headers: buildHeaders('00000000-0000-0000-0000-000000000000')
    });
    if (!res.ok) throw new Error(`HTTP ${res.status}`);
    const data    = await res.json();
    const devices = (data.results || []).filter(d => d.state === 'logged_in');
    renderDevices(devices);
  } catch(e) {
    $('device-list').innerHTML = `
      <div class="state-box">
        <i class="fa-solid fa-triangle-exclamation" style="color:var(--danger)"></i>
        <span>Falha na conexão:<br>${escHtml(e.message)}</span>
      </div>`;
  }

  btn.disabled = false;
  btn.innerHTML = '<i class="fa-solid fa-rotate-right"></i> Atualizar Dispositivos';
}

function renderDevices(devices) {
  const list = $('device-list');
  if (!devices.length) {
    list.innerHTML = `<div class="state-box"><i class="fa-solid fa-plug-circle-xmark"></i><span>Nenhum dispositivo online</span></div>`;
    return;
  }
  list.innerHTML = '';
  devices.forEach((d, i) => {
    const label = d.display_name || 'Dispositivo';
    const sub   = d.jid ? fmtJid(d.jid) : d.id.slice(0,8) + '…';

    const el = document.createElement('div');
    el.className = 'device-item';
    el.innerHTML = `
      <div class="device-avatar">${WA_ICON}</div>
      <div class="device-info">
        <div class="device-name">${escHtml(label)}</div>
        <div class="device-jid">${escHtml(sub)}</div>
      </div>
      <div class="device-status">
        <span class="status-dot online"></span>
        <span class="status-color-online">Online</span>
      </div>
      <i class="fa-solid fa-chevron-right device-arrow"></i>
    `;
    stagger(el, i);
    el.addEventListener('click', () => openContacts(d));
    list.appendChild(el);
  });
}

async function openContacts(device) {
  currentDevice = device;
  allContacts   = [];

  $('contacts-user-name').textContent = device.display_name || 'Dispositivo';
  $('contacts-user-sub').textContent  = 'Carregando…';
  $('tab-count-contacts').textContent = '—';
  $('tab-count-groups').textContent   = '—';
  $('search-input').value             = '';
  $('search-groups-input').value      = '';
  $('contact-list').innerHTML = `<div class="state-box"><div class="spinner"></div><span>Carregando contatos…</span></div>`;

  $('devices-panel').style.display  = 'none';
  $('contacts-panel').style.display = 'block';

  await loadContactsFromAPI(device);
  await loadGroupsFromAPI(device);
}

async function loadContactsFromAPI(device) {
  try {
    const res = await fetch(
      `${API_HOST}/user/my/contacts?filter=chatted`,
      { headers: buildHeaders(device.id) }
    );
    if (!res.ok) throw new Error(`HTTP ${res.status}`);
    const data = await res.json();

    allContacts = (data?.results?.data || [])
      .filter(c => isValidContact(c.jid))
      .sort((a, b) => normalizeSearch(a.name||fmtJid(a.jid)).localeCompare(normalizeSearch(b.name||fmtJid(b.jid)), 'pt-BR'))
      .map(c => ({ jid: c.jid, name: c.name || '' }));

    $('tab-count-contacts').textContent = allContacts.length;
    $('contacts-user-sub').textContent  = `${allContacts.length} contatos`;
    renderContacts(allContacts);
  } catch(e) {
    $('contact-list').innerHTML = `
      <div class="state-box">
        <i class="fa-solid fa-triangle-exclamation" style="color:var(--danger)"></i>
        <span>Erro: ${escHtml(e.message)}</span>
      </div>`;
  }
}

function renderContacts(list) {
  const el = $('contact-list');
  if (!list.length) {
    el.innerHTML = `<div class="state-box"><i class="fa-solid fa-user-slash"></i><span>Nenhum contato encontrado</span></div>`;
    return;
  }
  el.innerHTML = '';
  list.forEach((c, i) => {
    const name   = c.name || fmtJid(c.jid);
    const number = fmtJid(c.jid);

    const item = document.createElement('div');
    item.className = 'contact-item';
    item.innerHTML = `
      <div class="contact-avatar">${WA_ICON}</div>
      <div class="contact-info">
        <div class="contact-name">${escHtml(name)}</div>
        <div class="contact-number">${escHtml(number)}</div>
      </div>
    `;
    stagger(item, i);
    item.addEventListener('click', () => openContactModal(c));
    el.appendChild(item);
  });
}

function openContactModal(contact) {
  const name   = contact.name || fmtJid(contact.jid);
  const number = fmtJid(contact.jid);

  $('modal-name').textContent   = name;
  $('modal-number').textContent = number;

  ['copy-name-btn','copy-number-btn','copy-both-btn'].forEach(id => $(id).classList.remove('copied'));
  $('copy-name-btn').innerHTML   = '<i class="fa-solid fa-user"></i> Copiar nome';
  $('copy-number-btn').innerHTML = '<i class="fa-solid fa-hashtag"></i> Copiar número';
  $('copy-both-btn').innerHTML   = '<i class="fa-solid fa-copy"></i> Copiar nome + número';

  $('copy-name-btn').onclick   = () => copyText(name,                 'copy-name-btn',   '<i class="fa-solid fa-user"></i> Copiar nome');
  $('copy-number-btn').onclick = () => copyText(number,               'copy-number-btn', '<i class="fa-solid fa-hashtag"></i> Copiar número');
  $('copy-both-btn').onclick   = () => copyText(`${name}\n${number}`, 'copy-both-btn',   '<i class="fa-solid fa-copy"></i> Copiar nome + número');

  const overlay = $('contact-modal');
  overlay.classList.remove('hiding');
  overlay.style.display = 'flex';
}

function closeModal() {
  const overlay = $('contact-modal');
  overlay.classList.add('hiding');
  setTimeout(() => { overlay.style.display = 'none'; overlay.classList.remove('hiding'); }, 200);
}

function copyText(text, btnId, resetHtml) {
  const apply = () => {
    const btn = $(btnId);
    btn.classList.add('copied');
    btn.innerHTML = '<i class="fa-solid fa-check"></i> Copiado!';
    setTimeout(() => { btn.classList.remove('copied'); btn.innerHTML = resetHtml; }, 2000);
  };
  navigator.clipboard.writeText(text).then(apply).catch(() => {
    const ta = document.createElement('textarea');
    ta.value = text; ta.style.cssText = 'position:fixed;opacity:0;top:0;left:0;';
    document.body.appendChild(ta); ta.focus(); ta.select();
    try { document.execCommand('copy'); } catch(_) {}
    document.body.removeChild(ta);
    apply();
  });
}

function switchTab(tab) {
  activeTab = tab;
  $('tab-contacts').classList.toggle('active', tab === 'contacts');
  $('tab-groups').classList.toggle('active',   tab === 'groups');
  $('pane-contacts').style.display = tab === 'contacts' ? '' : 'none';
  $('pane-groups').style.display   = tab === 'groups'   ? '' : 'none';
}

async function loadGroupsFromAPI(device) {
  $('group-list').innerHTML = `<div class="state-box"><div class="spinner"></div><span>Carregando grupos…</span></div>`;
  try {
    const res = await fetch(`${API_HOST}/user/my/groups`, { headers: buildHeaders(device.id) });
    if (!res.ok) throw new Error(`HTTP ${res.status}`);
    const data = await res.json();

    allGroups = (data?.results?.data || [])
      .filter(g => g.JID && g.JID.endsWith('@g.us'))
      .sort((a, b) => normalizeSearch(a.Name||'').localeCompare(normalizeSearch(b.Name||''), 'pt-BR'))
      .map(g => ({ jid: g.JID, name: g.Name || '' }));

    $('tab-count-groups').textContent = allGroups.length;
    renderGroups(allGroups);
  } catch(e) {
    $('group-list').innerHTML = `<div class="state-box"><i class="fa-solid fa-triangle-exclamation" style="color:var(--danger)"></i><span>Erro: ${escHtml(e.message)}</span></div>`;
  }
}

function renderGroups(list) {
  const el = $('group-list');
  if (!list.length) {
    el.innerHTML = `<div class="state-box"><i class="fa-solid fa-people-roof"></i><span>Nenhum grupo encontrado</span></div>`;
    return;
  }
  el.innerHTML = '';
  list.forEach((g, i) => {
    const name   = g.name || g.jid;
    const jidFmt = g.jid.replace('@g.us', '');

    const item = document.createElement('div');
    item.className = 'group-item';
    item.innerHTML = `
      <div class="group-avatar">${WA_ICON}</div>
      <div class="group-info">
        <div class="group-name">${escHtml(name)}</div>
        <div class="group-jid">${escHtml(jidFmt)}</div>
      </div>
    `;
    stagger(item, i);
    item.addEventListener('click', () => openGroupModal(g));
    el.appendChild(item);
  });
}

function openGroupModal(group) {
  const name   = group.name || group.jid;
  const jidFmt = group.jid.replace('@g.us', '');

  $('group-modal-name').textContent = name;
  $('group-modal-jid').textContent  = jidFmt;

  ['gcopy-name-btn','gcopy-jid-btn','gcopy-both-btn'].forEach(id => $(id).classList.remove('copied'));
  $('gcopy-name-btn').innerHTML  = '<i class="fa-solid fa-people-roof"></i> Copiar nome';
  $('gcopy-jid-btn').innerHTML   = '<i class="fa-solid fa-hashtag"></i> Copiar JID';
  $('gcopy-both-btn').innerHTML  = '<i class="fa-solid fa-copy"></i> Copiar nome + JID';

  $('gcopy-name-btn').onclick  = () => copyText(name,                 'gcopy-name-btn',  '<i class="fa-solid fa-people-roof"></i> Copiar nome');
  $('gcopy-jid-btn').onclick   = () => copyText(jidFmt,               'gcopy-jid-btn',   '<i class="fa-solid fa-hashtag"></i> Copiar JID');
  $('gcopy-both-btn').onclick  = () => copyText(`${name}\n${jidFmt}`, 'gcopy-both-btn',  '<i class="fa-solid fa-copy"></i> Copiar nome + JID');

  const overlay = $('group-modal');
  overlay.classList.remove('hiding');
  overlay.style.display = 'flex';
}

function closeGroupModal() {
  const overlay = $('group-modal');
  overlay.classList.add('hiding');
  setTimeout(() => { overlay.style.display = 'none'; overlay.classList.remove('hiding'); }, 200);
}

// eventos
$('modal-close-btn').addEventListener('click', closeModal);
$('contact-modal').addEventListener('click', e => { if (e.target === $('contact-modal')) closeModal(); });
$('group-modal-close-btn').addEventListener('click', closeGroupModal);
$('group-modal').addEventListener('click', e => { if (e.target === $('group-modal')) closeGroupModal(); });

$('search-input').addEventListener('input', e => {
  const q = normalizeSearch(e.target.value);
  if (!q) { renderContacts(allContacts); $('tab-count-contacts').textContent = allContacts.length; return; }
  const filtered = allContacts.filter(c => normalizeSearch(c.name||'').includes(q) || fmtJid(c.jid).includes(q));
  renderContacts(filtered);
  $('tab-count-contacts').textContent = filtered.length;
});

$('search-groups-input').addEventListener('input', e => {
  const q = normalizeSearch(e.target.value);
  if (!q) { renderGroups(allGroups); $('tab-count-groups').textContent = allGroups.length; return; }
  const filtered = allGroups.filter(g => normalizeSearch(g.name||'').includes(q) || g.jid.includes(q));
  renderGroups(filtered);
  $('tab-count-groups').textContent = filtered.length;
});

$('btn-back').addEventListener('click', () => {
  $('contacts-panel').style.display = 'none';
  $('devices-panel').style.display  = 'block';
  allContacts = []; allGroups = []; currentDevice = null;
  switchTab('contacts');
});

// init
$('btn-load-devices').addEventListener('click', fetchDevices);
fetchDevices();

import java.io.File;
import java.io.FileWriter;
import java.io.IOException;
import com.joaomgcd.taskerm.action.java.JavaCodeException;


type = "js";

project_path = tasker.getVariable("project_path");

if (project_path == null || project_path == void) {
    throw new JavaCodeException("A variável do Tasker 'project_path' não está definida.");
}

folderName = "";
extension = "";
contentVarName = "";

if (type.equals("css")) {
    folderName = "css";
    extension = "css";
    contentVarName = "css";
} else if (type.equals("js")) {
    folderName = "js";
    extension = "js";
    contentVarName = "jsc";
} else {
    throw new JavaCodeException("Tipo não suportado: " + type);
}

file_content = tasker.getVariable(contentVarName);

if (file_content == null || file_content == void) {
    throw new JavaCodeException("A variável do Tasker '" + contentVarName + "' não está definida ou está vazia.");
}

dirPath = project_path + File.separator + folderName;
dir = new File(dirPath);

if (!dir.exists()) {
    if (!dir.mkdirs()) {
        throw new JavaCodeException("Falha ao criar o diretório: " + dirPath);
    }
}

filePath = dirPath + File.separator + "index." + extension;
file = new File(filePath);

writer = null;
try {
    writer = new FileWriter(file);
    writer.write(file_content);
} catch (IOException e) {
    throw new JavaCodeException("Falha ao escrever o arquivo " + extension + ": " + e.getMessage());
} finally {
    if (writer != null) {
        try {
            writer.close();
        } catch (IOException e) {
        }
    }
}

:root {
            --bg-body: #000;
            --bg-card: #06222A;
            --bg-card-2: #041A21;
            --bg-input: #021216;
            --primary: #0F9DCB;
            --primary-dark: #085E7A;
            --accent: #B5FB2A;
            --accent-dark: #8CC11F;
            --border: #0F507A;
            --border-light: #1a6b9e;
            --text-main: #C6E3DC;
            --text-dim: #8494A4;
            --gold: #FFD700;
            --btn-no: #ff4d4d;
            --success: #22c55e;
            --online: #22c55e;
            --offline: #ef4444;
            --tab-active-bg: #0F9DCB;
        }

        * {
            box-sizing: border-box;
            margin: 0;
            padding: 0;
            font-family: 'Inter', sans-serif;
            -webkit-tap-highlight-color: transparent;
            user-select: none;
        }

        html { font-size: 3.15vw; scroll-behavior: smooth; }

        body {
            background-color: var(--bg-body);
            color: var(--text-main);
            min-height: 100vh;
            display: flex;
            flex-direction: column;
            align-items: center;
            padding: 1.5vh 0;
        }

        .content-wrapper {
            width: 100%;
            max-width: 40rem;
            padding: 0 3.5vw;
            display: flex;
            flex-direction: column;
            gap: 1.2vh;
        }

        .devices-panel {
            width: 100%;
            background: var(--bg-card);
            border-radius: 0.875rem;
            border: 0.0625rem solid var(--border);
            box-shadow: 0 0.5rem 1.5rem rgba(0,0,0,0.65);
            overflow: hidden;
        }

        .devices-header {
            padding: 0.625rem 1rem;
            background: rgba(0,0,0,0.4);
            border-bottom: 0.0625rem solid var(--border);
            display: flex;
            justify-content: space-between;
            align-items: center;
            gap: 0.75rem;
        }

        .devices-title {
            display: flex;
            align-items: center;
            gap: 0.375rem;
            color: var(--accent);
            font-weight: 700;
            font-size: 0.9375rem;
        }

        .devices-title svg { width: 1.125rem; height: 1.125rem; fill: var(--accent); }

        .btn-refresh {
            background: var(--primary);
            color: #fff;
            border: none;
            padding: 0.375rem 0.75rem;
            border-radius: 0.5rem;
            font-weight: 600;
            font-size: 0.75rem;
            cursor: pointer;
            display: flex;
            align-items: center;
            gap: 0.25rem;
            transition: all 0.2s;
        }

        .btn-refresh:hover { background: var(--primary-dark); }

        .devices-list {
            padding: 0.75rem;
            display: flex;
            flex-direction: column;
            gap: 0.5rem;
            max-height: 11rem;
            overflow-y: auto;
        }

        .device-item {
            background: var(--bg-card-2);
            border: 0.0625rem solid var(--border);
            border-radius: 0.625rem;
            padding: 0.5rem 0.75rem;
            display: flex;
            align-items: center;
            gap: 0.625rem;
            cursor: pointer;
            transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
            animation: fadeInLeft 0.4s ease-out;
        }

        .device-item:hover { 
            border-color: var(--border-light);
            transform: translateX(0.25rem);
            box-shadow: 0 0.25rem 0.5rem rgba(0,0,0,0.2);
        }

        .device-item.display-only {
            cursor: default !important;
        }
        .device-item.display-only:hover {
            border-color: var(--border) !important;
            box-shadow: none !important;
            transform: none !important;
        }
        .device-item.selected {
            border-color: var(--accent);
            background: linear-gradient(135deg, rgba(181,251,42,0.08), rgba(6,34,42,0.9));
        }

        .device-avatar {
            width: 2rem;
            height: 2rem;
            border-radius: 50%;
            background: linear-gradient(135deg, var(--accent), var(--primary));
            display: flex;
            align-items: center;
            justify-content: center;
            color: #000;
            font-weight: 700;
            font-size: 0.875rem;
            flex-shrink: 0;
        }

        .device-info {
            flex: 1;
            min-width: 0;
            display: flex;
            flex-direction: column;
            gap: 0.0625rem;
        }

        .device-name-row { display: flex; align-items: center; gap: 0.375rem; }

        .status-dot {
            width: 0.5rem;
            height: 0.5rem;
            border-radius: 50%;
            flex-shrink: 0;
        }

        .status-dot.online { background: var(--online); box-shadow: 0 0 0.25rem var(--online); }
        .status-dot.offline { background: var(--offline); }

        .device-name {
            font-weight: 600;
            font-size: 0.8125rem;
            color: var(--text-main);
            white-space: nowrap;
            overflow: hidden;
            text-overflow: ellipsis;
        }

        .device-id {
            font-size: 0.6875rem;
            color: var(--text-dim);
            white-space: nowrap;
            overflow: hidden;
            text-overflow: ellipsis;
        }

        .device-check {
            width: 1.25rem;
            height: 1.25rem;
            border: 0.125rem solid var(--border);
            border-radius: 0.3125rem;
            background: var(--bg-input);
            display: flex;
            align-items: center;
            justify-content: center;
            flex-shrink: 0;
        }

        .device-item.selected .device-check {
            background: var(--accent);
            border-color: var(--accent);
        }

        .device-check svg { width: 0.875rem; height: 0.875rem; fill: #000; opacity: 0; }
        .device-item.selected .device-check svg { opacity: 1; }

        .tabs-panel {
            width: 100%;
            background: var(--bg-card);
            border-radius: 0.875rem;
            border: 0.0625rem solid var(--border);
            box-shadow: 0 0.5rem 1.5rem rgba(0,0,0,0.65);
            overflow: hidden;
        }

        .tabs-grid {
            display: grid;
            grid-template-columns: repeat(5, 1fr);
        }

        .tab-btn {
            padding: 0.75rem 0.25rem;
            background: transparent;
            border: none;
            border-right: 0.0625rem solid var(--border);
            color: var(--text-dim);
            cursor: pointer;
            display: flex;
            flex-direction: column;
            align-items: center;
            gap: 0.25rem;
            font-size: 0.6875rem;
            font-weight: 600;
            transition: all 0.2s;
        }

        .tab-btn:last-child { border-right: none; }
        .tab-btn svg { width: 1rem; height: 1rem; fill: currentColor; }
        .tab-btn:hover { color: var(--text-main); background: rgba(15,157,203,0.05); }
        .tab-btn.active { background: var(--tab-active-bg); color: #fff; }

        .main-container {
            width: 100%;
            background: var(--bg-card);
            border-radius: 0.875rem;
            border: 0.0625rem solid var(--border);
            box-shadow: 0 0.5rem 1.5rem rgba(0,0,0,0.65);
            overflow: hidden;
            min-height: 18rem;
        }

        .tab-content { display: none; padding: 0.875rem; }
        .tab-content.active { display: block; }
        .tab-content.slide-from-right { animation: slideInRight 0.25s cubic-bezier(0.25, 1, 0.5, 1) forwards; }
        .tab-content.slide-from-left { animation: slideInLeft 0.25s cubic-bezier(0.25, 1, 0.5, 1) forwards; }

        @keyframes slideInRight {
            from { opacity: 0.2; transform: translateX(1.5rem); }
            to { opacity: 1; transform: translateX(0); }
        }
        @keyframes slideInLeft {
            from { opacity: 0.2; transform: translateX(-1.5rem); }
            to { opacity: 1; transform: translateX(0); }
        }

        /* Badge Contador nas Abas */
        .tab-count-badge {
            background: rgba(15, 157, 203, 0.25);
            color: var(--accent);
            font-size: 0.5625rem;
            font-weight: 700;
            border-radius: 0.75rem;
            padding: 0.0625rem 0.3125rem;
            min-width: 0.875rem;
            text-align: center;
            border: 0.0625rem solid var(--border-light);
            line-height: 1;
            display: inline-block;
        }

        .tab-btn.active .tab-count-badge {
            background: #000;
            color: var(--accent);
            border-color: var(--accent);
        }

        /* Indicador de Status da Conexão */
        .connection-status-badge {
            display: flex;
            align-items: center;
            gap: 0.375rem;
            background: var(--bg-input);
            border: 0.0625rem solid var(--border);
            border-radius: 1rem;
            padding: 0.25rem 0.625rem;
            font-size: 0.625rem;
            font-weight: 700;
            color: var(--text-main);
            margin-left: auto;
        }

        .status-dot {
            width: 0.5rem;
            height: 0.5rem;
            border-radius: 50%;
            display: inline-block;
        }

        .status-dot.online {
            background: var(--online);
            box-shadow: 0 0 0.375rem var(--online);
        }

        .status-dot.offline {
            background: var(--offline);
            box-shadow: 0 0 0.375rem var(--offline);
        }

        /* Caixa de Pesquisa em Listas */
        .list-search-box {
            display: flex;
            align-items: center;
            background: var(--bg-input);
            border: 0.0625rem solid var(--border);
            border-radius: 0.5rem;
            padding: 0.375rem 0.625rem;
            margin-bottom: 0.75rem;
            gap: 0.375rem;
