        }

        .list-search-box:focus-within {
            border-color: var(--accent);
        }

        .list-search-box svg {
            width: 0.875rem;
            height: 0.875rem;
            fill: var(--text-dim);
            flex-shrink: 0;
        }

        .list-search-box input {
            background: transparent;
            border: none;
            color: var(--text-main);
            font-size: 0.75rem;
            width: 100%;
