            background: rgba(181, 251, 42, 0.1);
            color: var(--accent);
        }

        .items-grid {
            display: grid;
            grid-template-columns: repeat(auto-fill, minmax(6rem, 1fr));
            gap: 0.625rem;
            max-height: 22rem;
            overflow-y: auto;
            padding: 0.25rem;
            margin-bottom: 0.875rem;
        }

        .item-card {
            background: var(--bg-card-2);
            border: 0.0625rem solid var(--border);
            border-radius: 0.625rem;
            overflow: hidden;
            position: relative;
            cursor: pointer;
            display: flex;
            flex-direction: column;
            transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
            animation: fadeInUp 0.4s ease-out;
        }

        .item-card:hover { 
            border-color: var(--border-light);
            transform: translateY(-2px);
            box-shadow: 0 0.5rem 1rem rgba(0,0,0,0.3);
        }

        .item-card.selected {
            border-color: var(--accent);
            box-shadow: 0 0 0 0.125rem var(--accent);
        }

        .item-card .preview {
            aspect-ratio: 1/1;
            background: var(--bg-input);
            display: flex;
            align-items: center;
            justify-content: center;
            color: var(--text-dim);
            font-size: 0.625rem;
            padding: 0;
            text-align: center;
            word-break: break-word;
            position: relative;
            overflow: hidden;
        }

        .item-card .preview img,
        .item-card .preview video { 
            width: 100%; 
            height: 100%; 
            object-fit: cover; 
            display: block;
        }

        .modal-preview-container {
            width: 100%;
            background: #000;
            border-radius: 0.5rem;
            overflow: hidden;
            display: flex;
            align-items: center;
            justify-content: center;
            margin-bottom: 0.75rem;
            border: 0.0625rem solid var(--border);
        }

        .modal-preview-container img,
        .modal-preview-container video {
            max-width: 100%;
            max-height: 15rem;
            object-fit: contain;
            display: block;
        }

        .item-card .meta {
            background: linear-gradient(180deg, transparent, rgba(0,0,0,0.85));
            padding: 0.25rem 0.375rem;
            font-size: 0.5625rem;
            font-weight: 600;
            color: var(--accent);
        }

        .item-card .meta-row {
            display: flex;
            align-items: center;
            gap: 0.1875rem;
            color: var(--gold);
            font-size: 0.5rem;
        }

        .item-card .item-check {
            position: absolute;
            top: 0.25rem;
            right: 0.25rem;
            width: 1.125rem;
            height: 1.125rem;
            border-radius: 50%;
            background: rgba(0,0,0,0.6);
            border: 0.125rem solid var(--border-light);
            display: none;
            align-items: center;
            justify-content: center;
            z-index: 3;
        }

        .multiselect-mode .item-card .item-check { display: flex; }

        .item-card.selected .item-check {
            background: var(--accent);
            border-color: var(--accent);
        }

        .item-card .item-check svg {
            width: 0.75rem;
            height: 0.75rem;
            fill: #000;
            opacity: 0;
        }

        .item-card.selected .item-check svg { opacity: 1; }

        .item-card-actions {
            display: flex;
            justify-content: center;
            gap: 0.5rem;
            padding: 0.375rem;
            background: rgba(0,0,0,0.4);
            border-top: 0.0625rem solid var(--border);
        }

        .action-btn {
            width: 1.75rem;
            height: 1.75rem;
            border-radius: 0.375rem;
            background: var(--bg-card-2);
            border: 0.0625rem solid var(--border);
            display: flex;
            align-items: center;
            justify-content: center;
            cursor: pointer;
            transition: all 0.2s ease;
            color: var(--text-dim);
        }

        .action-btn:hover {
            background: var(--accent);
            color: #000;
            border-color: var(--accent);
            transform: scale(1.1);
        }

        .action-btn svg {
            width: 1rem;
            height: 1rem;
            fill: currentColor;
        }

        .action-btn.schedule-btn {
            color: var(--primary);
        }

        .action-btn.schedule-btn:hover {
            background: var(--primary);
            color: #fff;
        }

        .schedule-info {
            padding: 0.25rem 0.375rem;
            font-size: 0.625rem;
            color: var(--primary);
            text-align: center;
            background: rgba(15,157,203,0.1);
            border-top: 0.0625rem solid rgba(15,157,203,0.3);
        }

        .list-container {
            max-height: 20rem;
            overflow-y: auto;
            margin-bottom: 0.875rem;
        }

        .list-item {
            background: var(--bg-card-2);
            border: 0.0625rem solid var(--border);
            border-radius: 0.5rem;
            padding: 0.625rem;
            margin-bottom: 0.5rem;
            position: relative;
            cursor: pointer;
            transition: all 0.2s;
        }

        .list-item:hover { border-color: var(--border-light); }

        .list-item.selected {
            border-color: var(--accent);
            background: rgba(181,251,42,0.08);
        }

        .list-item.has-schedule {
            border-left: 0.25rem solid var(--primary);
        }

        .list-item.in-multiselect { cursor: crosshair; }

        .list-item .list-header {
            display: flex;
            align-items: flex-start;
            justify-content: space-between;
            gap: 0.375rem;
            margin-bottom: 0.25rem;
        }

        .list-item .list-type {
            color: var(--accent);
            font-size: 0.625rem;
            font-weight: 700;
            letter-spacing: 0.0625rem;
        }

        .list-item .list-title {
            font-weight: 600;
            font-size: 0.8125rem;
            color: var(--text-main);
            word-break: break-word;
            margin-bottom: 0.1875rem;
        }

        .list-item .list-meta {
            font-size: 0.6875rem;
            color: var(--text-dim);
        }

        .list-item .list-check {
            position: absolute;
            top: 0.5rem;
            right: 0.5rem;
            width: 1.125rem;
            height: 1.125rem;
            border-radius: 50%;
            background: rgba(0,0,0,0.6);
            border: 0.125rem solid var(--border-light);
            display: none;
            align-items: center;
            justify-content: center;
            z-index: 3;
        }

        .multiselect-mode .list-item .list-check { display: flex; }

        .list-item.selected .list-check {
            background: var(--accent);
            border-color: var(--accent);
        }

        .list-item .list-check svg {
            width: 0.75rem;
            height: 0.75rem;
            fill: #000;
            opacity: 0;
        }

        .list-item.selected .list-check svg { opacity: 1; }

        .tab-multiselect-controls {
            display: none;
            gap: 0.5rem;
            margin-bottom: 1rem;
            animation: fadeIn 0.3s ease;
        }

        .tab-multiselect-controls.show {
            display: flex;
        }

        .ms-btn {
            flex: 1;
            background: var(--bg-card-2);
            border: 0.0625rem solid var(--border);
            border-radius: 0.375rem;
            color: var(--text-dim);
            font-size: 0.625rem;
            font-weight: 600;
            padding: 0.5rem 0.25rem;
            cursor: pointer;
            display: flex;
            align-items: center;
            justify-content: center;
            gap: 0.25rem;
            transition: all 0.2s;
            text-transform: uppercase;
            letter-spacing: 0.02rem;
            white-space: nowrap;
        }

        .ms-btn:hover {
            background: var(--primary-dark);
            color: #fff;
            border-color: var(--primary);
        }

        .ms-btn.danger {
            color: #ff4d4d;
            border-color: rgba(255, 77, 77, 0.3);
        }

        .ms-btn.danger:hover {
            background: #ff4d4d;
            color: #fff;
            border-color: #ff4d4d;
        }

        .submit-btn {
            width: 100%;
            padding: 0.75rem;
            background: var(--accent);
            color: #000;
            border: none;
            border-radius: 0.625rem;
            font-weight: 800;
            font-size: 0.875rem;
            cursor: pointer;
            display: flex;
            align-items: center;
            justify-content: center;
            gap: 0.375rem;
            transition: all 0.3s ease;
        }

        .submit-btn:hover { 
            background: var(--accent-dark);
            transform: translateY(-2px);
            box-shadow: 0 0.25rem 0.75rem rgba(181,251,42,0.3);
        }
        .submit-btn:active { transform: translateY(0) scale(0.98); }
        .submit-btn:disabled { opacity: 0.5; cursor: not-allowed; transform: none; }
        .submit-btn svg { width: 1rem; height: 1rem; fill: #000; }
        .submit-btn.hidden { display: none !important; }

        .terminal-panel {
            width: 100%;
            background: var(--bg-card);
            border-radius: 0.875rem;
            border: 0.0625rem solid var(--border);
            box-shadow: 0 0.5rem 1.5rem rgba(0,0,0,0.65);
            overflow: hidden;
            margin-top: 0.375rem;
            transition: all 0.3s ease;
        }

        .terminal-panel.minimized .terminal-body {
            display: none;
        }

        .terminal-window-controls {
            display: flex;
            gap: 0.375rem;
            align-items: center;
            margin-left: auto;
        }

        .window-btn {
            width: 1.75rem;
            height: 1.75rem;
            border: none;
            border-radius: 0.25rem;
            background: transparent;
            color: var(--text-dim);
            cursor: pointer;
            display: flex;
            align-items: center;
            justify-content: center;
            transition: all 0.2s ease;
            padding: 0;
        }

        .window-btn:hover {
            background: rgba(255,255,255,0.1);
            color: var(--text-main);
        }

        .window-btn.minimize:hover {
            background: rgba(181,251,42,0.15);
            color: var(--accent);
        }

        .window-btn svg {
            width: 1rem; height: 1rem;
            fill: currentColor;
        }

        .window-btn.minimize svg {
            transform: translateY(0.25rem);
        }

        .terminal-header {
            user-select: none;
            padding: 0.5rem 1rem;
            background: rgba(0,0,0,0.4);
            border-bottom: 0.0625rem solid var(--border);
            display: flex;
            align-items: center;
            gap: 0.5rem;
        }

        .terminal-header h3 {
            color: var(--accent);
            font-size: 0.8125rem;
            font-weight: 700;
            margin: 0;
            display: flex;
            align-items: center;
            gap: 0.375rem;
            flex-shrink: 0;
        }

        .terminal-header h3::before {
            content: '●';
            color: var(--success);
            animation: blink 1.5s infinite;
        }

        @keyframes blink { 50% { opacity: 0.3; } }

        .btn-clear {
            background: transparent;
            border: 0.0625rem solid var(--border);
            color: var(--text-dim);
            padding: 0.1875rem 0.625rem;
            border-radius: 0.375rem;
            font-size: 0.6875rem;
            cursor: pointer;
        }

        .terminal-body {
            padding: 0.5rem 1rem;
            max-height: 10rem;
            overflow-y: auto;
            font-family: 'Courier New', monospace;
            font-size: 0.6875rem;
            line-height: 1.5;
        }

        .log-entry {
            padding: 0.1875rem 0;
            border-bottom: 0.0625rem solid rgba(15,80,122,0.3);
            word-break: break-all;
        }

        .log-entry:last-child { border-bottom: none; }
        .log-time { color: var(--text-dim); }
        .log-info { color: var(--primary); }
        .log-success { color: var(--accent); }
        .log-error { color: var(--btn-no); }
        .log-warn { color: var(--gold); }

        .form-group { margin-bottom: 0.75rem; }
        .form-group label { display: block; font-size: 0.75rem; font-weight: 600; margin-bottom: 0.25rem; }

        .form-group input[type="text"],
        .form-group input[type="number"],
        .form-group textarea,
        .form-group select {
            width: 100%;
            padding: 0.5rem 0.75rem;
            background: var(--bg-input);
            border: 0.0625rem solid var(--border);
            border-radius: 0.5rem;
            color: var(--text-main);
            font-size: 0.8125rem;
            font-family: inherit;
        }

        .form-group input:focus, .form-group textarea:focus, .form-group select:focus {
            outline: none;
            border-color: var(--accent);
        }

        .form-group textarea { resize: vertical; min-height: 3rem; }

        .auto-expand {
            overflow: hidden;
            min-height: 2.5rem;
            max-height: 13rem;
            line-height: 1.5;
            resize: none;
            box-sizing: border-box;
            transition: none;
        }

        .auto-expand:focus {
            overflow-y: auto;
        }

        .toggle-row {
            display: flex;
            align-items: center;
            justify-content: space-between;
            padding: 0.375rem 0;
            font-size: 0.8125rem;
        }

        .toggle-switch {
            position: relative;
            width: 2.25rem;
            height: 1.25rem;
            background: var(--bg-input);
            border-radius: 1rem;
            border: 0.0625rem solid var(--border);
            cursor: pointer;
        }

        .toggle-switch.on { background: var(--accent); border-color: var(--accent); }

        .toggle-switch::after {
            content: '';
            position: absolute;
            top: 0.125rem; left: 0.125rem;
            width: 0.875rem; height: 0.875rem;
            background: #fff;
            border-radius: 50%;
            transition: left 0.2s;
        }

        .toggle-switch.on::after { left: 1.125rem; }

        .modal-overlay {
            position: fixed;
            inset: 0;
            background: rgba(0,0,0,0.85);
            display: none;
            align-items: center;
            justify-content: center;
            padding: 3vw;
            z-index: 200;
        }

        .modal-overlay.show { 
            display: flex;
            animation: fadeIn 0.2s ease-out;
        }

        .modal {
            animation: slideUp 0.3s cubic-bezier(0.4, 0, 0.2, 1);
            background: var(--bg-card);
            border: 0.0625rem solid var(--border);
            border-radius: 0.875rem;
            max-width: 28rem;
            width: 100%;
            max-height: 90vh;
            overflow-y: auto;
            box-shadow: 0 1.5rem 3rem rgba(0,0,0,0.7);
        }

        @keyframes slideUp {
            from { opacity: 0; transform: translateY(2rem); }
            to { opacity: 1; transform: translateY(0); }
        }

        .modal-header {
            padding: 0.75rem 1rem;
            background: rgba(0,0,0,0.4);
            border-bottom: 0.0625rem solid var(--border);
            display: flex;
            justify-content: space-between;
            align-items: center;
        }

        .modal-header h3 { color: var(--accent); font-size: 0.9375rem; font-weight: 700; }

        .modal-close {
            background: transparent;
            border: none;
            color: var(--text-dim);
            font-size: 1.25rem;
            cursor: pointer;
            line-height: 1;
        }

        .modal-body { padding: 1rem; }

        .modal-footer {
            padding: 0.75rem 1rem;
            border-top: 0.0625rem solid var(--border);
            display: flex;
            gap: 0.5rem;
        }

        .btn-action {
            flex: 1;
            padding: 0.5rem 0.75rem;
            border: none;
            border-radius: 0.5rem;
            font-size: 0.8125rem;
            font-weight: 600;
            cursor: pointer;
        }

        .btn-no { background: var(--btn-no); color: white; }
        .btn-yes { background: var(--accent); color: #000; }
        .btn-primary { background: var(--primary); color: white; }
        .btn-action:hover { opacity: 0.9; }

        .picker-search {
            width: 100%;
            padding: 0.5rem 0.75rem;
            background: var(--bg-input);
            border: 0.0625rem solid var(--border);
            border-radius: 0.5rem;
            color: var(--text-main);
            font-size: 0.8125rem;
            margin-bottom: 0.5rem;
        }

        .suffix-picker {
            display: flex;
            gap: 0.375rem;
            flex-wrap: wrap;
            margin-bottom: 0.5rem;
        }

        .suffix-chip {
            padding: 0.5rem 0.875rem;
            background: var(--bg-input);
            border: 0.0625rem solid var(--border);
            border-radius: 0.5rem;
            color: var(--text-dim);
            font-size: 0.75rem;
            font-weight: 600;
            cursor: pointer;
            transition: all 0.2s;
            display: flex;
            align-items: center;
            gap: 0.375rem;
        }

        .suffix-chip:hover { border-color: var(--accent); color: var(--text-main); }
        .suffix-chip.active {
            background: var(--accent);
            color: #000;
            border-color: var(--accent);
        }

        .device-picker {
            display: flex;
            flex-direction: column;
            gap: 0.375rem;
            margin-top: 0.375rem;
            max-height: 14rem;
            overflow-y: auto;
            padding-right: 0.25rem;
        }

        .device-picker::-webkit-scrollbar { width: 0.375rem; }
        .device-picker::-webkit-scrollbar-track { background: var(--bg-input); border-radius: 0.25rem; }
        .device-picker::-webkit-scrollbar-thumb { background: var(--border); border-radius: 0.25rem; }

        .device-chip {
            padding: 0.5rem 0.625rem;
            background: var(--bg-input);
            border: 0.0625rem solid var(--border);
            border-radius: 0.5rem;
            color: var(--text-dim);
            font-size: 0.6875rem;
            font-weight: 600;
            cursor: pointer;
            transition: all 0.2s;
            display: flex;
            align-items: center;
            gap: 0.5rem;
            white-space: nowrap;
            overflow: hidden;
            text-overflow: ellipsis;
        }

        .device-chip:hover { border-color: var(--primary); color: var(--text-main); }
        .device-chip.active { background: var(--primary); color: #fff; border-color: var(--primary); }

        .device-chip .device-avatar {
            width: 1.25rem; height: 1.25rem;
            border-radius: 50%;
            background: var(--bg-card-2);
            flex-shrink: 0;
            display: flex; align-items: center; justify-content: center;
            overflow: hidden;
        }

        .device-chip .device-avatar img { width: 100%; height: 100%; object-fit: cover; }

        .device-chip .device-status {
            width: 0.375rem; height: 0.375rem;
            border-radius: 50%;
            flex-shrink: 0;
            margin-left: auto;
        }

        .device-chip .device-status.online { background: #4ade80; }
        .device-chip .device-status.offline { background: #f87171; }

        .duration-picker {
            display: flex;
            flex-wrap: wrap;
            gap: 0.375rem;
            margin-top: 0.375rem;
        }

        .duration-chip {
            flex: 1;
            min-width: calc(50% - 0.1875rem);
            padding: 0.5rem 0.625rem;
            background: var(--bg-input);
            border: 0.0625rem solid var(--border);
            border-radius: 0.5rem;
            color: var(--text-dim);
            font-size: 0.6875rem;
            font-weight: 600;
            cursor: pointer;
            transition: all 0.2s;
            display: flex;
            align-items: center;
            justify-content: center;
            gap: 0.375rem;
            text-align: center;
        }

        .duration-chip:hover { border-color: var(--primary); color: var(--primary); }
        .duration-chip.active { background: var(--primary); color: #fff; border-color: var(--primary); }
        .duration-chip svg { width: 0.875rem; height: 0.875rem; fill: currentColor; }

        .validation-alert {
            padding: 0.5rem 0.75rem;
            background: rgba(255,82,82,0.12);
            border: 0.0625rem solid rgba(255,82,82,0.4);
            border-radius: 0.5rem;
            color: #ff6b6b;
            font-size: 0.75rem;
            font-weight: 600;
            display: flex;
            align-items: center;
            gap: 0.375rem;
            margin-top: 0.375rem;
            animation: shakeAlert 0.4s ease;
        }

        .validation-alert svg { width: 0.875rem; height: 0.875rem; fill: currentColor; flex-shrink: 0; }

        .recipients-section {
            background: var(--bg-card-2);
            border: 0.0625rem solid var(--border);
            border-radius: 0.625rem;
            padding: 0.75rem;
            margin-bottom: 0.75rem;
        }

        .recipients-list {
            max-height: calc(5 * 4.5rem + 0.5rem);
            overflow-y: auto;
            padding-right: 0.25rem;
        }

        .recipients-header {
            display: flex;
            justify-content: space-between;
            align-items: center;
            margin-bottom: 0.625rem;
        }

        .recipients-header-title {
            font-size: 0.6875rem;
            font-weight: 700;
            color: var(--text-dim);
            letter-spacing: 0.05rem;
            text-transform: uppercase;
        }

        .btn-add-recipient {
            background: var(--primary);
            color: #fff;
            border: none;
            padding: 0.375rem 0.75rem;
            border-radius: 0.5rem;
            font-size: 0.75rem;
            font-weight: 600;
            cursor: pointer;
            display: flex;
            align-items: center;
            gap: 0.25rem;
        }

        .btn-add-recipient:hover { background: var(--primary-dark); }

        .recipient-box {
            background: var(--bg-input);
            border: 0.0625rem solid var(--border);
            border-radius: 0.625rem;
            padding: 0.5rem;
            padding-right: 2rem;
            margin-bottom: 0.5rem;
            position: relative;
            display: flex;
            gap: 0.375rem;
            align-items: center;
        }

        .recipient-box input[type="text"] {
            flex: 1;
            min-width: 0;
            padding: 0.5rem;
            background: transparent;
            border: 0.0625rem solid var(--border);
            border-radius: 0.375rem;
            color: var(--text-main);
            font-size: 0.8125rem;
        }

        .recipient-box input[type="text"]:focus { outline: none; border-color: var(--accent); }

        .suffix-selector { position: relative; flex-shrink: 0; }

        .suffix-selector-btn {
            padding: 0.5rem 0.625rem;
            background: var(--bg-card-2);
            border: 0.0625rem solid var(--border);
            border-radius: 0.375rem;
            color: var(--text-main);
            font-size: 0.75rem;
            cursor: pointer;
            min-width: 6rem;
            display: flex;
            justify-content: space-between;
            align-items: center;
            gap: 0.25rem;
        }

        .suffix-selector-btn:hover { border-color: var(--accent); }
        .suffix-selector-btn::after { content: '▾'; font-size: 0.625rem; }

        .suffix-dropdown {
            position: fixed;
            background: #000;
            border: 0.0625rem solid var(--border);
            border-radius: 0.5rem;
            z-index: 1000;
            min-width: 9rem;
            overflow: hidden;
            display: none;
            box-shadow: 0 0.5rem 1rem rgba(0,0,0,0.5);
        }

        .suffix-dropdown.show { display: block; }

        .suffix-option {
            padding: 0.625rem 0.75rem;
            display: flex;
            justify-content: space-between;
            align-items: center;
            cursor: pointer;
            border-bottom: 0.0625rem solid rgba(15,80,122,0.3);
            font-size: 0.8125rem;
        }

        .suffix-option:hover { background: var(--bg-card-2); }
        .suffix-option:last-child { border-bottom: none; }
        .suffix-option.active { color: var(--accent); }

        .suffix-radio {
            width: 1rem; height: 1rem;
            border-radius: 50%;
            border: 0.125rem solid var(--border);
            display: flex; align-items: center; justify-content: center;
        }

        .suffix-option.active .suffix-radio::after {
            content: '';
            width: 0.5rem; height: 0.5rem;
            border-radius: 50%;
            background: var(--accent);
        }

        .recipient-search-btn {
            width: 2rem; height: 2rem;
            background: var(--bg-card-2);
            border: 0.0625rem solid var(--border);
            border-radius: 0.375rem;
            display: flex; align-items: center; justify-content: center;
            cursor: pointer; color: var(--primary); flex-shrink: 0;
        }

        .recipient-search-btn:hover { border-color: var(--primary); background: rgba(15,157,203,0.1); }

        .recipient-remove-btn {
            position: absolute;
            top: 0.375rem; right: 0.375rem;
            width: 1.25rem; height: 1.25rem;
            background: var(--btn-no);
            border: none; border-radius: 50%;
            color: #fff; cursor: pointer;
            display: flex; align-items: center; justify-content: center;
            font-size: 0.6875rem; font-weight: 700;
            z-index: 2; line-height: 1; padding: 0;
        }

        .recipient-remove-btn:hover { background: #ff6666; transform: scale(1.1); }

        .recipient-search-results {
            position: absolute;
            top: 100%; left: 0; right: 0;
            background: #000;
            border: 0.0625rem solid var(--primary);
            border-radius: 0.5rem;
            z-index: 200;
            max-height: 10rem;
            overflow-y: auto;
            display: none;
            margin-top: 0.25rem;
        }

        .recipient-search-results.show { display: block; }

        .search-result-item {
            padding: 0.5rem 0.75rem;
            cursor: pointer;
            border-bottom: 0.0625rem solid rgba(15,80,122,0.3);
        }

        .search-result-item:hover { background: var(--bg-card-2); }
        .search-result-name { font-size: 0.8125rem; font-weight: 600; color: var(--text-main); }
        .search-result-phone { font-size: 0.6875rem; color: var(--text-dim); }

        .schedule-section {
            background: var(--bg-card-2);
            border: 0.0625rem solid var(--border);
            border-radius: 0.75rem;
            padding: 1rem;
            margin-bottom: 1rem;
        }

        .schedule-title {
            font-size: 0.875rem;
            font-weight: 700;
            color: var(--text-main);
            margin-bottom: 0.75rem;
            text-transform: uppercase;
            letter-spacing: 0.05rem;
        }

        .days-grid {
            display: grid;
            grid-template-columns: repeat(7, 1fr);
            gap: 0.375rem;
        }

        .day-chip {
            padding: 0.625rem 0.25rem;
            background: var(--bg-input);
            border: 0.0625rem solid var(--border);
            border-radius: 0.5rem;
            color: var(--text-dim);
            font-size: 0.6875rem;
            font-weight: 700;
            cursor: pointer;
            text-align: center;
            transition: all 0.2s;
        }

        .day-chip:hover { border-color: var(--accent); color: var(--text-main); }
        .day-chip.active { background: var(--accent); color: #000; border-color: var(--accent); }

        .times-list { display: flex; flex-direction: column; gap: 0.5rem; margin-bottom: 0.5rem; }

        .time-item {
            display: flex;
            align-items: center;
            gap: 0.5rem;
            background: var(--bg-input);
            padding: 0.5rem 0.75rem;
            border-radius: 0.5rem;
            border: 0.0625rem solid var(--border);
        }

        .time-item input[type="time"] {
            flex: 1;
            background: transparent;
            border: none;
            color: var(--text-main);
            font-size: 0.875rem;
            font-family: inherit;
        }

        .time-item input[type="time"]:focus { outline: none; }

