function showRecipientsAlert(alertId) {
    const alertEl = document.getElementById(alertId);
    if (alertEl) {
        alertEl.style.display = 'flex';
        setTimeout(() => { alertEl.style.display = 'none'; }, 3500);
    }
}

function hideRecipientsAlert(alertId) {
    const alertEl = document.getElementById(alertId);
    if (alertEl) alertEl.style.display = 'none';
}

function selectDuration(pickerName, value, el) {
    const picker = document.getElementById(pickerName + 'Picker');
    if (!picker) return;
    picker.querySelectorAll('.duration-chip').forEach(c => c.classList.remove('active'));
    if (el) el.classList.add('active');
    else {
        const chip = picker.querySelector(`.duration-chip[data-value="${value}"]`);
        if (chip) chip.classList.add('active');
    }
    // Esconde alertas de validação
    const alertEl = document.getElementById(pickerName + 'Alert');
    if (alertEl) alertEl.style.display = 'none';
}

function getDuration(pickerName) {
    const picker = document.getElementById(pickerName + 'Picker');
    if (!picker) return 0;
    const active = picker.querySelector('.duration-chip.active');
    return active ? parseInt(active.dataset.value) : 0;
}

function showValidationAlert(alertId, message) {
    const alertEl = document.getElementById(alertId);
    if (!alertEl) return;
    alertEl.innerHTML = `<svg viewBox="0 0 24 24"><path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm1 15h-2v-2h2v2zm0-4h-2V7h2v6z"/></svg><span>${message}</span>`;
    alertEl.style.display = 'flex';
    setTimeout(() => { alertEl.style.display = 'none'; }, 4000);
}

function hideValidationAlert(alertId) {
    const alertEl = document.getElementById(alertId);
    if (alertEl) alertEl.style.display = 'none';
}

/* ====== DEVICE PICKER (multi-select) ====== */
function selectDevice(pickerName, deviceId, el) {
    if (!el) return;

    const picker = el.closest('.device-picker');
    if (!picker) return;

    // Verifica quantos estão ativos
    const activeCount = picker.querySelectorAll('.device-chip.active').length;
    const isCurrentlyActive = el.classList.contains('active');

    // Não permite desmarcar o último
    if (isCurrentlyActive && activeCount <= 1) {
        log('warn', 'Deve haver pelo menos um dispositivo selecionado.');
        return;
    }

    // Toggle
    el.classList.toggle('active');

    // Esconde alerta
    const alertEl = document.getElementById(pickerName + 'DeviceAlert');
    if (alertEl) alertEl.style.display = 'none';
}

// Retorna array de objetos { device_id, device_phone } dos dispositivos selecionados
function getSelectedDeviceIds(pickerName) {
    const picker = document.getElementById(pickerName + 'DevicePicker');
    if (!picker) return [];
    const devices = [];
    picker.querySelectorAll('.device-chip.active').forEach(c => {
        const device = STATE.devices.find(d => d.id === c.dataset.device);
        if (device) {
            devices.push({
                device_id: device.id,
                device_phone: (device.phone || '').replace(/@s\.whatsapp\.net$/, '')
            });
        }
    });
    return devices;
}

// Helper para obter só os IDs (para compatibilidade)
function getSelectedDeviceIdsOnly(pickerName) {
    return getSelectedDeviceIds(pickerName).map(d => d.device_id);
}

// Extrai lista de { device_id, device } para uso no envio, com fallback para seleção global
function getDeviceListForSend(deviceIds) {
    let ids = deviceIds;
    if (!ids || (Array.isArray(ids) && ids.length === 0)) {
        ids = Array.from(STATE.selectedDeviceIds);
    }
    return normalizeDeviceIds(ids).map(devInfo => {
        const deviceId = devInfo.device_id || devInfo;
        const device = STATE.devices.find(d => d.id === deviceId);
        return { deviceId, device };
    }).filter(d => d.device !== null);
}

// Normaliza device_ids para o novo formato (array de objetos)
function normalizeDeviceIds(deviceIds) {
    if (!Array.isArray(deviceIds)) return [];
    return deviceIds.map(d => {
        if (typeof d === 'object' && d !== null && d.device_id) {
            return d;
        }
        // Se for string (formato antigo), converte
        const device = STATE.devices.find(dev => dev.id === d);
        if (device) {
            return {
                device_id: device.id,
                device_phone: (device.phone || '').replace(/@s\.whatsapp\.net$/, '')
            };
        }
        return { device_id: d, device_phone: '' };
    });
}

function getDeviceAvatar(deviceId) {
    // Retorna o avatar do dispositivo do STATE se disponível
    const device = STATE.devices.find(d => d.id === deviceId);
    if (device && device.avatar) return device.avatar;
    // Avatar padrão
    return 'data:image/svg+xml;base64,PHN2ZyB4bWxucz0iaHR0cDovL3d3dy53My5vcmcvMjAwMC9zdmciIHZpZXdCb3g9IjAgMCAyNCAyNCIgZmlsbD0iI2ZmZiI+PHBhdGggZD0iTTEyIDEyYzIuMjEgMCA0LTEuNzkgNC00cy0xLjc5LTQtNC00LTQgMS43OS00IDQgMS43OSA0IDQgNHptMCAyYy0yLjY3IDAtOCAxLjM0LTggNHYyaDE2di0yYzAtMi42Ni01LjMzLTQtOC00eiIvPjwvc3ZnPg==';
}

function populateDevicePicker(pickerName, selectedDevices = []) {
    const picker = document.getElementById(pickerName + 'DevicePicker');
    if (!picker) return;

    const devices = STATE.devices || [];

    // Remove alerta anterior se existir
    const oldAlert = document.getElementById(pickerName + 'DeviceAlert');
    if (oldAlert) oldAlert.remove();

    // Se não há dispositivos, mostra mensagem
    if (devices.length === 0) {
        picker.innerHTML = '<div style="font-size:0.6875rem; color:var(--text-dim); padding:0.375rem;">Nenhum dispositivo disponível</div>';
        picker.insertAdjacentHTML('afterend', `
            <div id="${pickerName}DeviceAlert" class="validation-alert" style="display:none;">
                <svg viewBox="0 0 24 24"><path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm1 15h-2v-2h2v2zm0-4h-2V7h2v6z"/></svg>
                <span>Selecione pelo menos um dispositivo</span>
            </div>
        `);
        return;
    }

    // Normaliza entrada (aceita array de IDs strings ou array de objetos)
    let activeIds = [];
    if (Array.isArray(selectedDevices)) {
        selectedDevices.forEach(d => {
            if (typeof d === 'object' && d !== null && d.device_id) {
                activeIds.push(d.device_id);
            } else if (typeof d === 'string') {
                activeIds.push(d);
            }
        });
    }

    // Se só há 1 dispositivo e nenhum foi especificado, seleciona automaticamente
    if (activeIds.length === 0 && devices.length === 1) {
        activeIds = [devices[0].id];
    }

    picker.innerHTML = devices.map(d => {
        const phone = (d.phone || '').replace(/@s\.whatsapp\.net$/, '') || 'Sem número';
        const name = d.name || 'Dispositivo';
        const isActive = activeIds.includes(d.id) ? 'active' : '';
        const statusClass = d.online ? 'online' : 'offline';
        const avatar = getDeviceAvatar(d.id);
        return `
            <button type="button" class="device-chip ${isActive}" data-device="${d.id}" onclick="selectDevice('${pickerName}', '${d.id}', this)">
                <span class="device-avatar"><img src="${avatar}" onerror="this.style.display='none'"></span>
                <span style="overflow:hidden; text-overflow:ellipsis;">${escapeHtml(phone)}${name !== phone ? ` · ${escapeHtml(name)}` : ''}</span>
                <span class="device-status ${statusClass}"></span>
            </button>
        `;
    }).join('');

    // Adiciona alerta após o picker
    picker.insertAdjacentHTML('afterend', `
        <div id="${pickerName}DeviceAlert" class="validation-alert" style="display:none;">
            <svg viewBox="0 0 24 24"><path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm1 15h-2v-2h2v2zm0-4h-2V7h2v6z"/></svg>
            <span>Selecione pelo menos um dispositivo</span>
        </div>
    `);
}

function showDevicePickerAlert(pickerName) {
    const alertEl = document.getElementById(pickerName + 'DeviceAlert');
    if (alertEl) {
        alertEl.style.display = 'flex';
        setTimeout(() => { alertEl.style.display = 'none'; }, 4000);
    }
}

function handleStatusFile(e) {
    const file = e.target.files[0];
    if (!file) return;
    STATE._pendingStatusPath = file.path || file.name || '';
    const reader = new FileReader();
    reader.onload = ev => {
        document.getElementById('statusPreview').style.display = 'block';
        if (file.type.startsWith('image/')) {
            document.getElementById('statusImgPreview').src = ev.target.result;
            document.getElementById('statusImgPreview').style.display = 'block';
            document.getElementById('statusVidPreview').style.display = 'none';
        } else {
            document.getElementById('statusVidPreview').src = ev.target.result;
            document.getElementById('statusVidPreview').style.display = 'block';
            document.getElementById('statusImgPreview').style.display = 'none';
        }
    };
    reader.readAsDataURL(file);
}

async function confirmAddStatus() {
    const type = STATE._pendingStatusType;
    const caption = document.getElementById('statusCaption').value.trim();
    const message = document.getElementById('statusMessage').value.trim();
    const schedule = STATE._pendingStatusSchedule || { times: [], days: [] };
    if (type === 'text' && !message) {
        showValidationAlert('statusMessageAlert', 'Digite uma mensagem');
        log('error', 'Digite a mensagem.');
        return;
    }
    const item = { type, caption: type !== 'text' ? caption : undefined, message: type === 'text' ? message : undefined, path: STATE._pendingStatusPath || '', schedule };
    STATE.statusItems.push(item);
    saveStatusFile();
    log('success', `Status ${type} adicionado.`);
    closeModal('addStatusModal');
    renderStatus();
}

function filterStatus(filter, el) {
    STATE.statusFilter = filter;
    document.querySelectorAll('#tab-status .chip').forEach(c => c.classList.remove('active'));
    if (el) el.classList.add('active');
    renderStatus();
    updateSendTypesVisibility();
}

function renderStatus() {
    updateTabCounters();
    const grid = document.getElementById('statusGrid');
    if (!grid) return;
    let items = STATE.statusItems || [];
    if (STATE.statusFilter !== 'all') items = items.filter(i => i.type === STATE.statusFilter);
    const q = STATE.searchQueries?.status;
    if (q) {
        items = items.filter(i => 
            (i.caption || '').toLowerCase().includes(q) ||
            (i.message || '').toLowerCase().includes(q) ||
            (i.path || '').toLowerCase().includes(q)
        );
    }
    if (items.length === 0) { 
        grid.innerHTML = '<div class="empty-state" style="grid-column:1/-1;">Nenhum status encontrado.</div>'; 
        updateSendTypesVisibility(); 
        return; 
    }
    const multiselectClass = STATE.multiselect.active && STATE.multiselect.section === 'status' ? 'multiselect-mode' : '';
    grid.innerHTML = `<div class="${multiselectClass}" style="display:contents;">` + items.map((item, idx) => {
        const realIdx = STATE.statusItems.indexOf(item);
        let preview = '';
        if (item.type === 'text') {
            preview = `<div style="padding:0.375rem; font-size:0.625rem;">${escapeHtml((item.message||'').substring(0, 50))}${(item.message||'').length > 50 ? '...' : ''}</div>`;
        } else if (item.path) {
            if (item.type === 'video') {
                preview = `<video src="${item.path}#t=0.5" preload="metadata" muted playsinline></video>
                            <div class="video-overlay" style="position:absolute; top:50%; left:50%; transform:translate(-50%, -50%); background:rgba(0,0,0,0.5); border-radius:50%; width:24px; height:24px; display:flex; align-items:center; justify-content:center; color:#fff;"><svg viewBox="0 0 24 24" style="width:0.75rem;height:0.75rem;fill:currentColor;"><path d="M8 5v14l11-7z"/></svg></div>`;
            } else {
                preview = `<img src="${item.path}" onerror="this.style.display='none'; this.nextElementSibling.style.display='flex';">
                            <div style="display:none; width:100%; height:100%; align-items:center; justify-content:center; background:var(--bg-input);"><svg viewBox="0 0 24 24" style="width:1rem;height:1rem;fill:var(--text-dim);"><path d="M21 19V5c0-1.1-.9-2-2-2H5c-1.1 0-2 .9-2 2v14c0 1.1.9 2 2 2h14c1.1 0 2-.9 2-2zM8.5 13.5l2.5 3.01L14.5 12l4.5 6H5l3.5-4.5z"/></svg></div>`;
            }
        }
        const hasSchedule = item.schedule && (item.schedule.days?.length > 0 || item.schedule.times?.length > 0);
        const scheduleText = hasSchedule ? `${item.schedule.days?.slice(0, 3).join(', ') || ''}${item.schedule.times?.length > 0 ? ' • ' + item.schedule.times[0] : ''}` : '';
        const isVideo = item.type === 'video' || (item.path && item.path.match(/\.(mp4|mov|avi|mkv|webm)$/i));
        const showExpand = !isVideo && item.type !== 'text';
        return `
            <div class="item-card ${item.selected ? 'selected' : ''} ${hasSchedule ? 'has-schedule' : ''}" data-idx="${realIdx}"
                 onclick="handleItemClick('status', ${realIdx}, event)"
                 onmousedown="handlePressStart(event, 'status', ${realIdx})"
                 ontouchstart="handlePressStart(event, 'status', ${realIdx})"
                 onmouseup="handlePressEnd()" ontouchend="handlePressEnd()" onmouseleave="handlePressEnd()">
                <div class="preview">${preview}</div>
                <div class="item-card-actions">
                    ${showExpand ? `<div class="action-btn" onclick="event.stopPropagation(); expandImage('${escapeHtml(item.path || '')}', '${escapeHtml(item.caption || '')}')" title="Expandir">
                        <svg viewBox="0 0 24 24"><path d="M7 14H5v5h5v-2H7v-3zm-2-4h2V7h3V5H5v5zm12 7h-3v2h5v-5h-2v3zM14 5v2h3v3h2V5h-5z"/></svg>
                    </div>` : ''}
                    <div class="action-btn schedule-btn" onclick="event.stopPropagation(); openScheduleModal('status', ${realIdx})" title="Agendamento">
                        <svg viewBox="0 0 24 24"><path d="M19 3h-1V1h-2v2H8V1H6v2H5c-1.1 0-2 .9-2 2v14c0 1.1.9 2 2 2h14c1.1 0 2-.9 2-2V5c0-1.1-.9-2-2-2zm0 16H5V8h14v11zM9 10H7v2h2v-2zm4 0h-2v2h2v-2zm4 0h-2v2h2v-2z"/></svg>
                    </div>
                </div>
                ${hasSchedule ? `<div class="schedule-info">${CAL_ICON} ${scheduleText}</div>` : ''}
                <div class="item-check"><svg viewBox="0 0 24 24"><path d="M9 16.2L4.8 12l-1.4 1.4L9 19 21 7l-1.4-1.4L9 16.2z"/></svg></div>
            </div>
        `;
    }).join('') + '</div>';
}

function expandImage(path, caption) {
    document.getElementById('expandImg').src = path;
    document.getElementById('expandCaption').textContent = caption || '';
    openModal('imageExpandModal');
}

