function handleImageFile(e) {
    const file = e.target.files[0];
    if (!file) return;
    STATE._pendingImagePath = file.path || file.name || '';
    const reader = new FileReader();
    reader.onload = ev => {
        STATE._pendingImageBase64 = ev.target.result;
        const prevEl = document.getElementById('imagePreview');
        if (prevEl) prevEl.style.display = 'block';
        const imgEl = document.getElementById('imageImgPreview');
        if (imgEl) imgEl.src = ev.target.result;
        const pathEl = document.getElementById('imagePathDisplay');
        if (pathEl) pathEl.textContent = STATE._pendingImagePath;
    };
    reader.readAsDataURL(file);
}



