/* =========================================================
   STATUS - ENVIO
   ========================================================= */
async function sendStatusBatch() {
    const sendImg = document.getElementById('sendImages').checked;
    const sendVid = document.getElementById('sendVideos').checked;
    const sendTxt = document.getElementById('sendTexts').checked;
    let items = STATE.statusItems.filter(i => i.selected);
    if (items.length === 0) items = STATE.statusItems;
    items = items.filter(i => {
        if (i.type === 'image' && !sendImg) return false;
        if (i.type === 'video' && !sendVid) return false;
        if (i.type === 'text' && !sendTxt) return false;
        return true;
    });
    if (items.length === 0) { log('error', 'Nenhum status.'); return; }
    const allDeviceIds = new Set();
    items.forEach(i => {
        const itemDevs = getDeviceListForSend(i.device_ids);
        itemDevs.forEach(d => allDeviceIds.add(d.deviceId));
    });
    if (allDeviceIds.size === 0) { log('error', 'Nenhum dispositivo configurado ou selecionado.'); return; }
    const ok = await askConfirm(`Enviar ${items.length} status via ${allDeviceIds.size} dispositivo(s)?`);
    if (!ok) return;
    await sendStatusItems(items);
    STATE.statusItems.forEach(i => i.selected = false);
    renderStatus();
    exitMultiselect();
}

async function sendAllStatus() {
    if (STATE.statusItems.length === 0) { log('error', 'Nenhum status.'); return; }
    const sendImg = document.getElementById('sendImages').checked;
    const sendVid = document.getElementById('sendVideos').checked;
    const sendTxt = document.getElementById('sendTexts').checked;
    let items = STATE.statusItems.filter(i => {
        if (i.type === 'image' && !sendImg) return false;
        if (i.type === 'video' && !sendVid) return false;
        if (i.type === 'text' && !sendTxt) return false;
        return true;
    });
    if (items.length === 0) { log('error', 'Nenhum status para enviar.'); return; }
    const allDeviceIds = new Set();
    items.forEach(i => {
        const itemDevs = getDeviceListForSend(i.device_ids);
        itemDevs.forEach(d => allDeviceIds.add(d.deviceId));
    });
    if (allDeviceIds.size === 0) { log('error', 'Nenhum dispositivo configurado ou selecionado.'); return; }
    const ok = await askConfirm(`Enviar TODOS os ${items.length} status via ${allDeviceIds.size} dispositivo(s)?`);
    if (!ok) return;
    await sendStatusItems(items);
    STATE.statusItems.forEach(i => i.selected = false);
    renderStatus();
    exitMultiselect();
}

async function sendStatusItems(items) {
    for (const item of items) {
        const deviceList = getDeviceListForSend(item.device_ids);
        if (deviceList.length === 0) {
            log('warn', `Item sem dispositivo configurado: ${item.type}`);
            continue;
        }
        for (const { deviceId, device } of deviceList) {
            log('info', `Enviando status [${item.type}] via ${device.name}...`);
            let res;
            if (item.type === 'text') {
                res = await apiRequest('/send/message', 'POST', {
                    phone: 'status@broadcast',
                    message: item.message
                }, deviceId);
            } else if (item.path) {
                const blob = await pathToBlob(item.path);
                if (blob) {
                    const formData = new FormData();
                    formData.append('phone', 'status@broadcast');
                    const parts = item.path.split('/');
                    const fileName = parts[parts.length - 1] || 'media';
                    formData.append(item.type === 'video' ? 'video' : 'image', blob, fileName);
                    if (item.caption) formData.append('caption', item.caption);
                    if (item.type === 'video') formData.append('is_video', 'true');
                    res = await apiMultipart('/send/image', formData, deviceId);
                } else {
                    res = { ok: false, data: 'Falha ao ler arquivo' };
                }
            } else if (item.base64) {
                res = await apiRequest('/send/image', 'POST', {
                    phone: 'status@broadcast',
                    image_path: item.base64,
                    caption: item.caption
                }, deviceId);
            } else {
                res = { ok: false, data: 'Sem arquivo' };
            }
            if (res && res.ok) {
                log('success', `[OK] Status enviado (${device.name})`);
                addToHistory({ section:'status', type: item.type + '_message', action:'send', status:'success', target:'status@broadcast', detail: item.caption || item.message, broadcastId: item.id });
            } else {
                log('error', `[ERRO] Erro: ${JSON.stringify(res?.data || res)}`);
                addToHistory({ section:'status', type: item.type + '_message', action:'send', status:'error', target:'status@broadcast', detail: item.caption || item.message, broadcastId: item.id });
            }
        }
    }
}

/* Envia imagem usando multipart/form-data */
async function sendImageMultipart(item, device, recipient) {
    const fullPhone = recipient.phone + recipient.suffix;
    log('info', `Enviando imagem para ${fullPhone} via ${device.name}...`);

    // Obtém o blob do arquivo
    let blob = null;
    let fileName = 'image.jpg';

    if (item.base64) {
        // Converte base64 para blob
        const byteChars = atob(item.base64);
        const byteNumbers = new Array(byteChars.length);
        for (let i = 0; i < byteChars.length; i++) byteNumbers[i] = byteChars.charCodeAt(i);
        const byteArray = new Uint8Array(byteNumbers);
        blob = new Blob([byteArray], { type: 'image/jpeg' });
        fileName = 'image.jpg';
    } else if (item.path) {
        log('info', `Lendo arquivo: ${item.path}`);
        blob = await pathToBlob(item.path);
        // Extrai nome do arquivo
        const parts = item.path.split('/');
        fileName = parts[parts.length - 1] || 'image.jpg';
    }

    if (!blob) {
        log('error', `Não foi possível ler o arquivo: ${item.path || '(base64)'}`);
        addToHistory({ section:'images', type:'image_message', action:'send', status:'error', targets:[fullPhone], target:fullPhone, detail: item.caption || item.path, broadcastId: item.id });
        return false;
    }

    // Monta FormData
    const formData = new FormData();
    formData.append('phone', fullPhone);
    formData.append('image', blob, fileName);
    if (item.caption) formData.append('caption', item.caption);
    formData.append('compress', String(item.compress !== false));
    formData.append('view_once', String(!!item.view_once));
    formData.append('is_forwarded', String(!!item.is_forwarded));
    formData.append('duration', String(item.duration || 0));

    console.log('FormData campos:', Array.from(formData.keys()));

    const res = await apiMultipart('/send/image', formData, device.id);

    if (res && res.ok) {
        log('success', `[OK] Imagem enviada para ${fullPhone}`);
        addToHistory({ section:'images', type:'image_message', action:'send', status:'success', targets:[fullPhone], target:fullPhone, detail:item.caption||'', broadcastId:item.id, is_forwarded:item.is_forwarded, duration:item.duration, caption:item.caption, path:item.path });
        return true;
    } else {
        log('error', `[ERRO] ${fullPhone}: ${JSON.stringify(res?.data || res)}`);
        addToHistory({ section:'images', type:'image_message', action:'send', status:'error', targets:[fullPhone], target:fullPhone, detail:item.caption||'', broadcastId:item.id });
        return false;
    }
}

async function sendImagesBatch() {
    const items = STATE.imageItems.filter(i => i.selected);
    if (items.length === 0) { log('error', 'Selecione imagens.'); return; }
    const allDeviceIds = new Set();
    items.forEach(i => {
        const itemDevs = getDeviceListForSend(i.device_ids);
        itemDevs.forEach(d => allDeviceIds.add(d.deviceId));
    });
    if (allDeviceIds.size === 0) { log('error', 'Nenhum dispositivo configurado nos itens ou selecionado.'); return; }
    const ok = await askConfirm(`Enviar ${items.length} imagem(ns) via ${allDeviceIds.size} dispositivo(s)?`);
    if (!ok) return;
    for (const item of items) {
        const deviceList = getDeviceListForSend(item.device_ids);
        for (const { deviceId, device } of deviceList) {
            for (const recipient of item.recipients) {
                await sendImageMultipart(item, device, recipient);
            }
        }
    }
    STATE.imageItems.forEach(i => i.selected = false);
    renderImages();
    exitMultiselect();
}

async function sendAllImages() {
    if (STATE.imageItems.length === 0) { log('error', 'Nenhuma imagem para enviar.'); return; }
    const allDeviceIds = new Set();
    STATE.imageItems.forEach(i => {
        const itemDevs = getDeviceListForSend(i.device_ids);
        itemDevs.forEach(d => allDeviceIds.add(d.deviceId));
    });
    if (allDeviceIds.size === 0) { log('error', 'Nenhum dispositivo configurado ou selecionado.'); return; }
    const ok = await askConfirm(`Enviar TODAS as ${STATE.imageItems.length} imagens via ${allDeviceIds.size} dispositivo(s)?`);
    if (!ok) return;
    for (const item of STATE.imageItems) {
        const deviceList = getDeviceListForSend(item.device_ids);
        for (const { deviceId, device } of deviceList) {
            for (const recipient of item.recipients) {
                await sendImageMultipart(item, device, recipient);
            }
        }
    }
}

/* =========================================================
   MESSAGES
   ========================================================= */
function openAddMessage() {
    document.getElementById('messageText').value = '';
    document.getElementById('msgForwarded').classList.remove('on');
    selectDuration('msgDuration', '0', document.querySelector('#msgDurationPicker .duration-chip[data-value="0"]'));
    STATE._pendingMessageSchedule = { times: [], days: [] };
    populateRecipientsContainer('msgRecipients', []);
    updateAddSchedulePreview('addMsgSchedulePreview', '_pendingMessageSchedule');
    hideRecipientsAlert('msgRecipientsAlert');
    populateDevicePicker('msg', []);
    openModal('addMessageModal');
}

async function confirmAddMessage() {
    const message = document.getElementById('messageText').value.trim();
    if (!message) {
        showValidationAlert('msgTextAlert', 'Digite uma mensagem');
        log('error', 'Digite a mensagem.');
        return;
    }
    hideValidationAlert('msgTextAlert');
    const recipients = collectRecipientsFromContainer('msgRecipients');
    if (recipients.length === 0) {
        showRecipientsAlert('msgRecipientsAlert');
        log('error', 'Adicione pelo menos um destinatário.');
        return;
    }
    hideRecipientsAlert('msgRecipientsAlert');
    const deviceIds = getSelectedDeviceIds('msg');
    if (deviceIds.length === 0) {
        showDevicePickerAlert('msg');
        log('error', 'Selecione pelo menos um dispositivo de envio.');
        return;
    }
    const forwarded = document.getElementById('msgForwarded').classList.contains('on');
    const duration = getDuration('msgDuration');
    const schedule = STATE._pendingMessageSchedule || { times: [], days: [] };
    STATE.messageItems.push({
        recipients, message, is_forwarded: forwarded, duration, type: 'message', schedule,
        device_ids: deviceIds
    });
    saveMessagesFile();
    log('success', `Mensagem adicionada para ${deviceIds.length} dispositivo(s) e ${recipients.length} destinatário(s).`);
    closeModal('addMessageModal');
    renderMessages();
}

