async function sendMessagesBatch() {
    const items = STATE.messageItems.filter(i => i.selected);
    if (items.length === 0) { log('error', 'Selecione mensagens.'); return; }
    // Coleta dispositivos únicos a partir dos itens
    const allDeviceIds = new Set();
    items.forEach(i => (i.device_ids || []).forEach(id => allDeviceIds.add(id)));
    if (allDeviceIds.size === 0) { log('error', 'Nenhum dispositivo configurado nos itens.'); return; }
    const ok = await askConfirm(`Enviar ${items.length} mensagem(ns) via ${allDeviceIds.size} dispositivo(s)?`);
    if (!ok) return;
    for (const item of items) {
        const deviceList = getDeviceListForSend(item.device_ids);
        for (const { deviceId, device } of deviceList) {
            for (const recipient of item.recipients) {
                const fullPhone = recipient.phone + recipient.suffix;
                log('info', `Enviando para ${fullPhone} via ${device.name}...`);
                const payload = { phone: fullPhone, message: item.message, is_forwarded: item.is_forwarded || false, duration: item.duration || 0 };
                const res = await apiRequest('/send/message', 'POST', payload, deviceId);
                if (res && res.ok) {
                    log('success', `[OK] Enviado para ${fullPhone}`);
                    addToHistory({ section:'messages', type:'message', action:'send', status:'success', targets:[fullPhone], target:fullPhone, detail:item.message.substring(0,80), broadcastId:item.id });
                } else {
                    log('error', `[ERRO] ${fullPhone}: ${JSON.stringify(res?.data || res)}`);
                    addToHistory({ section:'messages', type:'message', action:'send', status:'error', targets:[fullPhone], target:fullPhone, detail:item.message.substring(0,80), broadcastId:item.id });
                }
            }
        }
    }
    STATE.messageItems.forEach(i => i.selected = false);
    renderMessages();
    exitMultiselect();
}

async function sendAllMessages() {
    if (STATE.messageItems.length === 0) { log('error', 'Nenhuma mensagem.'); return; }
    const allDeviceIds = new Set();
    STATE.messageItems.forEach(i => (i.device_ids || []).forEach(id => allDeviceIds.add(id)));
    if (allDeviceIds.size === 0) { log('error', 'Nenhum dispositivo configurado nos itens.'); return; }
    const ok = await askConfirm(`Enviar TODAS as ${STATE.messageItems.length} mensagens via ${allDeviceIds.size} dispositivo(s)?`);
    if (!ok) return;
    for (const item of STATE.messageItems) {
        const deviceList = getDeviceListForSend(item.device_ids);
        for (const { deviceId, device } of deviceList) {
            for (const recipient of item.recipients) {
                const fullPhone = recipient.phone + recipient.suffix;
                log('info', `Enviando para ${fullPhone} via ${device.name}...`);
                const payload = { phone: fullPhone, message: item.message, is_forwarded: item.is_forwarded || false, duration: item.duration || 0 };
                const res = await apiRequest('/send/message', 'POST', payload, deviceId);
                if (res && res.ok) {
                    log('success', `[OK] Enviado para ${fullPhone}`);
                    addToHistory({ section:'messages', type:'message', action:'send', status:'success', targets:[fullPhone], target:fullPhone, detail:item.message.substring(0,80), broadcastId:item.id });
                } else {
                    log('error', `[ERRO] ${fullPhone}: ${JSON.stringify(res?.data || res)}`);
                    addToHistory({ section:'messages', type:'message', action:'send', status:'error', targets:[fullPhone], target:fullPhone, detail:item.message.substring(0,80), broadcastId:item.id });
                }
            }
        }
    }
}

/* =========================================================
   POLLS
   ========================================================= */
function openAddPoll() {
    document.getElementById('pollQuestion').value = '';
    document.getElementById('pollMaxAnswer').value = '1';
    document.getElementById('pollOptions').innerHTML = '';
    STATE._pendingPollSchedule = { times: [], days: [] };
    populateRecipientsContainer('pollRecipients', []);
    addPollOption(); addPollOption();
    updateAddSchedulePreview('addPollSchedulePreview', '_pendingPollSchedule');
    hideRecipientsAlert('pollRecipientsAlert');
    populateDevicePicker('poll', []);
    openModal('addPollModal');
}

function addPollOption() {
    const c = document.getElementById('pollOptions');
    const opts = c.querySelectorAll('.poll-option');
    if (opts.length >= 12) { log('warn', 'Máx. 12 opções.'); return; }
    const div = document.createElement('div');
    div.className = 'poll-option';
    div.innerHTML = `<input type="text" placeholder="Opção ${opts.length + 1}"><button onclick="this.parentElement.remove()" type="button">×</button>`;
    c.appendChild(div);
}

async function confirmAddPoll() {
    const question = document.getElementById('pollQuestion').value.trim();
    if (!question) { log('error', 'Digite a pergunta.'); return; }
    const options = Array.from(document.querySelectorAll('#pollOptions input')).map(i => i.value.trim()).filter(Boolean);
    if (options.length < 2) { log('error', 'Mín. 2 opções.'); return; }
    const recipients = collectRecipientsFromContainer('pollRecipients');
    if (recipients.length === 0) {
        showRecipientsAlert('pollRecipientsAlert');
        log('error', 'Adicione pelo menos um destinatário.');
        return;
    }
    hideRecipientsAlert('pollRecipientsAlert');
    const deviceIds = getSelectedDeviceIds('poll');
    if (deviceIds.length === 0) {
        showDevicePickerAlert('poll');
        log('error', 'Selecione pelo menos um dispositivo de envio.');
        return;
    }
    const max_answer = Math.max(1, Math.min(options.length, parseInt(document.getElementById('pollMaxAnswer').value) || 1));
    const schedule = STATE._pendingPollSchedule || { times: [], days: [] };
    STATE.pollItems.push({ recipients, question, options, max_answer, type: 'poll', schedule, device_ids: deviceIds });
    savePollsFile();
    log('success', `Enquete adicionada para ${deviceIds.length} dispositivo(s) e ${recipients.length} destinatário(s).`);
    closeModal('addPollModal');
    renderPolls();
}

function renderPolls() {
    updateTabCounters();
    const container = document.getElementById('pollsList');
    if (!container) return;
    let items = STATE.pollItems || [];
    const q = STATE.searchQueries?.polls;
