/* Envia arquivo via multipart */
async function sendFileMultipart(item, device, recipient) {
    const fullPhone = recipient.phone + recipient.suffix;
    log('info', `Enviando arquivo para ${fullPhone} via ${device.name}...`);

    let blob = null;
    let fileName = 'file.bin';

    if (item.path) {
        log('info', `Lendo arquivo: ${item.path}`);
        blob = await pathToBlob(item.path);
        const parts = item.path.split('/');
        fileName = parts[parts.length - 1] || 'file.bin';
    }

    if (!blob) {
        log('error', `Não foi possível ler: ${item.path}`);
        addToHistory({ section:'files', type:'file', action:'send', status:'error', targets:[fullPhone], target:fullPhone, detail:item.caption||item.path, broadcastId:item.id });
        return false;
    }

    const formData = new FormData();
    formData.append('phone', fullPhone);
    formData.append('file', blob, fileName);
    if (item.caption) formData.append('caption', item.caption);
    formData.append('is_forwarded', String(!!item.is_forwarded));

    const res = await apiMultipart('/send/file', formData, device.id);

    if (res && res.ok) {
        log('success', `[OK] Arquivo enviado para ${fullPhone}`);
        addToHistory({ section:'files', type:'file', action:'send', status:'success', targets:[fullPhone], target:fullPhone, detail:item.caption||item.path, broadcastId:item.id });
        return true;
    } else {
        log('error', `[ERRO] ${fullPhone}: ${JSON.stringify(res?.data || res)}`);
        addToHistory({ section:'files', type:'file', action:'send', status:'error', targets:[fullPhone], target:fullPhone, detail:item.caption||item.path, broadcastId:item.id });
        return false;
    }
}

async function sendFilesBatch() {
    const items = STATE.fileItems.filter(i => i.selected);
    if (items.length === 0) { log('error', 'Selecione arquivos.'); return; }
    const allDeviceIds = new Set();
