/* Swipe Gestures para alternar abas */
(function setupSwipeTabs() {
    const TAB_ORDER = ['status', 'images', 'messages', 'polls', 'files'];
    let touchStartX = 0;
    let touchStartY = 0;
    let touchStartTime = 0;

    document.addEventListener('touchstart', (e) => {
        if (e.touches.length !== 1) return;
        const target = e.target;
        if (document.querySelector('.modal-overlay.show')) return;
        if (target.closest('input, textarea, select, button, .items-grid, .list-item, .modal, .item-card')) return;

        touchStartX = e.touches[0].clientX;
        touchStartY = e.touches[0].clientY;
        touchStartTime = Date.now();
    }, { passive: true });

    document.addEventListener('touchend', (e) => {
        if (!touchStartX || !touchStartTime) return;
        if (document.querySelector('.modal-overlay.show')) {
            touchStartX = 0;
            return;
        }

        const touchEndX = e.changedTouches[0].clientX;
        const touchEndY = e.changedTouches[0].clientY;
        const deltaX = touchEndX - touchStartX;
        const deltaY = touchEndY - touchStartY;
        const duration = Date.now() - touchStartTime;

        touchStartX = 0;
        touchStartY = 0;
        touchStartTime = 0;

        if (Math.abs(deltaX) >= 60 && Math.abs(deltaY) <= 50 && duration <= 500) {
            const activeTabBtn = document.querySelector('.tab-btn.active');
            const currentTab = activeTabBtn ? activeTabBtn.dataset.tab : 'status';
            const currentIndex = TAB_ORDER.indexOf(currentTab);

            if (currentIndex !== -1) {
                if (deltaX < 0 && currentIndex < TAB_ORDER.length - 1) {
                    switchTab(TAB_ORDER[currentIndex + 1]);
                } else if (deltaX > 0 && currentIndex > 0) {
                    switchTab(TAB_ORDER[currentIndex - 1]);
                }
            }
        }
    }, { passive: true });
})();


function filterItemList(inputEl, section) {
    if (!STATE.searchQueries) STATE.searchQueries = { status: '', images: '', messages: '', polls: '', files: '' };
    STATE.searchQueries[section] = (inputEl.value || '').trim().toLowerCase();
    if (section === 'status') renderStatus();
    else if (section === 'images') renderImages();
    else if (section === 'messages') renderMessages();
    else if (section === 'polls') renderPolls();
    else if (section === 'files') renderFiles();
}

function updateTabCounters() {
    const statusCount = STATE.statusItems ? STATE.statusItems.length : 0;
    const imagesCount = STATE.imageItems ? STATE.imageItems.length : 0;
    const messagesCount = STATE.messageItems ? STATE.messageItems.length : 0;
    const pollsCount = STATE.pollItems ? STATE.pollItems.length : 0;
    const filesCount = STATE.fileItems ? STATE.fileItems.length : 0;

    const cSt = document.getElementById('count-status');
    if (cSt) cSt.textContent = statusCount;
    const cImg = document.getElementById('count-images');
    if (cImg) cImg.textContent = imagesCount;
    const cMsg = document.getElementById('count-messages');
    if (cMsg) cMsg.textContent = messagesCount;
    const cPoll = document.getElementById('count-polls');
    if (cPoll) cPoll.textContent = pollsCount;
    const cFile = document.getElementById('count-files');
    if (cFile) cFile.textContent = filesCount;
}

import java.io.File;
import java.io.FileWriter;
import java.io.IOException;
import com.joaomgcd.taskerm.action.java.JavaCodeException;


type = "js";

project_path = tasker.getVariable("project_path");

if (project_path == null || project_path == void) {
    throw new JavaCodeException("A variável do Tasker 'project_path' não está definida.");
}

folderName = "";
extension = "";
contentVarName = "";

if (type.equals("css")) {
    folderName = "css";
    extension = "css";
    contentVarName = "css";
} else if (type.equals("js")) {
    folderName = "js";
    extension = "js";
    contentVarName = "jsc";
} else {
    throw new JavaCodeException("Tipo não suportado: " + type);
}

file_content = tasker.getVariable(contentVarName);

if (file_content == null || file_content == void) {
    throw new JavaCodeException("A variável do Tasker '" + contentVarName + "' não está definida ou está vazia.");
}

dirPath = project_path + File.separator + folderName;
dir = new File(dirPath);

if (!dir.exists()) {
    if (!dir.mkdirs()) {
        throw new JavaCodeException("Falha ao criar o diretório: " + dirPath);
    }
}

filePath = dirPath + File.separator + "index." + extension;
file = new File(filePath);

writer = null;
try {
    writer = new FileWriter(file);
    writer.write(file_content);
} catch (IOException e) {
    throw new JavaCodeException("Falha ao escrever o arquivo " + extension + ": " + e.getMessage());
} finally {
    if (writer != null) {
        try {
            writer.close();
        } catch (IOException e) {
        }
    }
}

import android.graphics.Bitmap;
import android.graphics.BitmapFactory;
import android.graphics.Canvas;
import android.graphics.Color;
import android.graphics.LinearGradient;
import android.graphics.Paint;
import android.graphics.Shader;
import android.util.Base64;
import java.io.ByteArrayOutputStream;
import java.io.File;

/* * Processamento de Imagem com Escala Automática
 * Converte a lógica JS para Java (BeanShell Tasker)
 */

imagePath = tasker.getVariable("path");
numeroParaAdicionar = tasker.getVariable("final_number");

if (imagePath == null || imagePath.equals("")) {
    tasker.setVariable("canvas_error", "Caminho da imagem (path) vazio.");
    return;
}

try {
    /* 1. Carregar a Imagem Original */
    options = new BitmapFactory.Options();
    options.inMutable = true;
    img = BitmapFactory.decodeFile(imagePath, options);

    if (img == null) {
        tasker.setVariable("canvas_error", "Erro ao carregar imagem: " + imagePath);
        return;
    }

    /* 2. Lógica de Escala Automática (Base 1000px) */
    fator = (float) img.getWidth() / 1000f;

    corteEsquerda = -40f * fator; 
    corteDireita = -50f * fator;
    corteTopo = -385f * fator;
    corteBaixo = -20f * fator;

    tamanhoFonte = 450f * fator;    
    ajusteY = -460f * fator;        
    profundidade3D = (int) (15f * fator);
    espessuraContorno = 12f * fator;

    /* 3. Calcular Dimensões Finais */
    larguraFinal = (int) (img.getWidth() - corteEsquerda - corteDireita);

    yCalc = (ajusteY > 0 ? ajusteY : 0);
    alturaFinal = (int) (img.getHeight() + yCalc - corteTopo - corteBaixo);

    /* Proteção contra tamanhos inválidos */
    if (larguraFinal <= 0 || alturaFinal <= 0) {
        tasker.setVariable("canvas_error", "Configurações de corte resultam em tamanho inválido.");
        return;
    }

    /* 4. Criar Canvas e Desenhar Imagem com Corte */
    resultBitmap = Bitmap.createBitmap(larguraFinal, alturaFinal, Bitmap.Config.ARGB_8888);
    canvas = new Canvas(resultBitmap);
    canvas.drawBitmap(img, -corteEsquerda, -corteTopo, null);

    /* 5. Configurar Estilo do Texto */
    paint = new Paint();
    paint.setAntiAlias(true);
    paint.setTextSize(tamanhoFonte);
    paint.setFakeBoldText(true);
    paint.setTextAlign(Paint.Align.CENTER);
    paint.setStrokeJoin(Paint.Join.ROUND);

    x_final = (img.getWidth() / 2f) - corteEsquerda;
    y_final = (img.getHeight() / 2f) + ajusteY - corteTopo;

    /* 6. Desenhar Bloco 3D */
    paint.setStyle(Paint.Style.FILL_AND_STROKE);
    paint.setStrokeWidth(espessuraContorno);
    paint.setColor(Color.parseColor("#002233"));

    for (int i = 1; i <= profundidade3D; i++) {
        canvas.drawText(numeroParaAdicionar, x_final, y_final + i, paint);
    }

    /* 7. Desenhar Face Frontal (Contorno) */
    paint.setColor(Color.parseColor("#004466"));
    paint.setStyle(Paint.Style.STROKE);
    canvas.drawText(numeroParaAdicionar, x_final, y_final, paint);

    /* 8. Desenhar Face Frontal (Degradê) */
    gradient = new LinearGradient(
        0, y_final - tamanhoFonte, 
        0, y_final, 
        Color.parseColor("#99FF00"), 
        Color.parseColor("#00CCFF"), 
        Shader.TileMode.CLAMP
    );
    paint.setStyle(Paint.Style.FILL);
    paint.setShader(gradient);
    canvas.drawText(numeroParaAdicionar, x_final, y_final, paint);

    /* 9. Gerar Base64 Limpo para o Tasker */
    stream = new ByteArrayOutputStream();
    resultBitmap.compress(Bitmap.CompressFormat.PNG, 100, stream);
    byte[] byteArray = stream.toByteArray();

    /* NO_WRAP evita quebras de linha que corrompem a imagem no Tasker */
    base64Result = Base64.encodeToString(byteArray, Base64.NO_WRAP);

    tasker.setVariable("image_base64", base64Result);

    /* Limpeza de memória */
    img.recycle();
    resultBitmap.recycle();

} catch (Exception e) {
    tasker.setVariable("canvas_error", e.toString());
}

var data = JSON.parse(http_data);
var assets = data.assets || [];
var result = {};

for (var i = 0; i < assets.length; i++) {
    var asset = assets[i];
    var name = asset.name;
    var url = asset.browser_download_url;

    var key = name.replace(/\.[^/.]+$/, '')
                  .replace(/-/g, '_')
                  .replace(/\./g, '_')
                  .toLowerCase();

    result[key] = url;
}

result.title = data.name;
result.version = data.tag_name || '';

var jsonOutput = JSON.stringify(result, null, 4);
setLocal('download_links', jsonOutput);

import android.view.accessibility.AccessibilityEvent;
import android.view.accessibility.AccessibilityNodeInfo;
import android.accessibilityservice.AccessibilityService;
import java.util.List;
import com.joaomgcd.taskerm.action.java.JavaCodeException;

// Validação da ativação do serviço de acessibilidade
AccessibilityService service = tasker.getAccessibilityService();
if (service == null) {
    throw new JavaCodeException("Serviço de Acessibilidade não ativo.");
}

// Aguarda 1200 milissegundos antes de iniciar as ações de clique
android.os.SystemClock.sleep(1200);

// Configuração de retorno padrão e tempo limite de monitoramento (30 segundos)
String result = "timeout";
long endTime = System.currentTimeMillis() + 30000;

// Contador de passadas estáveis (tela final visível e sem nenhum clique novo)
int passadasEstaveis = 0;
final int PASSADAS_NECESSARIAS = 2; // exige 2 leituras seguidas estáveis antes de concluir

tasker.log("Iniciando monitoramento multi-idioma...");

// Loop principal de execução até o tempo limite ser atingido
while (System.currentTimeMillis() < endTime) {
    AccessibilityNodeInfo root = service.getRootInActiveWindow();

    if (root != null) {
        // Captura de todos os elementos da interface atual
        List nodes = service.getChildrenRecursive(root);
        boolean dialogoAtivo = false;
        boolean clicouNestaPassada = false;
        boolean telaFinalDetectada = false;

        for (int i = 0; i < nodes.size(); i++) {
            AccessibilityNodeInfo node = (AccessibilityNodeInfo) nodes.get(i);
            if (node == null) continue;

            // Identificação e clique via ID de recurso (padrão de sistema Android para botões positivos)
            String viewId = node.getViewIdResourceName();
            if (viewId != null && (viewId.contains("button1") || viewId.contains("button_positive"))) {
                if (node.isClickable()) {
                    node.performAction(AccessibilityNodeInfo.ACTION_CLICK);
                    clicouNestaPassada = true;
                    tasker.log("Clique por ID Universal efetuado.");
                }
            }

            // Identificação e clique via texto (mapeamento multi-idioma)
            if (node.getText() != null) {
                String t = node.getText().toString().toUpperCase().trim();

                // Verificação de termos que indicam a presença do diálogo de importação
                if (t.contains("TASKER") || t.contains("IMPORT") || t.contains("PROJET")) {
                    dialogoAtivo = true;
                }

                // Lista de termos para cliques de confirmação em múltiplos idiomas
                if (t.equals("SIM") || t.equals("YES") || t.equals("OK") || t.equals("SÍ") ||
                    t.equals("ДА") || t.equals("SÍ") || t.equals("SÌ") || t.equals("是") || t.equals("确定") ||
                    t.equals("SUBSTITUIR") || t.equals("REPLACE") || t.equals("OVERWRITE") ||
                    t.equals("CONTINUAR") || t.equals("CONTINUE")) {

                    if (node.isClickable()) {
                        node.performAction(AccessibilityNodeInfo.ACTION_CLICK);
                        clicouNestaPassada = true;
                        tasker.log("Clique por texto efetuado: " + t);
                    }
                }

                // Detecção de retorno à tela principal para definir conclusão
                if (t.contains("PROJECTS") || t.contains("PROJETOS") || t.contains("TASKS") || t.contains("TAREFAS")) {
                    telaFinalDetectada = true;
                }
            }
        }

        if (clicouNestaPassada) {
            // Acabou de clicar: reseta a contagem de estabilidade e dá tempo
            // pra UI assentar (fechar diálogo / carregar próxima tela) antes
            // de reavaliar, evitando ler a árvore em transição.
            passadasEstaveis = 0;
            android.os.SystemClock.sleep(600);
            continue;
        }

        if (telaFinalDetectada) {
            // Só conta como estável se a tela final apareceu E não houve
            // clique nesta passada. Exige duas leituras seguidas para
            // confirmar que não é um estado transitório.
            passadasEstaveis++;
            tasker.log("Tela final detectada (" + passadasEstaveis + "/" + PASSADAS_NECESSARIAS + ")");

            if (passadasEstaveis >= PASSADAS_NECESSARIAS) {
                result = "imported";
                break;
            }
        } else {
            passadasEstaveis = 0;
        }
    }

    // Intervalo de varredura para controle de consumo de CPU
    android.os.SystemClock.sleep(400);
}

return result;

import java.io.File;
import java.nio.file.Files;
import java.nio.file.Paths;
import java.util.List;
import java.util.ArrayList;
import java.util.Map;
import java.util.HashMap;
import org.json.JSONArray;
import org.json.JSONObject;

String basePath = "/storage/emulated/0/Tasker/projects_task/projects/whats-connect-api/system/broadcast-master/";
String jsonStatusPath = basePath + "json-status.json";

String readJsonFile(String filePath) {
    try {
        File file = new File(filePath);
        if (file.exists()) {
            return new String(Files.readAllBytes(Paths.get(filePath)));
        }
    } catch (Exception e) {
        tasker.log("Error reading file: " + filePath + " - " + e.getMessage());
    }
    return null;
}

void writeJsonFile(String filePath, String content) {
    try {
        Files.write(Paths.get(filePath), content.getBytes());
    } catch (Exception e) {
        tasker.log("Error writing file: " + filePath + " - " + e.getMessage());
    }
}

String jsonContent = readJsonFile(jsonStatusPath);
Map rootData = new HashMap();
List itemsList = new ArrayList();

if (jsonContent != null && jsonContent.length() > 0) {
    try {
        JSONObject jsonObject = new JSONObject(jsonContent);

        if (jsonObject.has("devices")) {
            JSONArray devicesArray = jsonObject.getJSONArray("devices");
            List devicesList = new ArrayList();
            for (int i = 0; i < devicesArray.length(); i++) {
                JSONObject deviceObj = devicesArray.getJSONObject(i);
                Map deviceMap = new HashMap();
                if (deviceObj.has("device_id")) deviceMap.put("device_id", deviceObj.getString("device_id"));
                if (deviceObj.has("device_phone")) deviceMap.put("device_phone", deviceObj.getString("device_phone"));
                devicesList.add(deviceMap);
            }
            rootData.put("devices", devicesList);
        } else {
            rootData.put("devices", new ArrayList());
        }

        if (jsonObject.has("items")) {
            JSONArray itemsArray = jsonObject.getJSONArray("items");
            for (int i = 0; i < itemsArray.length(); i++) {
                JSONObject itemObj = itemsArray.getJSONObject(i);
                Map itemMap = new HashMap();

                if (itemObj.has("type")) itemMap.put("type", itemObj.getString("type"));

                if (itemObj.has("schedule")) {
                    JSONObject scheduleObj = itemObj.getJSONObject("schedule");
                    Map scheduleMap = new HashMap();

                    if (scheduleObj.has("days")) {
                        JSONArray daysArray = scheduleObj.getJSONArray("days");
                        List daysList = new ArrayList();
                        for (int j = 0; j < daysArray.length(); j++) {
                            daysList.add(daysArray.getString(j));
                        }
                        scheduleMap.put("days", daysList);
                    } else {
                        scheduleMap.put("days", new ArrayList());
                    }

                    if (scheduleObj.has("times")) {
                        JSONArray timesArray = scheduleObj.getJSONArray("times");
                        List timesList = new ArrayList();
                        for (int j = 0; j < timesArray.length(); j++) {
                            timesList.add(timesArray.getString(j));
                        }
                        scheduleMap.put("times", timesList);
                    } else {
                        scheduleMap.put("times", new ArrayList());
                    }

                    itemMap.put("schedule", scheduleMap);
                } else {
                    Map scheduleMap = new HashMap();
                    scheduleMap.put("days", new ArrayList());
                    scheduleMap.put("times", new ArrayList());
                    itemMap.put("schedule", scheduleMap);
                }

                String type = itemObj.has("type") ? itemObj.getString("type") : "";

                if (type.equals("text")) {
                    if (itemObj.has("message")) itemMap.put("message", itemObj.getString("message"));
                } else if (type.equals("video")) {
                    if (itemObj.has("path")) itemMap.put("path", itemObj.getString("path"));
                    if (itemObj.has("caption")) itemMap.put("caption", itemObj.getString("caption"));
                } else if (type.equals("image")) {
                    // Keep image items but don't modify them
                    if (itemObj.has("path")) itemMap.put("path", itemObj.getString("path"));
                    if (itemObj.has("caption")) itemMap.put("caption", itemObj.getString("caption"));
                }

                itemsList.add(itemMap);
            }
        }

    } catch (Exception e) {
        tasker.log("Error parsing JSON: " + e.getMessage());
        rootData.put("devices", new ArrayList());
        itemsList = new ArrayList();
    }
} else {
    rootData.put("devices", new ArrayList());
    itemsList = new ArrayList();
}

String inputPathsString = tasker.getVariable("input");
String inputCaption = tasker.getVariable("caption");

if (inputCaption == null) inputCaption = "";

if (inputPathsString != null && inputPathsString.length() > 0) {
    String[] newPaths = inputPathsString.split(",");

    for (int i = 0; i < newPaths.length; i++) {
        String path = newPaths[i].trim();
        if (path.length() == 0) {
            continue;
        }

        // Validate video extension (only MP4 or 3GP)
        String lowerPath = path.toLowerCase();
        boolean isValidVideo = lowerPath.endsWith(".mp4") || lowerPath.endsWith(".3gp");

        if (!isValidVideo) {
            tasker.log("Invalid video format (only MP4 or 3GP): " + path);
            continue;
        }

        boolean pathExists = false;
        for (int j = 0; j < itemsList.size(); j++) {
            Map existingItem = (Map) itemsList.get(j);
            String existingPath = (String) existingItem.get("path");
            if (existingPath != null && path.equals(existingPath)) {
                pathExists = true;
                break;
            }
        }

        if (!pathExists) {
            Map newItem = new HashMap();
            newItem.put("type", "video");

            Map schedule = new HashMap();
            schedule.put("days", new ArrayList());
            schedule.put("times", new ArrayList());
            newItem.put("schedule", schedule);

            newItem.put("path", path);
            newItem.put("caption", inputCaption);

            itemsList.add(newItem);
            tasker.log("New video added: " + path);
        } else {
            tasker.log("Video already exists, ignored: " + path);
        }
    }
}

rootData.put("items", itemsList);

String updatedJson = tasker.toJson(rootData, true);

writeJsonFile(jsonStatusPath, updatedJson);

return "Video(s) added successfully! Total items: " + itemsList.size();

