import java.io.BufferedReader;
import java.io.File;
import java.io.FileReader;
import java.util.ArrayList;
import java.util.Collections;
import java.util.Date;
import java.text.SimpleDateFormat;
import java.util.Locale;
import java.util.regex.Pattern;
import java.util.regex.Matcher;

String filePath = "/storage/emulated/0/Tasker/projects_task/projects/whats-connect-api/system/project-xml/project-xml.json";
String lastUpdateLocal = tasker.getVariable("last_update");

try {
    File file = new File(filePath);
    if (!file.exists()) {
        tasker.setVariable("update_status", "error");
        tasker.setVariable("debug_error", "not file: " + filePath);
        return;
    }

    ArrayList<Long> allDates = new ArrayList<Long>();
    Pattern pattern = Pattern.compile("<(edate|cdate)>(\\d+)</(edate|cdate)>");

    BufferedReader reader = new BufferedReader(new FileReader(file), 4096);
    char[] buffer = new char[4096];
    StringBuilder leftover = new StringBuilder();
    int charsRead;

    while ((charsRead = reader.read(buffer)) != -1) {
        leftover.append(buffer, 0, charsRead);
        String chunk = leftover.toString();

        Matcher matcher = pattern.matcher(chunk);
        while (matcher.find()) {
            try {
                allDates.add(Long.parseLong(matcher.group(2)));
            } catch (NumberFormatException e) {}
        }

        if (chunk.length() > 50) {
            leftover = new StringBuilder(chunk.substring(chunk.length() - 50));
        }
    }
    reader.close();

    if (allDates.isEmpty()) {
        tasker.setVariable("update_status", "error");
        tasker.setVariable("debug_error", "Nenhuma data encontrada");
        return;
    }

    long maxTimestamp = Collections.max(allDates);
    SimpleDateFormat sdf = new SimpleDateFormat("dd/MM/yyyy HH:mm:ss", Locale.getDefault());
    String remoteDateFormatted = sdf.format(new Date(maxTimestamp));
    tasker.setVariable("remote_update_date", remoteDateFormatted);

    if (lastUpdateLocal == null || lastUpdateLocal.isEmpty() || !remoteDateFormatted.equals(lastUpdateLocal)) {
        tasker.setVariable("update_status", "new-update");
    } else {
        tasker.setVariable("update_status", "no-update");
    }

} catch (Exception e) {
    tasker.setVariable("update_status", "error");
    tasker.setVariable("debug_error", e.getMessage());
}

