import android.view.accessibility.AccessibilityEvent;
import android.view.accessibility.AccessibilityNodeInfo;
import android.accessibilityservice.AccessibilityService;
import java.util.List;
import com.joaomgcd.taskerm.action.java.JavaCodeException;

// Validação da ativação do serviço de acessibilidade
AccessibilityService service = tasker.getAccessibilityService();
if (service == null) {
    throw new JavaCodeException("Serviço de Acessibilidade não ativo.");
}

// Aguarda 1200 milissegundos antes de iniciar as ações de clique
android.os.SystemClock.sleep(1200);

// Configuração de retorno padrão e tempo limite de monitoramento (30 segundos)
String result = "timeout";
long endTime = System.currentTimeMillis() + 30000;

// Contador de passadas estáveis (tela final visível e sem nenhum clique novo)
int passadasEstaveis = 0;
final int PASSADAS_NECESSARIAS = 2; // exige 2 leituras seguidas estáveis antes de concluir

tasker.log("Iniciando monitoramento multi-idioma...");

// Loop principal de execução até o tempo limite ser atingido
while (System.currentTimeMillis() < endTime) {
    AccessibilityNodeInfo root = service.getRootInActiveWindow();

    if (root != null) {
        // Captura de todos os elementos da interface atual
        List nodes = service.getChildrenRecursive(root);
        boolean dialogoAtivo = false;
        boolean clicouNestaPassada = false;
        boolean telaFinalDetectada = false;

        for (int i = 0; i < nodes.size(); i++) {
            AccessibilityNodeInfo node = (AccessibilityNodeInfo) nodes.get(i);
            if (node == null) continue;

            // Identificação e clique via ID de recurso (padrão de sistema Android para botões positivos)
            String viewId = node.getViewIdResourceName();
            if (viewId != null && (viewId.contains("button1") || viewId.contains("button_positive"))) {
                if (node.isClickable()) {
                    node.performAction(AccessibilityNodeInfo.ACTION_CLICK);
                    clicouNestaPassada = true;
                    tasker.log("Clique por ID Universal efetuado.");
                }
            }

            // Identificação e clique via texto (mapeamento multi-idioma)
            if (node.getText() != null) {
                String t = node.getText().toString().toUpperCase().trim();

                // Verificação de termos que indicam a presença do diálogo de importação
                if (t.contains("TASKER") || t.contains("IMPORT") || t.contains("PROJET")) {
                    dialogoAtivo = true;
                }

                // Lista de termos para cliques de confirmação em múltiplos idiomas
                if (t.equals("SIM") || t.equals("YES") || t.equals("OK") || t.equals("SÍ") ||
                    t.equals("ДА") || t.equals("SÍ") || t.equals("SÌ") || t.equals("是") || t.equals("确定") ||
                    t.equals("SUBSTITUIR") || t.equals("REPLACE") || t.equals("OVERWRITE") ||
                    t.equals("CONTINUAR") || t.equals("CONTINUE")) {

                    if (node.isClickable()) {
                        node.performAction(AccessibilityNodeInfo.ACTION_CLICK);
                        clicouNestaPassada = true;
                        tasker.log("Clique por texto efetuado: " + t);
                    }
                }

                // Detecção de retorno à tela principal para definir conclusão
                if (t.contains("PROJECTS") || t.contains("PROJETOS") || t.contains("TASKS") || t.contains("TAREFAS")) {
                    telaFinalDetectada = true;
                }
            }
        }

        if (clicouNestaPassada) {
            // Acabou de clicar: reseta a contagem de estabilidade e dá tempo
            // pra UI assentar (fechar diálogo / carregar próxima tela) antes
            // de reavaliar, evitando ler a árvore em transição.
            passadasEstaveis = 0;
            android.os.SystemClock.sleep(600);
            continue;
        }

        if (telaFinalDetectada) {
            // Só conta como estável se a tela final apareceu E não houve
            // clique nesta passada. Exige duas leituras seguidas para
            // confirmar que não é um estado transitório.
            passadasEstaveis++;
            tasker.log("Tela final detectada (" + passadasEstaveis + "/" + PASSADAS_NECESSARIAS + ")");

            if (passadasEstaveis >= PASSADAS_NECESSARIAS) {
                result = "imported";
                break;
            }
        } else {
            passadasEstaveis = 0;
        }
    }

    // Intervalo de varredura para controle de consumo de CPU
    android.os.SystemClock.sleep(400);
}

return result;

