import java.io.File;
import java.io.FileReader;
import java.io.FileWriter;
import java.io.PrintWriter;
import java.io.BufferedReader;
import org.json.JSONArray;
import org.json.JSONObject;

String devicesPath = "/storage/emulated/0/Tasker/projects_task/projects/whats-connect-api/system/connections/devices.json";
String json_number = "%json_number"; // Variável que vem do Tasker com o número

// Limpa o número (remove @s.whatsapp.net se vier com ele)
String cleanNumber = json_number;
if (cleanNumber.contains("@")) {
    cleanNumber = cleanNumber.split("@")[0];
}

// Garante que o número tem o formato correto
String jid = cleanNumber + "@s.whatsapp.net";

// Função para ler o JSON atual
JSONArray getExistingDevices() {
    File file = new File(devicesPath);
    if (!file.exists()) {
        return new JSONArray();
    }

    try {
        BufferedReader reader = new BufferedReader(new FileReader(file));
        StringBuilder sb = new StringBuilder();
        String line;
        while ((line = reader.readLine()) != null) {
            sb.append(line);
        }
        reader.close();

        if (sb.length() > 0) {
            return new JSONArray(sb.toString());
        }
    } catch (Exception e) {
        // Erro ao ler, retorna array vazio
    }
    return new JSONArray();
}

// Função para salvar o JSON
void saveDevices(JSONArray devices) {
    try {
        File file = new File(devicesPath);
        file.getParentFile().mkdirs(); // Garante que o diretório existe

        PrintWriter writer = new PrintWriter(new FileWriter(file, false));
        writer.println(devices.toString(2)); // Formata com indentação de 2 espaços
        writer.close();
    } catch (Exception e) {
        // Erro ao salvar
    }
}

// Verifica se o dispositivo já existe
boolean deviceExists(JSONArray devices, String jid) {
    for (int i = 0; i < devices.length(); i++) {
        JSONObject device = devices.getJSONObject(i);
        if (device.getString("jid").equals(jid)) {
            return true;
        }
    }
    return false;
}

// ========== LÓGICA PRINCIPAL ==========

JSONArray devices = getExistingDevices();

if (!deviceExists(devices, jid)) {
    // Dispositivo novo - criar entrada
    JSONObject newDevice = new JSONObject();
    newDevice.put("jid", jid);

    // Se não houver nenhum dispositivo, este é o PRINCIPAL
    // Se já existir algum, este é SECUNDÁRIO
    boolean isPrincipal = (devices.length() == 0);
    newDevice.put("is_principal", isPrincipal);
    newDevice.put("connected", true);
    newDevice.put("timestamp", new java.text.SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ss").format(new java.util.Date()));

    devices.put(newDevice);
    saveDevices(devices);

    // Variável de retorno para saber se foi principal ou não
    if (isPrincipal) {
        tasker.setVariable("device_status", "PRINCIPAL");
        tasker.setVariable("device_type", "main");
    } else {
        tasker.setVariable("device_status", "SECUNDARIO");
        tasker.setVariable("device_type", "secondary");
    }
    tasker.setVariable("device_added", "true");

} else {
    // Dispositivo já existe - apenas atualiza timestamp e connected
    for (int i = 0; i < devices.length(); i++) {
        JSONObject device = devices.getJSONObject(i);
        if (device.getString("jid").equals(jid)) {
            device.put("connected", true);
            device.put("timestamp", new java.text.SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ss").format(new java.util.Date()));
            break;
        }
    }
    saveDevices(devices);

    tasker.setVariable("device_status", "JA_EXISTENTE");
    tasker.setVariable("device_added", "false");
}

// Salva o JSON completo em uma variável para debug
tasker.setVariable("devices_json", devices.toString(2));

