pm = context.getPackageManager();

hasWhatsApp = false;
hasWhatsAppBusiness = false;

packages = pm.getInstalledPackages(0);

for (int i = 0; i < packages.size(); i++) {
    packageInfo = (PackageInfo) packages.get(i);
    packageName = packageInfo.packageName;

    if ("com.whatsapp".equals(packageName)) {
        hasWhatsApp = true;
    }
    else if ("com.whatsapp.w4b".equals(packageName)) {
        hasWhatsAppBusiness = true;
    }

    if (hasWhatsApp && hasWhatsAppBusiness) {
        break;
    }
}

result = "";
if (hasWhatsApp && hasWhatsAppBusiness) {
    result = "whatsApp message|whatsApp business";
} else if (hasWhatsApp) {
    result = "whatsApp message";
} else if (hasWhatsAppBusiness) {
    result = "whatsApp business";
} else {
    result = "Nem WhatsApp nem WhatsApp Business estão instalados.";
}

return result;

