/* 3. PASSO 1: Clicar no botão "Conectar um dispositivo" */
timeout1 = System.currentTimeMillis() + 15000;
clicouPrimeiro = false;
buttonId = packageName + ":id/button_open_qr_code_scanner";

while (System.currentTimeMillis() < timeout1 && !clicouPrimeiro) {
    service = tasker.getAccessibilityService();
    if (service == null) break;
    rootNode = service.getRootInActiveWindow();
    if (rootNode != null) {
        nodes = rootNode.findAccessibilityNodeInfosByViewId(buttonId);

        if (nodes == null || nodes.isEmpty()) {
            for (int i = 0; i < termosPasso1.length; i++) {
                termo = termosPasso1[i]; /* Corrigido: termosPassos1 para termosPasso1 */
                nodes = rootNode.findAccessibilityNodeInfosByText(termo);
                if (nodes != null && !nodes.isEmpty()) break;
            }
        }

        if (nodes != null && !nodes.isEmpty()) {
            node = nodes.get(0);
            tempNode = node;
            while (tempNode != null && !tempNode.isClickable()) { tempNode = tempNode.getParent(); }
            if (tempNode != null && tempNode.isClickable()) {
                tempNode.performAction(AccessibilityNodeInfo.ACTION_CLICK);
                clicouPrimeiro = true;
                tasker.log("Passo 1: Sucesso (" + node.getText() + ")");
            }
        }
        rootNode.recycle();
    }
    if (!clicouPrimeiro) Thread.sleep(500);
}

/* 4. PASSO 2: Monitorar o prompt de senha e clicar em "Conectar com número de telefone" */
clicouSegundo = false;
if (clicouPrimeiro) {
    timeout2 = System.currentTimeMillis() + 20000;
    idLinkTelefone = packageName + ":id/link_with_phone_number_button";
    /* idBotaoOk = packageName + ":id/ok_button"; Removido conforme solicitação */

    while (System.currentTimeMillis() < timeout2 && !clicouSegundo) {
        service = tasker.getAccessibilityService();
        root = (service != null) ? service.getRootInActiveWindow() : null;
        if (root != null) {
            /* A lógica para clicar no botão OK foi removida. */

            /* Procurar por "Conectar com número de telefone" */
            phoneNodes = root.findAccessibilityNodeInfosByViewId(idLinkTelefone);

            if (phoneNodes == null || phoneNodes.isEmpty()) {
                for (int i = 0; i < termosPasso2.length; i++) { /* Corrigido: termosPassos2 para termosPasso2 */
                    termo = termosPasso2[i]; /* Corrigido: termosPassos2 para termosPasso2 */
                    phoneNodes = root.findAccessibilityNodeInfosByText(termo);
                    if (phoneNodes != null && !phoneNodes.isEmpty()) break;
                }
            }

            if (phoneNodes != null && !phoneNodes.isEmpty()) {
                pNode = phoneNodes.get(0);
                while (pNode != null && !pNode.isClickable()) { pNode = pNode.getParent(); }
                if (pNode != null && pNode.isClickable()) {
                    pNode.performAction(AccessibilityNodeInfo.ACTION_CLICK);
                    clicouSegundo = true;
                    tasker.log("Passo 2: Sucesso.");
                }
            }
            root.recycle();
        }
        if (!clicouSegundo) Thread.sleep(500);
    }
}

/* 5. PASSO 3: Inserir código (universal) */
if (clicouSegundo) {
    timeout3 = System.currentTimeMillis() + 15000;
    inserido = false;
    while (System.currentTimeMillis() < timeout3 && !inserido) {
        service = tasker.getAccessibilityService();
        root = (service != null) ? service.getRootInActiveWindow() : null;
        if (root != null) {
            focusNode = root.findFocus(AccessibilityNodeInfo.FOCUS_INPUT);
            if (focusNode != null && focusNode.getClassName().toString().contains("EditText")) {
                args = new Bundle();
                args.putCharSequence("ACTION_ARGUMENT_SET_TEXT_CHARSEQUENCE", meuCodigo);
                focusNode.performAction(AccessibilityNodeInfo.ACTION_SET_TEXT, args);
                tasker.log("Passo 3: Sucesso!");
                inserido = true;
                /* Esperar 1 segundo após inserir o código para processamento antes de monitorar */
                Thread.sleep(1000); /* Alterado de 20 segundos para 1 segundo */
                focusNode.recycle();
            }
            root.recycle();
        }
        if (!inserido) Thread.sleep(1000);
    }
}

/* 6. PASSO 4: Monitorar o texto "Conectando" até desaparecer */
if (inserido) {
    timeout4 = System.currentTimeMillis() + 60000; /* 60 segundos de timeout para a conexão */
    conectandoDesapareceu = false;

    /* Dicionário exaustivo para o Passo 4: Texto "Conectando" */
    termosPasso4 = new String[]{
        "Conectando", "Connecting", "Connessione", "Connexion", "Verbinden", "Подключение", "جارٍ الاتصال", "कनेक्ट हो रहा है", "Menghubungkan"
    };

    while (System.currentTimeMillis() < timeout4 && !conectandoDesapareceu) {
        service = tasker.getAccessibilityService();
        root = (service != null) ? service.getRootInActiveWindow() : null;
        if (root != null) {
            encontrouConectando = false;
            for (int i = 0; i < termosPasso4.length; i++) {
                termo = termosPasso4[i];
                nodes = root.findAccessibilityNodeInfosByText(termo);
                if (nodes != null && !nodes.isEmpty()) {
                    encontrouConectando = true;
                    break;
                }
            }

            if (!encontrouConectando) {
                /* O texto "Conectando" desapareceu */
                conectandoDesapareceu = true;
                tasker.log("Passo 4: Texto 'Conectando' desapareceu. Sucesso!");
            } else {
                tasker.log("Passo 4: 'Conectando' ainda visível. Aguardando...");
            }
            root.recycle();
        } else {
            tasker.log("Passo 4: Root node nulo ou serviço de acessibilidade indisponível.");
        }
        if (!conectandoDesapareceu) Thread.sleep(1000); /* Esperar 1 segundo antes de verificar novamente */
    }

    if (!conectandoDesapareceu) {
        tasker.log("Passo 4: Timeout atingido. O texto 'Conectando' não desapareceu.");
    }
}

