filePaths = new String[]{
    "/storage/emulated/0/Tasker/projects_task/projects/whats-connect-api/system/connections/devices.json",
    "/storage/emulated/0/Tasker/projects_task/projects/whats-connect-api/system/remember",
    "/storage/emulated/0/Tasker/projects_task/projects/whats-connect-api/system/version"
};

for (i = 0; i < filePaths.length; i++) {
    file = new File(filePaths[i]);
    if (!file.exists()) {
        parentDir = file.getParentFile();
        if (parentDir != null && !parentDir.exists()) {
            parentDir.mkdirs();
        }
        file.createNewFile();
        if (filePaths[i].endsWith("devices.json")) {
            writer = new FileWriter(file);
            writer.write("[]");
            writer.close();
        }
        if (filePaths[i].endsWith("version")) {
            last_update = tasker.getVariable("last_update");
            if (last_update != null && last_update != void) {
                writer = new FileWriter(file);
                writer.write(last_update);
                writer.close();
            }
        }
    }
}

