boolean isResponseSuccess(String response) {
    if (response == null) return false;
    try {
        JSONObject jsonResponse = new JSONObject(response);
        String code = jsonResponse.optString("code", "");
        return code.equals("SUCCESS");
    } catch (Exception e) {
        return response.contains("SUCCESS");
    }
}

int updateAllJsonFilesWithNewDevices(Map newDevices) {
    int updatedFiles = 0;

    for (int f = 0; f < jsonFiles.length; f++) {
        String jsonFilePath = jsonFiles[f];
        String fileName = fileNames[f];
        String jsonContent = readJsonFile(jsonFilePath);
        if (jsonContent == null) continue;

        try {
            JSONObject root = new JSONObject(jsonContent);
            if (!root.has("devices")) continue;

            JSONArray devicesArray = root.getJSONArray("devices");
            boolean fileModified = false;

            for (int i = 0; i < devicesArray.length(); i++) {
                JSONObject deviceObj = devicesArray.getJSONObject(i);
                String oldDeviceId = deviceObj.getString("device_id");
                String phoneNumber = deviceObj.getString("device_phone");

                if (newDevices.containsKey(phoneNumber)) {
                    String newDeviceId = (String) newDevices.get(phoneNumber);
                    if (!oldDeviceId.equals(newDeviceId)) {
                        deviceObj.put("device_id", newDeviceId);
                        fileModified = true;
                        addLog("  Updated device " + phoneNumber + ": " + oldDeviceId + " -> " + newDeviceId);
                    }
                }
            }

            if (root.has("items")) {
                JSONArray itemsArray = root.getJSONArray("items");
                for (int i = 0; i < itemsArray.length(); i++) {
                    JSONObject item = itemsArray.getJSONObject(i);
                    if (item.has("device_ids")) {
                        JSONArray itemDeviceIds = item.getJSONArray("device_ids");
                        for (int j = 0; j < itemDeviceIds.length(); j++) {
                            JSONObject deviceIdObj = itemDeviceIds.getJSONObject(j);
                            String oldDeviceId = deviceIdObj.getString("device_id");
                            String phoneNumber = deviceIdObj.optString("device_phone", "");

                            if (phoneNumber.length() > 0 && newDevices.containsKey(phoneNumber)) {
                                String newDeviceId = (String) newDevices.get(phoneNumber);
                                if (!oldDeviceId.equals(newDeviceId)) {
                                    deviceIdObj.put("device_id", newDeviceId);
                                    fileModified = true;
                                    addLog("  Updated device in items: " + phoneNumber + ": " + oldDeviceId + " -> " + newDeviceId);
                                }
                            }
                        }
                    }
                }
            }

            if (fileModified) {
                writeJsonFile(jsonFilePath, root.toString(2));
                updatedFiles++;
                addLog("Updated file: " + fileName);
            }
        } catch (Exception e) {
            addLog("Error updating " + fileName + ": " + e.getMessage());
        }
    }

    return updatedFiles;
}

Map getDevicesFromHttpDataAndUpdateFiles() {
    Map deviceMap = new HashMap();
    Map phoneToDeviceId = new HashMap();

    String httpData = tasker.getVariable("http_data");

    if (httpData != null && httpData.length() > 0) {
        addLog("=== Using http_data from Tasker ===");
        try {
            JSONObject jsonData = new JSONObject(httpData);
            if (jsonData.has("results")) {
                JSONArray results = jsonData.getJSONArray("results");
                addLog("Found " + results.length() + " devices in http_data");

                for (int i = 0; i < results.length(); i++) {
                    JSONObject device = results.getJSONObject(i);
                    String state = device.optString("state", "");

                    if (state.equals("logged_in")) {
                        String id = device.getString("id");
                        String jid = device.getString("jid");
                        String phone = jid.replace("@s.whatsapp.net", "");
                        deviceMap.put(id, phone);
                        phoneToDeviceId.put(phone, id);
                        addLog("Logged device: " + id + " -> " + phone);
                    } else {
                        addLog("Device ignored (state=" + state + ")");
                    }
                }
            }
        } catch (Exception e) {
            addLog("Error parsing http_data: " + e.getMessage());
        }
    }

    if (!phoneToDeviceId.isEmpty()) {
        addLog("=== Updating JSON files with new device IDs ===");
        int updatedCount = updateAllJsonFilesWithNewDevices(phoneToDeviceId);
        addLog("Updated " + updatedCount + " out of " + jsonFiles.length + " JSON files");
    }

    if (deviceMap.isEmpty()) {
        addLog("=== http_data empty, trying local API ===");
        try {
            String response = makeHttpRequest("/devices", "GET", null, null);
            if (response != null) {
                JSONObject jsonResponse = new JSONObject(response);
                if (jsonResponse.has("results")) {
                    JSONArray results = jsonResponse.getJSONArray("results");
                    for (int i = 0; i < results.length(); i++) {
                        JSONObject device = results.getJSONObject(i);
                        String state = device.optString("state", "");
                        if (state.equals("logged_in")) {
                            String id = device.getString("id");
                            String jid = device.getString("jid");
                            String phone = jid.replace("@s.whatsapp.net", "");
                            deviceMap.put(id, phone);
                            addLog("API Device: " + id + " -> " + phone);
                        }
                    }
                }
            }
        } catch (Exception e) {
            addLog("API error: " + e.getMessage());
        }
    }

    if (deviceMap.isEmpty()) {
        addLog("=== Using devices from JSON files ===");
        for (int f = 0; f < jsonFiles.length; f++) {
            String jsonFilePath = jsonFiles[f];
            String jsonContent = readJsonFile(jsonFilePath);
            if (jsonContent == null) continue;
            try {
                JSONObject root = new JSONObject(jsonContent);
                if (root.has("devices")) {
                    JSONArray devices = root.getJSONArray("devices");
                    for (int i = 0; i < devices.length(); i++) {
                        JSONObject device = devices.getJSONObject(i);
                        String id = device.getString("device_id");
                        String phone = device.getString("device_phone");
                        deviceMap.put(id, phone);
                        addLog("File Device: " + id + " -> " + phone);
                    }
                }
            } catch (Exception e) {}
        }
    }

    addLog("Total available devices: " + deviceMap.size());
    return deviceMap;
}

String getCurrentDateTime() {
    SimpleDateFormat sdf = new SimpleDateFormat("yyyy-MM-dd HH:mm:ss");
    return sdf.format(Calendar.getInstance().getTime());
}

long getCurrentMillis() {
    return System.currentTimeMillis();
}

String getCurrentDate() {
    SimpleDateFormat sdf = new SimpleDateFormat("yyyy-MM-dd");
    return sdf.format(Calendar.getInstance().getTime());
}

String getCurrentDay() {
    SimpleDateFormat sdf = new SimpleDateFormat("EEEE");
    String day = sdf.format(Calendar.getInstance().getTime());

    if (day.equalsIgnoreCase("Monday") || day.equalsIgnoreCase("segunda-feira")) return "Mon";
    if (day.equalsIgnoreCase("Tuesday") || day.equalsIgnoreCase("terça-feira")) return "Tue";
    if (day.equalsIgnoreCase("Wednesday") || day.equalsIgnoreCase("quarta-feira")) return "Wed";
    if (day.equalsIgnoreCase("Thursday") || day.equalsIgnoreCase("quinta-feira")) return "Thu";
    if (day.equalsIgnoreCase("Friday") || day.equalsIgnoreCase("sexta-feira")) return "Fri";
    if (day.equalsIgnoreCase("Saturday") || day.equalsIgnoreCase("sábado")) return "Sat";
    if (day.equalsIgnoreCase("Sunday") || day.equalsIgnoreCase("domingo")) return "Sun";

    return day;
}

String getCurrentTime() {
    SimpleDateFormat sdf = new SimpleDateFormat("HH:mm");
    return sdf.format(Calendar.getInstance().getTime());
}

sendResults = "";
addLog("========================================");
addLog("Starting Broadcast Sender");
addLog("========================================");

addLog("API URL: " + apiBaseUrl);

Map deviceMap = getDevicesFromHttpDataAndUpdateFiles();

if (deviceMap.isEmpty()) {
    addLog("WARNING: No devices available! Check http_data or API connection.");
    addResult("ERROR: No devices found to send messages");
} else {
    addLog("Devices loaded successfully: " + deviceMap.size());
}

String currentDate = getCurrentDate();
String currentDay = getCurrentDay();
String currentTime = getCurrentTime();
addLog("Current Date: " + currentDate);
addLog("Current Day: " + currentDay);
addLog("Current Time: " + currentTime);

Map cache = new HashMap();
File cacheFile = new File(cachePath);
if (cacheFile.exists()) {
    String cacheContent = readJsonFile(cachePath);
    if (cacheContent != null) {
        try {
            JSONObject cacheJson = new JSONObject(cacheContent);
            JSONArray sentItems = cacheJson.getJSONArray("sent_items");
            for (int i = 0; i < sentItems.length(); i++) {
                JSONObject sentItem = sentItems.getJSONObject(i);
                cache.put(sentItem.getString("key"), sentItem);
            }
            addLog("Cache loaded: " + cache.size() + " items");
        } catch (Exception e) {
            addLog("Error loading cache: " + e.getMessage());
        }
    }
}

addLog("========================================");

List sentKeys = new ArrayList();
int totalItemsProcessed = 0;
int totalItemsSkipped = 0;
int totalErrors = 0;
int totalItemsNoSchedule = 0;

for (int f = 0; f < jsonFiles.length; f++) {
    String jsonFilePath = jsonFiles[f];
    String fileName = fileNames[f];
    String jsonContent = readJsonFile(jsonFilePath);
    if (jsonContent == null) {
        addLog("File not found: " + fileName);
        continue;
    }

    try {
        JSONObject root = new JSONObject(jsonContent);
        if (!root.has("items")) {
            addLog("No items array in: " + fileName);
            continue;
        }

        JSONArray items = root.getJSONArray("items");
        addLog("Checking file: " + fileName + " (" + items.length() + " items)");

        for (int i = 0; i < items.length(); i++) {
            totalItemsProcessed++;
            JSONObject item = items.getJSONObject(i);
            String itemType = item.optString("type", "unknown");

            if (!item.has("schedule")) {
                addLog("  Item " + (i+1) + ": NO schedule object - skipping");
                totalItemsNoSchedule++;
                continue;
            }

            JSONObject schedule = item.getJSONObject("schedule");

            if (!hasValidSchedule(schedule)) {
                addLog("  Item " + (i+1) + ": Empty schedule (no days AND no times configured) - skipping");
                totalItemsNoSchedule++;
                continue;
            }

            JSONArray days = schedule.optJSONArray("days");
            JSONArray times = schedule.optJSONArray("times");

            if (!isDayMatch(days, currentDay)) {
                addLog("  Item " + (i+1) + ": Day mismatch (current day: " + currentDay + ") - skipping");
                continue;
            }

            if (!isTimeMatch(times, currentTime)) {
                addLog("  Item " + (i+1) + ": Time mismatch (current time: " + currentTime + ") - skipping");
                continue;
            }

            boolean hasRequiredFields = true;
            String missingFields = "";

            if (itemType.equals("message") || itemType.equals("text")) {
                if (!item.has("message") || item.getString("message").length() == 0) {
                    hasRequiredFields = false;
                    missingFields = "message";
                }
            } else if (itemType.equals("image") || itemType.equals("image_message")) {
                if (!item.has("path")) {
                    hasRequiredFields = false;
                    missingFields = "path";
                } else if (!isValidFilePath(item.getString("path"))) {
                    hasRequiredFields = false;
                    missingFields = "invalid file path: " + item.getString("path");
                }
            } else if (itemType.equals("video") || itemType.equals("video_message")) {
                if (!item.has("path")) {
                    hasRequiredFields = false;
                    missingFields = "path";
                } else if (!isValidFilePath(item.getString("path"))) {
                    hasRequiredFields = false;
                    missingFields = "invalid file path: " + item.getString("path");
                }
            } else if (itemType.equals("file")) {
                if (!item.has("path")) {
                    hasRequiredFields = false;
                    missingFields = "path";
                } else if (!isValidFilePath(item.getString("path"))) {
                    hasRequiredFields = false;
                    missingFields = "invalid file path: " + item.getString("path");
                }
            } else if (itemType.equals("poll")) {
                if (!item.has("question")) {
                    hasRequiredFields = false;
                    missingFields = "question";
                }
                if (!item.has("options") || item.getJSONArray("options").length() == 0) {
                    hasRequiredFields = false;
                    missingFields = missingFields + (missingFields.length() > 0 ? ", options" : "options");
                }
            }

            if (!hasRequiredFields) {
                addLog("  Item " + (i+1) + ": MISSING REQUIRED FIELDS - " + missingFields);
                addResult("  ERROR: Item " + (i+1) + " missing " + missingFields);
                totalErrors++;
                continue;
            }

            String uniqueItemId = "";
            if (item.has("path")) {
                uniqueItemId = item.getString("path");
            } else if (item.has("message")) {
                uniqueItemId = item.getString("message");
            } else if (item.has("question")) {
                uniqueItemId = item.getString("question");
            } else {
                uniqueItemId = String.valueOf(i);
            }

            String itemKey = fileName + "_" + itemType + "_" + String.valueOf(uniqueItemId.hashCode()) + "_" + currentDate;

            if (cache.containsKey(itemKey)) {
                addLog("  Item " + (i+1) + ": Already sent today - skipping");
                totalItemsSkipped++;
                continue;
            }

            addLog(">>> SENDING: " + fileName + " - " + itemType);
            addResult("Sending: " + fileName + " - " + itemType);

            JSONArray recipients = item.optJSONArray("recipients");
            JSONArray deviceIds = item.optJSONArray("device_ids");
            boolean isStatus = (fileName.equals("json-status.json"));
            boolean isForwarded = item.optBoolean("is_forwarded", false);
            boolean allSuccess = true;
            int errorCount = 0;

            if (isStatus) {
                if (itemType.equals("text") || itemType.equals("message")) {
                    String message = item.getString("message");

                    if (deviceIds != null && deviceIds.length() > 0) {
                        for (int d = 0; d < deviceIds.length(); d++) {
                            JSONObject deviceObj = deviceIds.getJSONObject(d);
                            String deviceId = deviceObj.getString("device_id");
                            if (!deviceMap.containsKey(deviceId)) {
                                addResult("  WARNING: Device " + deviceId + " not available");
                                errorCount++;
                                allSuccess = false;
                                continue;
                            }
                            addResult("  Sending text status via device: " + deviceId);
                            String response = sendTextStatus(deviceId, message, isForwarded);
                            if (!isResponseSuccess(response)) {
                                errorCount++;
                                allSuccess = false;
                                addResult("    FAILED to send text status");
                            }
                        }
                    } else {
                        java.util.Iterator it = deviceMap.keySet().iterator();
                        while (it.hasNext()) {
                            String deviceId = it.next().toString();
                            addResult("  Sending text status via device: " + deviceId);
                            String response = sendTextStatus(deviceId, message, isForwarded);
                            if (!isResponseSuccess(response)) {
                                errorCount++;
                                allSuccess = false;
                                addResult("    FAILED to send text status");
                            }
                        }
                    }
                }
                else if (itemType.equals("image") || itemType.equals("image_message")) {
                    String path = item.optString("path", "");
                    if (path.length() == 0) {
                        addLog("  No path for image status");
                        addResult("  ERROR: Missing path for image status");
                        errorCount++;
                        allSuccess = false;
                    } else if (!isValidFilePath(path)) {
                        addLog("  Invalid file path: " + path);
                        addResult("  ERROR: File not found - " + path);
                        errorCount++;
                        allSuccess = false;
                    } else {
                        String caption = item.optString("caption", "");
                        if (deviceIds != null && deviceIds.length() > 0) {
                            for (int d = 0; d < deviceIds.length(); d++) {
                                JSONObject deviceObj = deviceIds.getJSONObject(d);
                                String deviceId = deviceObj.getString("device_id");
                                if (!deviceMap.containsKey(deviceId)) {
                                    addResult("  WARNING: Device " + deviceId + " not available");
                                    errorCount++;
                                    allSuccess = false;
                                    continue;
                                }
                                addResult("  Sending image status via device: " + deviceId);
                                String response = sendImage(deviceId, "", caption, path, true, isForwarded);
                                if (!isResponseSuccess(response)) {
                                    errorCount++;
                                    allSuccess = false;
                                    addResult("    FAILED to send image status");
                                }
                            }
                        } else {
                            java.util.Iterator it = deviceMap.keySet().iterator();
                            while (it.hasNext()) {
                                String deviceId = it.next().toString();
                                addResult("  Sending image status via device: " + deviceId);
                                String response = sendImage(deviceId, "", caption, path, true, isForwarded);
                                if (!isResponseSuccess(response)) {
                                    errorCount++;
                                    allSuccess = false;
                                    addResult("    FAILED to send image status");
                                }
                            }
                        }
                    }
                }
                else if (itemType.equals("video") || itemType.equals("video_message")) {
                    String path = item.optString("path", "");
                    if (path.length() == 0) {
                        addLog("  No path for video status");
                        addResult("  ERROR: Missing path for video status");
                        errorCount++;
                        allSuccess = false;
                    } else if (!isValidFilePath(path)) {
                        addLog("  Invalid file path: " + path);
                        addResult("  ERROR: File not found - " + path);
                        errorCount++;
                        allSuccess = false;
                    } else {
                        String caption = item.optString("caption", "");
                        if (deviceIds != null && deviceIds.length() > 0) {
                            for (int d = 0; d < deviceIds.length(); d++) {
                                JSONObject deviceObj = deviceIds.getJSONObject(d);
                                String deviceId = deviceObj.getString("device_id");
                                if (!deviceMap.containsKey(deviceId)) {
                                    addResult("  WARNING: Device " + deviceId + " not available");
                                    errorCount++;
                                    allSuccess = false;
                                    continue;
                                }
                                addResult("  Sending video status via device: " + deviceId);
                                String response = sendVideo(deviceId, "", caption, path, true, isForwarded);
                                if (!isResponseSuccess(response)) {
                                    errorCount++;
                                    allSuccess = false;
                                    addResult("    FAILED to send video status");
                                }
                            }
                        } else {
                            java.util.Iterator it = deviceMap.keySet().iterator();
                            while (it.hasNext()) {
                                String deviceId = it.next().toString();
                                addResult("  Sending video status via device: " + deviceId);
                                String response = sendVideo(deviceId, "", caption, path, true, isForwarded);
                                if (!isResponseSuccess(response)) {
                                    errorCount++;
                                    allSuccess = false;
                                    addResult("    FAILED to send video status");
                                }
                            }
                        }
                    }
                } else {
                    addLog("  Unknown status type: " + itemType);
                    addResult("  ERROR: Unknown status type - " + itemType);
                    errorCount++;
                    allSuccess = false;
                }
            }
            else if (recipients != null && recipients.length() > 0) {
                for (int r = 0; r < recipients.length(); r++) {
                    JSONObject recipient = recipients.getJSONObject(r);
                    String recipientPhone = recipient.getString("phone");
                    String recipientSuffix = recipient.optString("suffix", "@s.whatsapp.net");
                    String fullPhone = recipientPhone + recipientSuffix;

                    if (!isValidPhone(recipientPhone)) {
                        addResult("  ERROR: Invalid phone number - " + recipientPhone);
                        errorCount++;
                        allSuccess = false;
                        continue;
                    }

                    if (deviceIds != null && deviceIds.length() > 0) {
                        for (int d = 0; d < deviceIds.length(); d++) {
                            JSONObject deviceObj = deviceIds.getJSONObject(d);
                            String deviceId = deviceObj.getString("device_id");
                            if (!deviceMap.containsKey(deviceId)) {
                                addResult("  WARNING: Device " + deviceId + " not available for " + fullPhone);
                                errorCount++;
                                allSuccess = false;
                                continue;
                            }

                            addResult("  To: " + fullPhone + " via device: " + deviceId);

                            String response = null;
                            try {
                                if (itemType.equals("message") || itemType.equals("text")) {
                                    String message = item.getString("message");
                                    int duration = item.optInt("duration", 0);
                                    response = sendMessage(deviceId, fullPhone, message, isForwarded, duration);

                                } else if (itemType.equals("image") || itemType.equals("image_message")) {
                                    String path = item.getString("path");
                                    if (!isValidFilePath(path)) {
                                        addResult("    ERROR: File not found - " + path);
                                        errorCount++;
                                        allSuccess = false;
                                        continue;
                                    }
                                    String caption = item.optString("caption", "");
                                    response = sendImage(deviceId, fullPhone, caption, path, false, isForwarded);

                                } else if (itemType.equals("video") || itemType.equals("video_message")) {
                                    String path = item.getString("path");
                                    if (!isValidFilePath(path)) {
                                        addResult("    ERROR: File not found - " + path);
                                        errorCount++;
                                        allSuccess = false;
                                        continue;
                                    }
                                    String caption = item.optString("caption", "");
                                    response = sendVideo(deviceId, fullPhone, caption, path, false, isForwarded);

                                } else if (itemType.equals("file")) {
                                    String path = item.getString("path");
                                    if (!isValidFilePath(path)) {
                                        addResult("    ERROR: File not found - " + path);
                                        errorCount++;
                                        allSuccess = false;
                                        continue;
                                    }
                                    String caption = item.optString("caption", "");
                                    response = sendFile(deviceId, fullPhone, caption, path, isForwarded);

                                } else if (itemType.equals("poll")) {
                                    String question = item.getString("question");
                                    JSONArray options = item.getJSONArray("options");
                                    int maxAnswer = item.optInt("max_answer", 1);
                                    response = sendPoll(deviceId, fullPhone, question, options, maxAnswer);
                                }

                                if (!isResponseSuccess(response)) {
                                    errorCount++;
                                    allSuccess = false;
                                    addResult("    FAILED to send to " + fullPhone);
                                }
                            } catch (Exception e) {
                                addResult("    ERROR: Exception - " + e.getMessage());
                                errorCount++;
                                allSuccess = false;
                            }
                        }
                    } else {
                        java.util.Iterator it = deviceMap.keySet().iterator();
                        while (it.hasNext()) {
                            String deviceId = it.next().toString();
                            addResult("  To: " + fullPhone + " via device: " + deviceId);

                            String response = null;
                            try {
                                if (itemType.equals("message") || itemType.equals("text")) {
                                    String message = item.getString("message");
                                    int duration = item.optInt("duration", 0);
                                    response = sendMessage(deviceId, fullPhone, message, isForwarded, duration);

                                } else if (itemType.equals("image") || itemType.equals("image_message")) {
                                    String path = item.getString("path");
                                    if (!isValidFilePath(path)) {
                                        addResult("    ERROR: File not found - " + path);
                                        errorCount++;
                                        allSuccess = false;
                                        continue;
                                    }
                                    String caption = item.optString("caption", "");
                                    response = sendImage(deviceId, fullPhone, caption, path, false, isForwarded);

                                } else if (itemType.equals("video") || itemType.equals("video_message")) {
                                    String path = item.getString("path");
                                    if (!isValidFilePath(path)) {
                                        addResult("    ERROR: File not found - " + path);
                                        errorCount++;
                                        allSuccess = false;
                                        continue;
                                    }
                                    String caption = item.optString("caption", "");
                                    response = sendVideo(deviceId, fullPhone, caption, path, false, isForwarded);

                                } else if (itemType.equals("file")) {
                                    String path = item.getString("path");
                                    if (!isValidFilePath(path)) {
                                        addResult("    ERROR: File not found - " + path);
                                        errorCount++;
                                        allSuccess = false;
                                        continue;
                                    }
                                    String caption = item.optString("caption", "");
                                    response = sendFile(deviceId, fullPhone, caption, path, isForwarded);

                                } else if (itemType.equals("poll")) {
                                    String question = item.getString("question");
                                    JSONArray options = item.getJSONArray("options");
                                    int maxAnswer = item.optInt("max_answer", 1);
                                    response = sendPoll(deviceId, fullPhone, question, options, maxAnswer);
                                }

                                if (!isResponseSuccess(response)) {
                                    errorCount++;
                                    allSuccess = false;
                                    addResult("    FAILED to send to " + fullPhone);
                                }
                            } catch (Exception e) {
                                addResult("    ERROR: Exception - " + e.getMessage());
                                errorCount++;
                                allSuccess = false;
                            }
                        }
                    }
                }
            } else if (!isStatus) {
                addResult("  WARNING: No recipients found for this item");
                addLog("  Item " + (i+1) + ": No recipients - skipping");
                totalErrors++;
                continue;
            }

            if (allSuccess) {
                JSONObject cacheItem = new JSONObject();
                cacheItem.put("key", itemKey);
                cacheItem.put("file", fileName);
                cacheItem.put("type", itemType);
                cacheItem.put("date", getCurrentDateTime());
                cacheItem.put("time_ms", getCurrentMillis());
                sentKeys.add(cacheItem);
                addLog("  Item " + (i+1) + ": SEND SUCCESS - Added to cache");
            } else {
                addLog("  Item " + (i+1) + ": SEND FAILED - " + errorCount + " error(s) - Not added to cache");
                totalErrors++;
            }
        }

    } catch (Exception e) {
        addLog("Error processing " + fileName + ": " + e.getMessage());
        totalErrors++;
    }
}

if (sentKeys.size() > 0) {
    JSONArray sentItemsArray = new JSONArray();
    java.util.Iterator it = cache.keySet().iterator();
    while (it.hasNext()) {
        String key = it.next().toString();
        Object value = cache.get(key);
        if (value instanceof JSONObject) {
            sentItemsArray.put((JSONObject) value);
        }
    }
    for (int i = 0; i < sentKeys.size(); i++) {
        sentItemsArray.put((JSONObject) sentKeys.get(i));
    }
    JSONObject cacheJson = new JSONObject();
    cacheJson.put("sent_items", sentItemsArray);
    writeJsonFile(cachePath, cacheJson.toString(2));
    addLog("Cache saved: " + sentItemsArray.length() + " items");
}

tasker.setVariable("send_log", debugLog);
tasker.setVariable("send_results", sendResults);
tasker.setVariable("send_count", String.valueOf(sentKeys.size()));
tasker.setVariable("send_errors", String.valueOf(totalErrors));
tasker.setVariable("send_processed", String.valueOf(totalItemsProcessed));
tasker.setVariable("send_skipped", String.valueOf(totalItemsSkipped));
tasker.setVariable("send_no_schedule", String.valueOf(totalItemsNoSchedule));

addLog("========================================");
addLog("EXECUTION SUMMARY");
addLog("========================================");
addLog("Total processed: " + totalItemsProcessed);
addLog("Successfully sent: " + sentKeys.size());
addLog("Skipped (already sent): " + totalItemsSkipped);
addLog("Skipped (no schedule): " + totalItemsNoSchedule);
addLog("Errors: " + totalErrors);
addLog("========================================");

return "Successfully sent: " + sentKeys.size() + " items (Errors: " + totalErrors + ")";
